// ── Sticky bit (S_ISVTX) enforcement ──────────────────────────────────────

/// Newtype adapter: implements [`tidefs_permission::InodeAttr`] for
/// references to the VFS engine's [`InodeAttr`], bridging the orphan-rule
/// gap between `tidefs_types_vfs_core::InodeAttr` and the
/// `tidefs_permission::InodeAttr` trait.
struct VfsInodeAttrRef<'a>(&'a InodeAttr);

impl PermissionInodeAttr for VfsInodeAttrRef<'_> {
    fn uid(&self) -> u32 {
        self.0.posix.uid
    }
    fn gid(&self) -> u32 {
        self.0.posix.gid
    }
    fn mode(&self) -> u32 {
        self.0.posix.mode
    }
}

fn check_sticky_unlink_with_attrs(
    parent_attr: &InodeAttr,
    child_attr: &InodeAttr,
    ctx: &RequestCtx,
) -> Result<(), Errno> {
    let plan = tidefs_permission::plan_sticky_directory_delete(
        &VfsInodeAttrRef(parent_attr),
        &VfsInodeAttrRef(child_attr),
        ctx.uid,
    );
    if plan.is_allowed() {
        Ok(())
    } else {
        Err(Errno::EPERM)
    }
}

/// Check POSIX sticky-bit permission for a rename operation.
///
/// Both source and (when replacing) target sides must satisfy the sticky
/// rule. Returns `Ok(())` when allowed, `Err(EPERM)` when either side
/// is denied.
fn check_sticky_rename(
    engine: &dyn VfsEngine,
    old_parent: InodeId,
    old_name: &[u8],
    new_parent: InodeId,
    new_name: &[u8],
    ctx: &RequestCtx,
) -> Result<(), Errno> {
    let src_dir_attr = engine.getattr(old_parent, None, ctx)?;
    let src_victim_attr = engine.lookup(old_parent, old_name, ctx)?;
    let src_dir = VfsInodeAttrRef(&src_dir_attr);
    let src_victim = VfsInodeAttrRef(&src_victim_attr);

    let plan = if new_parent == old_parent {
        // Same directory: the source victim is already resolved, but for
        // the target side we need the existing target entry (if any).
        match engine.lookup(new_parent, new_name, ctx) {
            Ok(target_attr) => {
                let t = VfsInodeAttrRef(&target_attr);
                let target = Some(tidefs_permission::StickyDirectoryRenameTarget::new(
                    &src_dir, &t,
                ));
                tidefs_permission::plan_sticky_directory_rename(
                    &src_dir,
                    &src_victim,
                    target,
                    ctx.uid,
                )
            }
            Err(Errno::ENOENT) => tidefs_permission::plan_sticky_directory_rename(
                &src_dir,
                &src_victim,
                None,
                ctx.uid,
            ),
            Err(e) => return Err(e),
        }
    } else {
        let dst_dir_attr = engine.getattr(new_parent, None, ctx)?;
        let dst_dir = VfsInodeAttrRef(&dst_dir_attr);
        match engine.lookup(new_parent, new_name, ctx) {
            Ok(target_attr) => {
                let t = VfsInodeAttrRef(&target_attr);
                let target = Some(tidefs_permission::StickyDirectoryRenameTarget::new(
                    &dst_dir, &t,
                ));
                tidefs_permission::plan_sticky_directory_rename(
                    &src_dir,
                    &src_victim,
                    target,
                    ctx.uid,
                )
            }
            Err(Errno::ENOENT) => tidefs_permission::plan_sticky_directory_rename(
                &src_dir,
                &src_victim,
                None,
                ctx.uid,
            ),
            Err(e) => return Err(e),
        }
    };

    if plan.is_allowed() {
        Ok(())
    } else {
        Err(Errno::EPERM)
    }
}

/// Return true when `name` is a reserved POSIX ACL xattr name.
fn is_posix_acl_xattr_name(name: &[u8]) -> bool {
    name == b"system.posix_acl_access" || name == b"system.posix_acl_default"
}

fn caller_is_member_of_group(ctx: &RequestCtx, gid: u32) -> bool {
    ctx.gid == gid || ctx.groups.contains(&gid)
}

fn caller_can_keep_sgid(ctx: &RequestCtx, gid: u32) -> bool {
    ctx.uid == 0 || caller_is_member_of_group(ctx, gid)
}

fn request_groups_from_status_text(status: &str, primary_gid: u32) -> Vec<u32> {
    let mut groups = vec![primary_gid];
    let Some(line) = status.lines().find(|line| line.starts_with("Groups:")) else {
        return groups;
    };

    for field in line["Groups:".len()..].split_whitespace() {
        if let Ok(gid) = field.parse::<u32>() {
            if !groups.contains(&gid) {
                groups.push(gid);
            }
        }
    }
    groups
}

fn request_groups_from_pid(pid: u32, primary_gid: u32) -> Vec<u32> {
    if pid == 0 {
        return vec![primary_gid];
    }
    let path = format!("/proc/{pid}/status");
    match std::fs::read_to_string(path) {
        Ok(status) => request_groups_from_status_text(&status, primary_gid),
        Err(_) => vec![primary_gid],
    }
}

fn request_groups_for_ids(uid: u32, pid: u32, primary_gid: u32) -> Vec<u32> {
    if uid == 0 {
        vec![primary_gid]
    } else {
        request_groups_from_pid(pid, primary_gid)
    }
}

fn apply_setattr_privilege_mode_rules(
    attr: &SetAttr,
    current: &InodeAttr,
    ctx: &RequestCtx,
) -> SetAttr {
    let mut effective = *attr;
    let mut mode = if attr.valid & FATTR_MODE != 0 {
        (current.posix.mode & S_IFMT) | (attr.mode & !S_IFMT)
    } else {
        current.posix.mode
    };
    let mut force_mode = false;

    if (attr.valid & (FATTR_UID | FATTR_GID)) != 0 && ctx.uid != 0 {
        mode = (current.posix.mode & S_IFMT) | (mode & !S_IFMT & !(S_ISUID | S_ISGID));
        force_mode = true;
    }

    if attr.valid & FATTR_MODE != 0
        && mode & S_ISGID != 0
        && !caller_can_keep_sgid(ctx, current.posix.gid)
    {
        mode &= !S_ISGID;
        force_mode = true;
    }

    if force_mode || attr.valid & FATTR_MODE != 0 {
        effective.valid |= FATTR_MODE;
        effective.mode = mode;
    }

    effective
}
/// Check that the caller has write+execute access on a parent directory,
/// with POSIX ACL support. Retrieves the parent's access ACL from xattr
/// storage when present; falls back to mode-bit checking otherwise.
///
/// Returns `Ok(())` when access is granted, `Err(EACCES)` when denied,
/// or an engine error on metadata/xattr lookup failure.
fn check_parent_write_execute(
    engine: &dyn VfsEngine,
    parent: InodeId,
    ctx: &RequestCtx,
    mount_identity: &MountIdentity,
) -> Result<(), Errno> {
    let parent_attr = engine.getattr(parent, None, ctx)?;
    check_parent_write_execute_with_attr(engine, parent, &parent_attr, ctx, mount_identity)
}

fn check_parent_write_execute_with_attr(
    engine: &dyn VfsEngine,
    parent: InodeId,
    parent_attr: &InodeAttr,
    ctx: &RequestCtx,
    mount_identity: &MountIdentity,
) -> Result<(), Errno> {
    if !mount_identity.is_valid() {
        return Err(Errno::EACCES);
    }
    if parent_attr.kind != NodeKind::Dir {
        return Err(Errno::ENOTDIR);
    }
    if ctx.uid == 0 {
        return Ok(());
    }
    let acl: Option<Vec<PosixAclEntry>> =
        match engine.getxattr(parent, b"system.posix_acl_access", ctx) {
            Ok(data) => tidefs_permission::decode_posix_acl_xattr(&data).ok(),
            Err(Errno::ENODATA) => None,
            Err(_) => None,
        };
    plan_fuse_access_result(
        Ok(*parent_attr),
        ctx,
        ACCESS_WRITE | ACCESS_EXECUTE,
        acl.as_deref(),
        mount_identity,
    )
}

fn check_parent_write_execute_mutation_preflight(
    engine: &dyn VfsEngine,
    parent: InodeId,
    ctx: &RequestCtx,
    mount_identity: &MountIdentity,
) -> Result<(), Errno> {
    if !mount_identity.is_valid() {
        return Err(Errno::EACCES);
    }
    if ctx.uid == 0 {
        return Ok(());
    }
    check_parent_write_execute(engine, parent, ctx, mount_identity)
}

fn delete_child_attr_for_mutation_preflight(
    engine: &dyn VfsEngine,
    parent: InodeId,
    name: &[u8],
    ctx: &RequestCtx,
    mount_identity: &MountIdentity,
) -> Result<InodeAttr, Errno> {
    if !mount_identity.is_valid() {
        return Err(Errno::EACCES);
    }
    if ctx.uid == 0 {
        let child_attr = engine.lookup(parent, name, ctx)?;
        enforce_immutable_guard(child_attr.flags.to_raw_flags())?;
        return Ok(child_attr);
    }

    let parent_attr = engine.getattr(parent, None, ctx)?;
    check_parent_write_execute_with_attr(engine, parent, &parent_attr, ctx, mount_identity)?;
    let child_attr = engine.lookup(parent, name, ctx)?;
    check_sticky_unlink_with_attrs(&parent_attr, &child_attr, ctx)?;
    enforce_immutable_guard(parent_attr.flags.to_raw_flags())?;
    enforce_immutable_guard(child_attr.flags.to_raw_flags())?;
    Ok(child_attr)
}

fn enforce_mutable_parent_dir(parent_attr: &InodeAttr) -> Result<(), Errno> {
    if parent_attr.kind != NodeKind::Dir {
        return Err(Errno::ENOTDIR);
    }
    enforce_immutable_guard(parent_attr.flags.to_raw_flags())
}

fn rename_parent_attr_for_mutation_preflight(
    engine: &dyn VfsEngine,
    parent: InodeId,
    ctx: &RequestCtx,
) -> Result<InodeAttr, Errno> {
    match engine.getattr(parent, None, ctx) {
        Ok(attr) => Ok(attr),
        Err(Errno::EIO) => Err(Errno::ENOENT),
        Err(errno) => Err(errno),
    }
}

fn rename_mutation_preflight(
    engine: &dyn VfsEngine,
    old_parent: InodeId,
    old_name: &[u8],
    new_parent: InodeId,
    new_name: &[u8],
    ctx: &RequestCtx,
    mount_identity: &MountIdentity,
) -> Result<(), Errno> {
    if !mount_identity.is_valid() {
        return Err(Errno::EACCES);
    }
    if ctx.uid != 0 {
        check_parent_write_execute(engine, old_parent, ctx, mount_identity)?;
        check_parent_write_execute(engine, new_parent, ctx, mount_identity)?;
        check_sticky_rename(engine, old_parent, old_name, new_parent, new_name, ctx)?;
    }

    let src_parent_attr = rename_parent_attr_for_mutation_preflight(engine, old_parent, ctx)?;
    enforce_mutable_parent_dir(&src_parent_attr)?;
    if new_parent != old_parent {
        let dst_parent_attr = rename_parent_attr_for_mutation_preflight(engine, new_parent, ctx)?;
        enforce_mutable_parent_dir(&dst_parent_attr)?;
    }

    let src_child = engine.lookup(old_parent, old_name, ctx)?;
    enforce_immutable_guard(src_child.flags.to_raw_flags())?;
    match engine.lookup(new_parent, new_name, ctx) {
        Ok(dst_child) => enforce_immutable_guard(dst_child.flags.to_raw_flags())?,
        Err(Errno::ENOENT) => {}
        Err(errno) => return Err(errno),
    }
    Ok(())
}

/// Map a namespace `kind` field to a VFS [`NodeKind`].
fn namespace_kind_to_node_kind(kind: u32) -> NodeKind {
    match kind {
        tidefs_namespace::KIND_DIR => NodeKind::Dir,
        tidefs_namespace::KIND_FILE => NodeKind::File,
        tidefs_namespace::KIND_SYMLINK => NodeKind::Symlink,
        tidefs_namespace::KIND_FIFO => NodeKind::Fifo,
        tidefs_namespace::KIND_SOCKET => NodeKind::Socket,
        tidefs_namespace::KIND_CHAR => NodeKind::CharDev,
        tidefs_namespace::KIND_BLOCK => NodeKind::BlockDev,
        _ => NodeKind::File, // fallback: treat unknown as regular file
    }
}

/// Convert namespace [`tidefs_namespace::InodeAttributes`] to VFS [`InodeAttr`].
fn namespace_attrs_to_inode_attr(attrs: &tidefs_namespace::InodeAttributes) -> InodeAttr {
    let kind = match attrs.mode & 0o170000 {
        0o040000 => NodeKind::Dir,
        0o120000 => NodeKind::Symlink,
        0o010000 => NodeKind::Fifo,
        0o140000 => NodeKind::Socket,
        0o060000 => NodeKind::BlockDev,
        0o020000 => NodeKind::CharDev,
        _ => NodeKind::File,
    };
    let atime_ns = system_time_to_ns(attrs.atime);
    let mtime_ns = system_time_to_ns(attrs.mtime);
    let ctime_ns = system_time_to_ns(attrs.ctime);
    InodeAttr::new(
        InodeId::new(attrs.inode),
        Generation::new(0),
        kind,
        tidefs_types_vfs_core::PosixAttrs::new(
            attrs.mode,
            attrs.uid,
            attrs.gid,
            attrs.nlink,
            attrs.rdev,
            atime_ns,
            mtime_ns,
            ctime_ns,
            0_i64, // btime_ns
            attrs.size,
            0,   // blocks_512
            512, // blksize
        ),
        tidefs_types_vfs_core::InodeFlags::none(),
        0, // subtree_rev
        0, // dir_rev
    )
}
const CREATE_METADATA_RESERVATION_BYTES: u64 = 4096;
/// Convert [`tidefs_namespace::NamespaceError`] to VFS [`Errno`].
pub(crate) fn namespace_error_to_errno(e: tidefs_namespace::NamespaceError) -> Errno {
    match e {
        tidefs_namespace::NamespaceError::NotFound
        | tidefs_namespace::NamespaceError::InodeNotFound => Errno::ENOENT,
        tidefs_namespace::NamespaceError::AlreadyExists => Errno::EEXIST,
        tidefs_namespace::NamespaceError::NotEmpty => Errno::ENOTEMPTY,
        tidefs_namespace::NamespaceError::NotDirectory => Errno::ENOTDIR,
        tidefs_namespace::NamespaceError::IsDirectory => Errno::EISDIR,
        tidefs_namespace::NamespaceError::InvalidName => Errno::EINVAL,
        tidefs_namespace::NamespaceError::TooManySymlinks => Errno::ELOOP,
        tidefs_namespace::NamespaceError::NotSymlink => Errno::EINVAL,
        tidefs_namespace::NamespaceError::LinkCountOverflow => Errno::EMLINK,
        tidefs_namespace::NamespaceError::RenameCycle => Errno::EINVAL,
        _ => Errno::EIO,
    }
}

