/// Extended file attributes returned by `dispatch_statx` (FUSE_STATX, opcode 52).
///
/// Mirrors the fields from `struct statx` that TideFS can populate from
/// the engine's `getattr` path. Birth time (`btime`) is included because
/// `PosixAttrs` already tracks it.
#[derive(Clone, Debug)]
pub struct StatxReply {
    pub stx_mask: u32,
    pub stx_blksize: u32,
    pub stx_attributes: u64,
    pub stx_nlink: u32,
    pub stx_uid: u32,
    pub stx_gid: u32,
    pub stx_mode: u16,
    pub stx_ino: u64,
    pub stx_size: u64,
    pub stx_blocks: u64,
    pub stx_atime_sec: i64,
    pub stx_atime_nsec: u32,
    pub stx_mtime_sec: i64,
    pub stx_mtime_nsec: u32,
    pub stx_ctime_sec: i64,
    pub stx_ctime_nsec: u32,
    pub stx_btime_sec: i64,
    pub stx_btime_nsec: u32,
}

/// Mask bits for `StatxReply::stx_mask`, matching Linux `STATX_*` constants.
pub mod statx_mask {
    pub const STATX_BASIC_STATS: u32 = 0x0000_07ff;
    pub const STATX_BTIME: u32 = 0x0000_0800;
    /// Mask bit indicating the caller wants the `stx_attributes` field.
    pub const STATX_ATTRS: u32 = 0x0000_1000;
}

/// Extended attribute attribute constants used in `stx_attributes`.
/// Matches Linux `STATX_ATTR_*` flags.
pub mod statx_attr {
    /// Inode has extended attributes present.
    pub const STATX_ATTR_XATTR_PRESENT: u64 = 0x0000_0000_0000_0001;
    /// Inode has a POSIX access ACL stored as an xattr.
    pub const STATX_ATTR_POSIX_ACL_ACCESS: u64 = 0x0000_0000_0000_0002;
    /// Inode has a POSIX default ACL stored as an xattr (directories).
    pub const STATX_ATTR_POSIX_ACL_DEFAULT: u64 = 0x0000_0000_0000_0004;
}

const FUSE_STATX_OUT_WIRE_SIZE: usize = 288;
const FUSE_STATX_CACHE_VALID_SECS: u64 = 0;
const FUSE_STATX_CACHE_VALID_NSECS: u32 = 0;
const FUSE_STATX_OUT_FLAGS: u32 = 0;
const STATX_SUPPORTED_ATTRIBUTES: u64 = statx_attr::STATX_ATTR_XATTR_PRESENT
    | statx_attr::STATX_ATTR_POSIX_ACL_ACCESS
    | statx_attr::STATX_ATTR_POSIX_ACL_DEFAULT;

/// Metadata about an inode's xattr state, used to enrich statx replies.
#[derive(Clone, Debug, Default)]
pub struct XattrStatxMetadata {
    /// True when at least one xattr (of any namespace) exists.
    pub has_any_xattr: bool,
    /// True when `system.posix_acl_access` exists on the inode.
    pub has_acl_access: bool,
    /// True when `system.posix_acl_default` exists on the inode.
    pub has_acl_default: bool,
    /// BLAKE3-256 digest of all xattr names and values (domain-separated).
    pub blake3_digest: Option<blake3::Hash>,
}

impl XattrStatxMetadata {
    /// Build metadata from a NUL-separated packed xattr name list.
    pub fn from_packed_xattr_names(packed: &[u8]) -> Self {
        let names: Vec<&[u8]> = packed
            .split(|b| *b == 0)
            .filter(|s| !s.is_empty())
            .collect();
        let has_any_xattr = !names.is_empty();
        let has_acl_access = names.iter().any(|n| *n == b"system.posix_acl_access");
        let has_acl_default = names.iter().any(|n| *n == b"system.posix_acl_default");
        Self {
            has_any_xattr,
            has_acl_access,
            has_acl_default,
            blake3_digest: None,
        }
    }
}

#[derive(Clone, Debug, Eq, Ord, PartialEq, PartialOrd)]
struct DentryKey {
    parent_inode: u64,
    name: Vec<u8>,
}

impl DentryKey {
    fn new(parent_inode: u64, name: &[u8]) -> Self {
        Self {
            parent_inode,
            name: name.to_vec(),
        }
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct DentryPolicy {
    positive_entry_ttl: Duration,
    positive_attr_ttl: Duration,
    negative_entry_ttl: Duration,
}

impl Default for DentryPolicy {
    fn default() -> Self {
        Self {
            positive_entry_ttl: Duration::from_secs(1),
            positive_attr_ttl: Duration::from_secs(1),
            negative_entry_ttl: Duration::from_millis(250),
        }
    }
}

impl DentryPolicy {
    fn for_timestamp_policy(self, timestamp_policy: TimestampPolicy, read_only: bool) -> Self {
        let mut policy = self;
        if read_only || timestamp_policy != TimestampPolicy::NoAtime {
            policy.positive_entry_ttl = Duration::ZERO;
            policy.positive_attr_ttl = Duration::ZERO;
        }
        policy
    }

    fn positive_lookup_config(self) -> LookupConfig {
        lookup_config_from_ttls(self.positive_entry_ttl, self.positive_attr_ttl)
    }

    fn negative_lookup_config(self) -> LookupConfig {
        lookup_config_from_ttls(self.negative_entry_ttl, Duration::from_secs(0))
    }

    fn positive_reply_ttl(self) -> Duration {
        lookup_cache_ttl(self.positive_lookup_config())
    }

    fn negative_reply_ttl(self) -> Duration {
        self.negative_entry_ttl
    }
    /// Construct a DentryPolicy from a CoherencyProfileParams.
    fn from_coherency_params(params: crate::coherency_profile::CoherencyProfileParams) -> Self {
        Self {
            positive_entry_ttl: params.entry_ttl,
            positive_attr_ttl: params.attr_ttl,
            negative_entry_ttl: params.negative_ttl,
        }
    }
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct DentryInvalidationState {
    next_generation: u64,
    invalidated_entries: BTreeMap<DentryKey, u64>,
    invalidated_parent_dirs: BTreeMap<u64, u64>,
}

impl DentryInvalidationState {
    fn next_invalidation_generation(&mut self) -> u64 {
        self.next_generation = self.next_generation.saturating_add(1);
        self.next_generation
    }

    fn invalidate_child(&mut self, parent_inode: u64, name: &[u8]) -> u64 {
        let generation = self.next_invalidation_generation();
        self.invalidated_entries
            .insert(DentryKey::new(parent_inode, name), generation);
        self.invalidated_parent_dirs
            .insert(parent_inode, generation);
        generation
    }

    fn invalidate_rename(
        &mut self,
        old_parent_inode: u64,
        old_name: &[u8],
        new_parent_inode: u64,
        new_name: &[u8],
    ) -> u64 {
        let generation = self.next_invalidation_generation();
        self.invalidated_entries
            .insert(DentryKey::new(old_parent_inode, old_name), generation);
        self.invalidated_entries
            .insert(DentryKey::new(new_parent_inode, new_name), generation);
        self.invalidated_parent_dirs
            .insert(old_parent_inode, generation);
        self.invalidated_parent_dirs
            .insert(new_parent_inode, generation);
        generation
    }

    #[cfg(test)]
    fn entry_generation(&self, parent_inode: u64, name: &[u8]) -> Option<u64> {
        self.invalidated_entries
            .get(&DentryKey::new(parent_inode, name))
            .copied()
    }

    #[cfg(test)]
    fn parent_generation(&self, parent_inode: u64) -> Option<u64> {
        self.invalidated_parent_dirs.get(&parent_inode).copied()
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct DataCacheGenerationSnapshot {
    generation: u64,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct DataCacheRangeFence {
    start: u64,
    end: u64,
    generation: u64,
}

#[derive(Clone, Debug, Default, Eq, PartialEq)]
struct DataCacheInvalidationState {
    next_generation: u64,
    inode_generations: BTreeMap<u64, u64>,
    range_fences: BTreeMap<u64, Vec<DataCacheRangeFence>>,
    read_cache_generations: BTreeMap<u64, u64>,
    fuse_page_generations: BTreeMap<(u64, u64), u64>,
}

impl DataCacheInvalidationState {
    const RANGE_FENCE_LIMIT_PER_INODE: usize = 1024;

    fn next_generation(&mut self) -> u64 {
        self.next_generation = self.next_generation.saturating_add(1);
        self.next_generation
    }

    fn invalidate_inode(&mut self, ino: u64) -> u64 {
        let generation = self.next_generation();
        self.inode_generations.insert(ino, generation);
        self.range_fences.remove(&ino);
        self.read_cache_generations.remove(&ino);
        self.fuse_page_generations
            .retain(|(page_ino, _), _| *page_ino != ino);
        generation
    }

    fn invalidate_range(&mut self, ino: u64, offset: u64, length: u64) -> u64 {
        if length == 0 {
            return self.current_generation(ino, offset, length);
        }
        if offset == 0 && length == u64::MAX {
            return self.invalidate_inode(ino);
        }

        let generation = self.next_generation();
        let end = offset.saturating_add(length);
        let fences = self.range_fences.entry(ino).or_default();
        fences.push(DataCacheRangeFence {
            start: offset,
            end,
            generation,
        });
        if fences.len() > Self::RANGE_FENCE_LIMIT_PER_INODE {
            self.inode_generations.insert(ino, generation);
            self.range_fences.remove(&ino);
        }
        self.read_cache_generations.remove(&ino);
        generation
    }

    fn current_generation(&self, ino: u64, offset: u64, length: u64) -> u64 {
        let mut generation = self.inode_generations.get(&ino).copied().unwrap_or(0);
        if length == 0 {
            return generation;
        }
        let end = offset.saturating_add(length);
        if let Some(fences) = self.range_fences.get(&ino) {
            for fence in fences {
                if fence.start < end && offset < fence.end {
                    generation = generation.max(fence.generation);
                }
            }
        }
        generation
    }

    fn snapshot(&self, ino: u64, offset: u64, length: u64) -> DataCacheGenerationSnapshot {
        DataCacheGenerationSnapshot {
            generation: self.current_generation(ino, offset, length),
        }
    }

    fn snapshot_allows_range(
        &self,
        ino: u64,
        offset: u64,
        length: u64,
        snapshot: DataCacheGenerationSnapshot,
    ) -> bool {
        snapshot.generation >= self.current_generation(ino, offset, length)
    }

    fn record_read_cache_fill(&mut self, ino: u64, snapshot: DataCacheGenerationSnapshot) {
        self.read_cache_generations.insert(ino, snapshot.generation);
    }

    fn read_cache_allows_range(&self, ino: u64, offset: u64, length: u64) -> bool {
        self.read_cache_generations
            .get(&ino)
            .copied()
            .is_some_and(|generation| generation >= self.current_generation(ino, offset, length))
    }

    fn forget_read_cache_fill(&mut self, ino: u64) {
        self.read_cache_generations.remove(&ino);
    }

    fn record_fuse_page_fill(
        &mut self,
        ino: u64,
        offset: u64,
        length: u64,
        page_size: u64,
        snapshot: DataCacheGenerationSnapshot,
    ) {
        if length == 0 || page_size == 0 {
            return;
        }
        let end = offset.saturating_add(length);
        let mut page_offset = (offset / page_size) * page_size;
        while page_offset < end {
            self.fuse_page_generations
                .insert((ino, page_offset), snapshot.generation);
            page_offset = page_offset.saturating_add(page_size);
        }
    }

    fn fuse_page_allows_range(&self, ino: u64, page_offset: u64, page_size: u64) -> bool {
        self.fuse_page_generations
            .get(&(ino, page_offset))
            .copied()
            .is_some_and(|generation| {
                generation >= self.current_generation(ino, page_offset, page_size)
            })
    }

    fn forget_fuse_page_fill(&mut self, ino: u64, page_offset: u64) {
        self.fuse_page_generations.remove(&(ino, page_offset));
    }
}

/// Daemon-side negative lookup cache that avoids repeated dir-index scans
/// for recently-missed names.  The kernel also caches negative dentries via
/// the `entry_ttl` in the FUSE reply; this cache catches repeated lookups
/// that arrive after the kernel TTL expires or from parallel clients.
///
/// Entries are keyed by `(parent_inode, name)` and expire after a
/// configurable TTL.  Directory mutations (create, unlink, rename, etc.)
/// eagerly invalidate the affected entries.
#[derive(Debug)]
struct NegativeLookupCache {
    /// Cached entries: `(parent_inode, name, expiry_ns)`.
    entries: Vec<(u64, Vec<u8>, u64)>,
    /// Maximum number of cached negative entries.
    max_entries: usize,
    /// Default TTL in nanoseconds for new entries.
    default_ttl_ns: u64,
}

impl NegativeLookupCache {
    /// Create a new negative cache with the given capacity and default TTL.
    fn new(max_entries: usize, default_ttl: std::time::Duration) -> Self {
        Self {
            entries: Vec::with_capacity(max_entries.min(64)),
            max_entries,
            default_ttl_ns: default_ttl.as_nanos() as u64,
        }
    }

    /// Return `true` if `(parent_ino, name)` has a non-expired negative
    /// cache entry, `false` otherwise.  Expired entries are pruned eagerly.
    fn check(&mut self, parent_ino: u64, name: &[u8], now_ns: u64) -> bool {
        self.prune_expired(now_ns);
        self.entries
            .iter()
            .any(|(p, n, _)| *p == parent_ino && n == name)
    }

    /// Insert a negative entry with the default TTL.
    /// If the cache is full the oldest entry is evicted.
    fn insert(&mut self, parent_ino: u64, name: &[u8], now_ns: u64) {
        // De-duplicate: remove any existing entry for the same key.
        self.entries
            .retain(|(p, n, _)| !(*p == parent_ino && n == name));
        if self.entries.len() >= self.max_entries {
            // Evict oldest (front of FIFO vec).
            self.entries.remove(0);
        }
        self.entries
            .push((parent_ino, name.to_vec(), now_ns + self.default_ttl_ns));
    }

    /// Invalidate a specific `(parent_ino, name)` entry.
    fn invalidate_child(&mut self, parent_ino: u64, name: &[u8]) {
        self.entries
            .retain(|(p, n, _)| !(*p == parent_ino && n == name));
    }

    /// Invalidate all entries for a given parent directory.
    fn invalidate_parent_dir(&mut self, parent_ino: u64) {
        self.entries.retain(|(p, _, _)| *p != parent_ino);
    }

    /// Remove all expired entries.
    fn prune_expired(&mut self, now_ns: u64) {
        self.entries.retain(|(_, _, expiry)| *expiry > now_ns);
    }

    /// Return the current number of cached entries.
    #[cfg(test)]
    fn len(&self) -> usize {
        self.entries.len()
    }
}

const NAMESPACE_DIR_HANDLE_TAG: u64 = 1 << 63;

fn namespace_dir_handle_id(ino: u64) -> u64 {
    NAMESPACE_DIR_HANDLE_TAG | (ino & !NAMESPACE_DIR_HANDLE_TAG)
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum AdapterDirHandleBacking {
    Engine,
    Namespace,
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
struct AdapterDirHandle {
    dh: EngineDirHandle,
    cursor: u64,
    backing: AdapterDirHandleBacking,
}

impl AdapterDirHandle {
    fn new(dh: EngineDirHandle) -> Self {
        Self {
            dh,
            cursor: 0,
            backing: AdapterDirHandleBacking::Engine,
        }
    }

    fn namespace(dh: EngineDirHandle) -> Self {
        Self {
            dh,
            cursor: 0,
            backing: AdapterDirHandleBacking::Namespace,
        }
    }

    fn requested_offset(&self, kernel_offset: u64) -> u64 {
        if kernel_offset == self.cursor {
            self.cursor
        } else {
            kernel_offset
        }
    }

    fn finish_page(&mut self, requested_offset: u64, last_emitted_cookie: Option<u64>) {
        self.cursor = last_emitted_cookie.unwrap_or(requested_offset);
    }
}

#[derive(Debug, Default)]
struct AdapterDirHandleTable {
    handles: BTreeMap<u64, AdapterDirHandle>,
}

impl AdapterDirHandleTable {
    fn insert(&mut self, dh: EngineDirHandle) {
        self.handles
            .insert(dh.dh_id.get(), AdapterDirHandle::new(dh));
    }

    fn insert_namespace(&mut self, dh: EngineDirHandle) {
        self.handles
            .insert(dh.dh_id.get(), AdapterDirHandle::namespace(dh));
    }

    fn get(&self, fh: u64) -> Option<AdapterDirHandle> {
        self.handles.get(&fh).copied()
    }

    fn remove(&mut self, fh: u64) -> Option<AdapterDirHandle> {
        self.handles.remove(&fh)
    }

    fn finish_page(&mut self, fh: u64, requested_offset: u64, last_emitted_cookie: Option<u64>) {
        if let Some(handle) = self.handles.get_mut(&fh) {
            handle.finish_page(requested_offset, last_emitted_cookie);
        }
    }
}

