    /// Public dispatch for POSIX rename(2) / renameat2(2).
    ///
    /// Atomically moves `name` under `parent` to `newname` under `newparent`.
    /// Supports `RENAME_NOREPLACE` (EEXIST if destination exists),
    /// `RENAME_EXCHANGE` (atomically swap two entries), and the default
    /// overwrite semantics.
    ///
    /// Errors: `ENOENT`, `ENOTDIR`, `EISDIR`, `EEXIST` (NOREPLACE),
    /// `ENOTEMPTY`, `EXDEV`, `EINVAL`.
    #[tracing::instrument(skip(self, ctx), fields(ino = tracing::field::Empty, op = "rename"))]
    pub fn dispatch_rename(
        &self,
        ctx: &RequestCtx,
        parent: u64,
        name: &[u8],
        newparent: u64,
        newname: &[u8],
        flags: u32,
    ) -> Result<(), Errno> {
        self.dispatch_rename_entry(ctx, parent, name, newparent, newname, flags)
    }

    /// Dispatch a POSIX rename with intent-log crash-safety atomicity.
    /// Dispatch a POSIX rename through the VFS engine.
    pub fn dispatch_rename_entry(
        &self,
        ctx: &RequestCtx,
        parent: u64,
        name: &[u8],
        newparent: u64,
        newname: &[u8],
        flags: u32,
    ) -> Result<(), Errno> {
        self.check_not_read_only()?;
        // Phase 1: Pre-checks (permissions, sticky-bit) before recording intent.
        // Failures here mean no intent was recorded -- no crash-recovery risk.
        let mount_identity = self.permission_mount_identity()?;
        let e = self.engine.lock().unwrap();
        let engine: &dyn VfsEngine = &**e;
        let old_parent = InodeId::new(parent);
        let new_parent = InodeId::new(newparent);
        rename_mutation_preflight(
            engine,
            old_parent,
            name,
            new_parent,
            newname,
            ctx,
            &mount_identity,
        )?;
        let overwritten_target_attr = if flags
            & tidefs_types_posix_filesystem_adapter_core::rename_flags::RENAME_EXCHANGE
            == 0
        {
            match engine.lookup(new_parent, newname, ctx) {
                Ok(attr) => Some(attr),
                Err(Errno::ENOENT) => None,
                Err(_) => None,
            }
        } else {
            None
        };
        let result = self
            .rename_dispatch
            .dispatch_engine_with_flags(EngineRenameRequest {
                engine,
                ctx,
                old_parent,
                old_name: name,
                new_parent,
                new_name: newname,
                flags,
            });
        drop(e);

        self.record_dentry_rename(parent, name, newparent, newname);

        self.invalidate_inode_metadata_after_engine_write(parent);
        self.invalidate_inode_metadata_after_engine_write(newparent);
        if result.is_ok() {
            if let Some(overwritten) = overwritten_target_attr {
                let overwritten_ino = overwritten.inode_id.get();
                if overwritten.posix.nlink <= 1
                    && self
                        .file_handles
                        .lock()
                        .unwrap()
                        .open_ref_count(overwritten_ino)
                        == 0
                {
                    self.invalidate_caches_after_inode_data_unreachable(overwritten_ino);
                } else {
                    self.invalidate_inode_metadata_after_engine_write(overwritten_ino);
                }
            }
        }

        result
    }

    /// Public dispatch for POSIX link(2).  Creates a hard link from an
    /// existing inode to a new name under `newparent`.  Returns the inode
    /// attributes on success.  Errors: `ENOENT`, `EEXIST`, `EPERM` (old
    /// path is a directory), `EMLINK`, `ENOTDIR`, `ENOSPC`.
    #[tracing::instrument(skip(self, ctx), fields(ino = %ino, newparent = %newparent, op = "link"))]
    pub fn dispatch_link(
        &self,
        ctx: &RequestCtx,
        ino: u64,
        newparent: u64,
        newname: &[u8],
    ) -> Result<InodeAttr, Errno> {
        // Mounted hard links use the engine as the authoritative inode,
        // metadata, and persistence boundary. Namespace-only hard-link
        // support remains available through dispatch_link_via_namespace for
        // legacy tests.
        self.dispatch_link_entry(ctx, ino, newparent, newname)
    }

    pub fn dispatch_link_entry(
        &self,
        ctx: &RequestCtx,
        ino: u64,
        newparent: u64,
        newname: &[u8],
    ) -> Result<InodeAttr, Errno> {
        self.check_not_read_only()?;
        let mount_identity = self.permission_mount_identity()?;
        let e = self.engine.lock().unwrap();
        check_parent_write_execute(&**e, InodeId::new(newparent), ctx, &mount_identity)?;
        // POSIX: reject link if target parent directory is immutable.
        {
            let parent_attr = e.getattr(InodeId::new(newparent), None, ctx)?;
            enforce_immutable_guard(parent_attr.flags.to_raw_flags())?;
        }
        let attr = dispatch_link_batch(
            &**e as &dyn tidefs_vfs_engine::VfsEngine,
            &[LinkBatchRequest {
                target: InodeId::new(ino),
                new_parent: InodeId::new(newparent),
                new_name: newname,
                ctx: ctx.clone(),
            }],
        )
        .into_iter()
        .next()
        .unwrap()?;
        self.invalidate_inode_metadata_after_engine_write(attr.inode_id.get());
        self.record_dentry_child_mutation(newparent, newname);
        self.populate_getattr_cache(attr.inode_id.get(), &attr);
        Ok(attr)
    }
    /// Namespace-backed mkdir: call [`tidefs_namespace::Namespace::create_dir`]
    /// Namespace-backed hard link: call [`tidefs_namespace::Namespace::create_hard_link_by_inode`]
    /// with the target inode directly, bypassing the old-parent/old-name lookup.
    fn dispatch_link_via_namespace(
        &self,
        ns: &Namespace,
        target: u64,
        new_parent: u64,
        new_name: &[u8],
    ) -> Result<InodeAttr, Errno> {
        let new_name_str = std::str::from_utf8(new_name).map_err(|_| Errno::EINVAL)?;
        let ino = ns
            .create_hard_link_by_inode(target, new_parent, new_name_str)
            .map_err(namespace_error_to_errno)?;
        let ns_attrs = ns.get_attrs(ino).ok_or(Errno::EIO)?;
        let attr = namespace_attrs_to_inode_attr(&ns_attrs);
        self.record_dentry_child_mutation(new_parent, new_name);
        self.populate_getattr_cache(attr.inode_id.get(), &attr);
        Ok(attr)
    }

    /// with default directory attributes, return the created inode's [`InodeAttr`].
    fn dispatch_mkdir_via_namespace(
        &self,
        ns: &Namespace,
        parent: u64,
        name: &[u8],
        mode: u32,
    ) -> Result<InodeAttr, Errno> {
        let name_str = std::str::from_utf8(name).map_err(|_| Errno::EINVAL)?;
        let now = std::time::SystemTime::now();
        let attrs = tidefs_namespace::InodeAttributes {
            inode: 0,                     // allocated by create_dir
            mode: mode & 0o777 | 0o40000, // S_IFDIR + permissions
            uid: 0,
            gid: 0,
            size: 0,
            nlink: 2, // . and parent
            atime: now,
            mtime: now,
            ctime: now,
            rdev: 0,
        };
        let ino = ns
            .create_dir(parent, name_str, attrs)
            .map_err(namespace_error_to_errno)?;
        let ns_attrs = ns.get_attrs(ino).ok_or(Errno::EIO)?;
        let attr = namespace_attrs_to_inode_attr(&ns_attrs);
        self.record_dentry_child_mutation(parent, name);
        self.populate_getattr_cache(attr.inode_id.get(), &attr);
        Ok(attr)
    }

    /// Namespace-backed create: call [`tidefs_namespace::Namespace::create_file`]
    /// with the given file attributes, allocate a file handle, and return a
    /// [`VfsCreateDispatch`].
    fn dispatch_create_via_namespace(
        &self,
        ns: &Namespace,
        parent: u64,
        name: &[u8],
        mode: u32,
        open_flags: u32,
    ) -> Result<VfsCreateDispatch, Errno> {
        let name_str = std::str::from_utf8(name).map_err(|_| Errno::EINVAL)?;
        let now = std::time::SystemTime::now();
        let attrs = tidefs_namespace::InodeAttributes {
            inode: 0,
            mode: mode & 0o777,
            uid: 0,
            gid: 0,
            size: 0,
            nlink: 1,
            atime: now,
            mtime: now,
            ctime: now,
            rdev: 0,
        };
        let ino = ns
            .create_file(parent, name_str, attrs)
            .map_err(namespace_error_to_errno)?;
        let ns_attrs = ns.get_attrs(ino).ok_or(Errno::EIO)?;
        let attr = namespace_attrs_to_inode_attr(&ns_attrs);
        self.record_dentry_child_mutation(parent, name);
        self.populate_getattr_cache(attr.inode_id.get(), &attr);

        let engine_fh = tidefs_types_vfs_core::EngineFileHandle::new(
            tidefs_types_vfs_core::InodeId::new(attr.inode_id.get()),
            0u32,
            tidefs_types_vfs_core::FileHandleId::new(0),
            0,
        );
        let fuse_open_flags = self.fuse_open_flags_for_request(open_flags);
        let adapter_fh = {
            let mut handles = self.file_handles.lock().unwrap();
            let adapter_fh = handles.allocate(attr.inode_id.get(), open_flags, engine_fh);
            if let Some(handle) = handles.handles.get_mut(&adapter_fh) {
                handle.fuse_open_flags = fuse_open_flags;
            }
            adapter_fh
        };
        self.file_handles.lock().unwrap().inc_open_ref(ino);
        self.remember_writeback_inode(ino);
        Ok(VfsCreateDispatch {
            attr,
            adapter_fh,
            fuse_open_flags,
        })
    }
    /// Namespace-backed mknod: call [`tidefs_namespace::Namespace::mknod`]
    /// with the given mode and rdev, return the created inode's [`InodeAttr`].
    fn dispatch_mknod_via_namespace(
        &self,
        ns: &Namespace,
        parent: u64,
        name: &[u8],
        mode: u32,
        rdev: u32,
    ) -> Result<InodeAttr, Errno> {
        let name_str = std::str::from_utf8(name).map_err(|_| Errno::EINVAL)?;
        let ino = ns
            .mknod(parent, name_str, mode, rdev)
            .map_err(namespace_error_to_errno)?;
        let ns_attrs = ns.get_attrs(ino).ok_or(Errno::EIO)?;
        let attr = namespace_attrs_to_inode_attr(&ns_attrs);
        self.record_dentry_child_mutation(parent, name);
        self.populate_getattr_cache(attr.inode_id.get(), &attr);
        Ok(attr)
    }

    /// Namespace-backed lookup: use [`tidefs_namespace::Namespace::lookup`]
    /// to resolve a (parent, name) pair through the directory index.  When
    /// the VFS engine also knows the inode, return the engine attributes so
    /// remounted namespace metadata cannot synthesize fresh timestamps.
    fn dispatch_lookup_via_namespace(
        &self,
        ctx: &RequestCtx,
        ns: &Namespace,
        parent: u64,
        name: &[u8],
    ) -> Result<InodeAttr, Errno> {
        let name_str = std::str::from_utf8(name).map_err(|_| Errno::EINVAL)?;
        let ino = ns
            .lookup(parent, name_str)
            .map_err(namespace_error_to_errno)?
            .ok_or(Errno::ENOENT)?;
        let e = self.engine.lock().unwrap();
        let engine_attr = e.getattr(InodeId::new(ino), None, ctx);
        match engine_attr {
            Ok(attr) => {
                self.sync_namespace_attrs_local(ino, &attr);
                self.cache_path_lookup(parent, name, &attr);
                self.record_lookup_count(attr.inode_id.get());
                return Ok(attr);
            }
            Err(Errno::ENOENT | Errno::ESTALE | Errno::EIO) => {}
            Err(errno) => return Err(errno),
        }

        let engine_lookup_attr = e.lookup(InodeId::new(parent), name, ctx);
        match engine_lookup_attr {
            Ok(attr) if attr.inode_id.get() == ino => {
                self.sync_namespace_attrs_local(ino, &attr);
                self.cache_path_lookup(parent, name, &attr);
                self.record_lookup_count(attr.inode_id.get());
                return Ok(attr);
            }
            Ok(_) | Err(Errno::ENOENT | Errno::ESTALE | Errno::EIO) => {}
            Err(errno) => return Err(errno),
        }

        let ns_attrs = ns.get_attrs(ino).ok_or(Errno::EIO)?;
        let attr = namespace_attrs_to_inode_attr(&ns_attrs);
        self.cache_path_lookup(parent, name, &attr);
        self.record_lookup_count(attr.inode_id.get());
        Ok(attr)
    }

    fn cache_path_lookup(&self, parent: u64, name: &[u8], attr: &InodeAttr) {
        self.path_lookup_cache.lock().unwrap().insert(
            parent,
            name,
            attr.inode_id.get(),
            attr.generation.get(),
            *attr,
        );
    }

    fn record_lookup_count(&self, ino: u64) {
        let mut counts = self.lookup_counts.lock().unwrap();
        *counts.entry(ino).or_insert(0) = counts.get(&ino).unwrap_or(&0).saturating_add(1);
    }

    fn has_forget_refcount(&self, ino: u64) -> bool {
        self.forget_refcounts
            .lock()
            .unwrap()
            .get(&ino)
            .copied()
            .unwrap_or(0)
            > 0
    }

    fn remember_removed_lookup_attr(&self, attr: InodeAttr) {
        let ino = attr.inode_id.get();
        if ino == 1 || !self.has_forget_refcount(ino) {
            return;
        }
        let mut removed_attr = attr;
        removed_attr.posix.nlink = 0;
        self.removed_lookup_attrs
            .lock()
            .unwrap()
            .insert(ino, removed_attr);
    }

    fn removed_lookup_attr_out(&self, ino: u64) -> Option<FuseAttrOut> {
        if !self.has_forget_refcount(ino) {
            self.removed_lookup_attrs.lock().unwrap().remove(&ino);
            return None;
        }
        let attr = self
            .removed_lookup_attrs
            .lock()
            .unwrap()
            .get(&ino)
            .copied()?;
        let out = crate::workers_meta::fuse_attr_out(ino, &attr.posix, attr.kind);
        Some(fuse_attr_out_with_ttl(out, Duration::ZERO))
    }

    pub fn dispatch_mkdir_entry(
        &self,
        ctx: &RequestCtx,
        parent: u64,
        name: &[u8],
        mode: u32,
    ) -> Result<InodeAttr, Errno> {
        self.check_not_read_only()?;
        let mount_identity = self.permission_mount_identity()?;
        let e = self.engine.lock().unwrap();
        check_parent_write_execute_mutation_preflight(
            &**e,
            InodeId::new(parent),
            ctx,
            &mount_identity,
        )?;
        let attr = dispatch_mkdir_batch(
            &**e as &dyn tidefs_vfs_engine::VfsEngine,
            &[MkdirBatchRequest {
                parent: InodeId::new(parent),
                name,
                mode,
                ctx: ctx.clone(),
            }],
        )
        .into_iter()
        .next()
        .unwrap()?;
        self.record_dentry_child_mutation(parent, name);
        self.populate_getattr_cache(attr.inode_id.get(), &attr);
        Ok(attr)
    }

    #[tracing::instrument(skip(self, ctx), fields(ino = %parent, op = "mkdir"))]
    pub fn dispatch_mkdir(
        &self,
        ctx: &RequestCtx,
        parent: u64,
        name: &[u8],
        mode: u32,
    ) -> Result<InodeAttr, Errno> {
        // Always route mkdir through the engine so the inode is known
        // to the engine for subsequent operations.
        self.dispatch_mkdir_entry(ctx, parent, name, mode)
    }
    #[tracing::instrument(skip(self, ctx), fields(ino = %parent, op = "unlink"))]
    pub fn dispatch_unlink(&self, ctx: &RequestCtx, parent: u64, name: &[u8]) -> Result<(), Errno> {
        self.dispatch_unlink_entry(ctx, parent, name)
    }

    #[tracing::instrument(skip(self, ctx), fields(ino = %parent, op = "rmdir"))]
    pub fn dispatch_rmdir(&self, ctx: &RequestCtx, parent: u64, name: &[u8]) -> Result<(), Errno> {
        self.dispatch_rmdir_entry(ctx, parent, name)
    }

    pub fn dispatch_unlink_entry(
        &self,
        ctx: &RequestCtx,
        parent: u64,
        name: &[u8],
    ) -> Result<(), Errno> {
        self.check_not_read_only()?;
        let mount_identity = self.permission_mount_identity()?;
        let e = self.engine.lock().unwrap();
        let parent_id = InodeId::new(parent);
        let child_attr =
            delete_child_attr_for_mutation_preflight(&**e, parent_id, name, ctx, &mount_identity)?;
        // Capacity tracking for freed space is handled by the engine's
        // CapacityAuthority during unlink dispatch.
        let child_inode_for_delete = child_attr.inode_id;
        let result = dispatch_unlink_batch(
            &**e as &dyn tidefs_vfs_engine::VfsEngine,
            &[UnlinkBatchRequest {
                parent: parent_id,
                name,
                ctx: ctx.clone(),
            }],
        )
        .into_iter()
        .next()
        .unwrap();

        result?;

        // Capacity tracking for freed space is handled by the engine's
        // CapacityAuthority (record_free) during unlink dispatch.
        self.invalidate_inode_metadata_after_engine_write(child_inode_for_delete.get());
        if child_attr.posix.nlink <= 1 {
            self.remember_removed_lookup_attr(child_attr);
        }
        self.record_dentry_child_mutation(parent, name);

        // When unlink succeeds and nlink reaches 0 but open handles
        // still reference the inode, insert into the orphan index so
        // the last-close handler in dispatch_release can trigger
        // cleanup-engine reclamation (#5527, #5549).
        let refcount = {
            let fht = self.file_handles.lock().unwrap();
            fht.open_ref_count(child_inode_for_delete.get())
        };
        if refcount > 0 {
            // The inode was unlinked while open: orphan it.
            if let Ok(attrs) = e.getattr(child_inode_for_delete, None, ctx) {
                if attrs.posix.nlink == 0 {
                    let entry = OrphanEntry::new(
                        child_inode_for_delete.get(),
                        attrs.generation.get(),
                        0,
                        OrphanEntryFlags::NONE,
                    );
                    self.orphan_index
                        .lock()
                        .unwrap()
                        .insert(child_inode_for_delete.get(), entry);
                }
            }
        } else if child_attr.posix.nlink <= 1 {
            self.invalidate_caches_after_inode_data_unreachable(child_inode_for_delete.get());
        }

        Ok(())
    }
    /// Namespace-backed unlink: call [`tidefs_namespace::Namespace::unlink`]
    /// which handles both file removal and empty-directory removal.
    fn dispatch_unlink_via_namespace(
        &self,
        ns: &Namespace,
        parent: u64,
        name: &[u8],
        ctx: &RequestCtx,
    ) -> Result<(), Errno> {
        let name_str = std::str::from_utf8(name).map_err(|_| Errno::EINVAL)?;

        // Resolve child inode for sticky-bit enforcement and notify_delete.
        let child_inode = ns
            .lookup(parent, name_str)
            .map_err(namespace_error_to_errno)
            .unwrap_or(None);

        // POSIX sticky-bit (S_ISVTX) enforcement: when the parent
        // directory has the sticky bit set, only the file owner,
        // directory owner, or root may delete entries.
        if let Some(parent_attrs) = ns.get_attrs(parent) {
            if let Some(child_ino) = child_inode {
                if let Some(child_attrs) = ns.get_attrs(child_ino) {
                    if !sticky_dir_allows_unlink_or_rename(
                        parent_attrs.mode,
                        parent_attrs.uid,
                        child_attrs.uid,
                        ctx.uid,
                    ) {
                        return Err(Errno::EPERM);
                    }
                }
            }
        }

        let ns_result = ns
            .unlink(parent, name_str)
            .map_err(namespace_error_to_errno);

        ns_result?;

        self.record_dentry_child_mutation(parent, name);
        if let Some(child) = child_inode {
            self.negative_cache
                .lock()
                .unwrap()
                .invalidate_parent_dir(child);
            self.path_lookup_cache
                .lock()
                .unwrap()
                .invalidate_parent_dir(child);
        }
        Ok(())
    }

    /// and enforce directory-empty constraint through the namespace.
    fn dispatch_rmdir_via_namespace(
        &self,
        ns: &Namespace,
        parent: u64,
        name: &[u8],
        ctx: &RequestCtx,
    ) -> Result<(), Errno> {
        let name_str = std::str::from_utf8(name).map_err(|_| Errno::EINVAL)?;

        // Resolve child inode for sticky-bit enforcement and notify_delete.
        let child_inode = ns
            .lookup(parent, name_str)
            .map_err(namespace_error_to_errno)
            .unwrap_or(None);

        // POSIX sticky-bit (S_ISVTX) enforcement: when the parent
        // directory has the sticky bit set, only the file owner,
        // directory owner, or root may delete entries.
        if let Some(parent_attrs) = ns.get_attrs(parent) {
            if let Some(child_ino) = child_inode {
                if let Some(child_attrs) = ns.get_attrs(child_ino) {
                    if !sticky_dir_allows_unlink_or_rename(
                        parent_attrs.mode,
                        parent_attrs.uid,
                        child_attrs.uid,
                        ctx.uid,
                    ) {
                        return Err(Errno::EPERM);
                    }
                }
            }
        }

        let ns_result = ns
            .unlink(parent, name_str)
            .map_err(namespace_error_to_errno);

        ns_result?;

        self.record_dentry_child_mutation(parent, name);
        if let Some(child) = child_inode {
            self.negative_cache
                .lock()
                .unwrap()
                .invalidate_parent_dir(child);
            self.path_lookup_cache
                .lock()
                .unwrap()
                .invalidate_parent_dir(child);
        }
        Ok(())
    }

    /// Namespace-backed getattr: resolve inode attributes through
    /// [`tidefs_namespace::Namespace::get_attrs`], convert to [`FuseAttrOut`]
    /// with TTL from the dentry policy, and populate the short-lived getattr
    /// cache for subsequent requests.
    fn dispatch_getattr_via_namespace(
        &self,
        ns: &Namespace,
        ino: u64,
    ) -> Result<FuseAttrOut, Errno> {
        let attrs = ns.get_attrs(ino).ok_or(Errno::ESTALE)?;
        let inode_attr = namespace_attrs_to_inode_attr(&attrs);
        let attr_out = crate::workers_meta::fuse_attr_out(ino, &inode_attr.posix, inode_attr.kind);
        // Populate cache with TTL from the coherency profile.
        let cache_ttl = self.dentry_policy.positive_attr_ttl;
        let attr_out = fuse_attr_out_with_ttl(attr_out, cache_ttl);
        {
            let mut cache = self.getattr_cache.lock().unwrap();
            cache.insert(ino, (attr_out, std::time::Instant::now() + cache_ttl));
        }
        Ok(attr_out)
    }

    /// Namespace-backed setattr: read current attributes via
    /// [`tidefs_namespace::Namespace::get_attrs`], apply the [`SetAttr`]
    /// mask with partial-set semantics (only fields present in the valid
    /// mask are modified), persist through
    /// [`tidefs_namespace::Namespace::update_attrs`], and return the
    /// updated [`FuseAttrOut`].
    fn dispatch_setattr_via_namespace(
        &self,
        ns: &Namespace,
        ino: u64,
        attr: &SetAttr,
        caller_uid: u32,
        caller_gid: u32,
        supplemental_gids: &[u32],
    ) -> Result<FuseAttrOut, Errno> {
        // Read-only mount: reject any attribute mutation.
        if self.read_only {
            return Err(Errno::EROFS);
        }

        let current = ns.get_attrs(ino).ok_or(Errno::ESTALE)?;
        // ── Immutable inode flag enforcement ──────────────────────────────
        // POSIX: immutable files reject chmod, chown, truncate, and utimes.
        // Check before any mutation path so we never touch an immutable inode.
        let mutation_requested = attr.valid
            & (FATTR_SIZE | FATTR_MODE | FATTR_UID | FATTR_GID | FATTR_ATIME | FATTR_MTIME)
            != 0;
        if mutation_requested {
            let e = self.engine.lock().unwrap();
            if let Ok(engine_attr) = e.getattr(InodeId::new(ino), None, &RequestCtx::new_root()) {
                enforce_immutable_guard(engine_attr.flags.to_raw_flags())?;
            }
        }
        // POSIX: truncate on a directory must return EISDIR.
        if attr.valid & FATTR_SIZE != 0 && (current.mode & 0o170000) == 0o040000 {
            return Err(Errno::EISDIR);
        }
        // POSIX permission gate (chmod/chown/chgrp).
        if let Err(_meta_err) = crate::workers_meta::can_setattr(
            caller_uid,
            caller_gid,
            supplemental_gids,
            current.uid,
            current.gid,
            attr.valid,
            attr,
        ) {
            return Err(Errno::EPERM);
        }

        let mut attrs = current;

        // Apply mutable fields from the SetAttr mask (partial-set semantics).
        if attr.valid & FATTR_MODE != 0 {
            attrs.mode = (attrs.mode & S_IFMT) | (attr.mode & !S_IFMT);
        }
        if attr.valid & FATTR_UID != 0 {
            attrs.uid = attr.uid;
        }
        if attr.valid & FATTR_GID != 0 {
            attrs.gid = attr.gid;
        }
        // FATTR_SIZE: update the metadata size field. Extent-map truncation
        // (block deallocation, page-cache invalidation) is handled by the
        // engine dispatch layer above; the namespace layer owns only metadata.
        let now = std::time::SystemTime::now();
        if attr.valid & FATTR_SIZE != 0 {
            attrs.size = attr.size;
            // POSIX: truncate updates mtime if not explicitly set by caller.
            if attr.valid & (FATTR_MTIME | FATTR_MTIME_NOW) == 0 {
                attrs.mtime = now;
            }
        }
        if attr.valid & FATTR_ATIME != 0 {
            attrs.atime = time_from_ns(attr.atime_ns);
        }
        if attr.valid & FATTR_MTIME != 0 {
            attrs.mtime = time_from_ns(attr.mtime_ns);
        }
        if attr.valid & FATTR_ATIME_NOW != 0 {
            attrs.atime = now;
        }
        if attr.valid & FATTR_MTIME_NOW != 0 {
            attrs.mtime = now;
        }
        // Always bump ctime on any metadata change.
        let had_metadata_change = attr.valid
            & (FATTR_MODE
                | FATTR_UID
                | FATTR_GID
                | FATTR_ATIME
                | FATTR_MTIME
                | FATTR_ATIME_NOW
                | FATTR_MTIME_NOW
                | FATTR_SIZE)
            != 0;
        if had_metadata_change {
            attrs.ctime = now;
        }

        ns.update_attrs(ino, attrs)
            .map_err(namespace_error_to_errno)?;

        // Re-read to return committed state.
        let updated = ns.get_attrs(ino).ok_or(Errno::ESTALE)?;
        let inode_attr = namespace_attrs_to_inode_attr(&updated);
        let attr_out = crate::workers_meta::fuse_attr_out(ino, &inode_attr.posix, inode_attr.kind);
        // Invalidate getattr cache entry and path lookup cache on mutation.
        {
            let mut cache = self.getattr_cache.lock().unwrap();
            cache.remove(&ino);
        }
        self.path_lookup_cache.lock().unwrap().remove_by_ino(ino);
        Ok(attr_out)
    }

    pub fn dispatch_rmdir_entry(
        &self,
        ctx: &RequestCtx,
        parent: u64,
        name: &[u8],
    ) -> Result<(), Errno> {
        self.check_not_read_only()?;
        let mount_identity = self.permission_mount_identity()?;
        let e = self.engine.lock().unwrap();
        let parent_id = InodeId::new(parent);
        let child_attr =
            delete_child_attr_for_mutation_preflight(&**e, parent_id, name, ctx, &mount_identity)?;
        // Resolve the removed directory's inode before rmdir: needed both
        // for negative-cache invalidation.
        let removed_attr = child_attr;
        // Capacity tracking for freed space is handled by the engine's
        // CapacityAuthority during rmdir dispatch.

        let result = dispatch_rmdir_batch(
            &**e as &dyn tidefs_vfs_engine::VfsEngine,
            &[RmdirBatchRequest {
                parent: parent_id,
                name,
                ctx: ctx.clone(),
            }],
        )
        .into_iter()
        .next()
        .unwrap();

        result?;

        // Capacity tracking for freed space is handled by the engine's
        // CapacityAuthority (record_free) during rmdir dispatch.
        self.remember_removed_lookup_attr(removed_attr);
        self.record_dentry_child_mutation(parent, name);
        // Invalidate all negative-cache entries scoped to the now-removed
        // directory, since lookups against it will return ENOTDIR from now on.
        self.negative_cache
            .lock()
            .unwrap()
            .invalidate_parent_dir(removed_attr.inode_id.get());
        self.path_lookup_cache
            .lock()
            .unwrap()
            .invalidate_parent_dir(removed_attr.inode_id.get());
        Ok(())
    }

    pub fn dispatch_access_check(
        &self,
        ctx: &RequestCtx,
        ino: u64,
        mask: i32,
    ) -> Result<(), Errno> {
        let requested = fuse_access_requested_from_mask(mask)?;
        let mount_identity = self.permission_mount_identity()?;

        let e = self.engine.lock().unwrap();
        let acl: Option<Vec<PosixAclEntry>> =
            match e.getxattr(InodeId::new(ino), b"system.posix_acl_access", ctx) {
                Ok(data) => tidefs_permission::decode_posix_acl_xattr(&data).ok(),
                Err(Errno::ENODATA) => None,
                Err(_) => None,
            };
        match e.getattr(InodeId::new(ino), None, ctx) {
            Ok(attr) => {
                plan_fuse_access_result(Ok(attr), ctx, requested, acl.as_deref(), &mount_identity)
            }
            Err(Errno::ENOENT | Errno::ESTALE | Errno::EIO) if self.namespace.is_some() => {
                drop(e);
                let ns = self.namespace.as_ref().expect("namespace checked");
                let attrs = ns.get_attrs(ino).ok_or(Errno::ESTALE)?;
                let inode_attr = namespace_attrs_to_inode_attr(&attrs);
                plan_fuse_access_result(Ok(inode_attr), ctx, requested, None, &mount_identity)
            }
            Err(errno) => Err(errno),
        }
    }

    pub fn dispatch_access(&self, ctx: &RequestCtx, ino: u64, mask: i32) -> Result<(), Errno> {
        self.dispatch_access_check(ctx, ino, mask)
    }

    fn project_snapshot_catalog_directory(
        mut template: InodeAttr,
        inode_id: InodeId,
        generation: Generation,
    ) -> Result<InodeAttr, Errno> {
        if template.kind != NodeKind::Dir {
            return Err(Errno::ENOTDIR);
        }
        template.inode_id = inode_id;
        template.generation = generation;
        Ok(template)
    }

    /// Resolve a directory entry by name within a parent directory.
    ///
    /// This is the core lookup dispatch: given a parent inode and child name,
    /// it delegates to the VFS engine to resolve namespace → dir-index →
    /// inode-metadata and returns the target inode attributes.
    ///
    /// Returns `ENOENT` when the name does not exist, `ENOTDIR` when
    /// `parent` is not a directory, and `EACCES` on permission denial.
    #[tracing::instrument(skip(self, ctx), fields(ino = %parent, op = "lookup"))]
    pub fn dispatch_lookup(
        &self,
        ctx: &RequestCtx,
        parent: u64,
        name: &[u8],
    ) -> Result<InodeAttr, Errno> {
        let _timer = crate::observability::LatencyTimer::new(&crate::observability::HIST_METADATA);

        // Snapshot catalog lookups must bypass the ordinary positive and
        // negative caches: catalog generation changes make cached synthetic
        // identities stale, and deletion must become ENOENT immediately.
        if parent == SNAPSHOT_NAMESPACE_ROOT_INODE_ID.get() {
            let e = self.engine.lock().unwrap();
            let (inode_id, generation) = e.snapshot_catalog_lookup(name)?;
            let root = e.get_root_inode(ctx)?;
            let template = e.getattr(root, None, ctx)?;
            return Self::project_snapshot_catalog_directory(template, inode_id, generation);
        }

        if name == b".snapshot" {
            let e = self.engine.lock().unwrap();
            if let Some(generation) = e.snapshot_catalog_generation() {
                let template = e.getattr(InodeId::new(parent), None, ctx)?;
                return Self::project_snapshot_catalog_directory(
                    template,
                    SNAPSHOT_NAMESPACE_ROOT_INODE_ID,
                    generation,
                );
            }
        }

        // Check daemon-side negative cache before hitting the engine.
        let now_ns = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .map(|d| d.as_nanos() as u64)
            .unwrap_or(0);
        if self
            .negative_cache
            .lock()
            .unwrap()
            .check(parent, name, now_ns)
        {
            return Err(Errno::ENOENT);
        }

        // Check positive path lookup cache before hitting the engine.
        let cache_hit = {
            let mut cache = self.path_lookup_cache.lock().unwrap();
            cache
                .get(parent, name)
                .map(|entry| (entry.ino, entry.value))
        };
        if let Some((ino, attr)) = cache_hit {
            self.record_lookup_count(ino);
            return Ok(attr);
        }

        // Route through namespace when available; fall through
        // to the engine when the lookup misses (fresh pool with empty
        // namespace but authoritative engine data).
        if let Some(ref ns) = self.namespace {
            match self.dispatch_lookup_via_namespace(ctx, ns, parent, name) {
                Ok(attr) => {
                    return Ok(attr);
                }
                Err(Errno::ENOENT) | Err(Errno::EIO) | Err(Errno::ESTALE) => {} // fall through
                Err(e) => return Err(e),
            }
        }

        let result = {
            let e = self.engine.lock().unwrap();
            e.lookup(InodeId::new(parent), name, ctx)
        };

        // Track per-inode lookup frequency metric for reclaim.
        if let Ok(ref attr) = result {
            let ino = attr.inode_id.get();
            self.record_lookup_count(ino);
            self.cache_path_lookup(parent, name, attr);
        }

        // Cache negative results for the configured TTL.
        if let Err(Errno::ENOENT) = &result {
            self.negative_cache
                .lock()
                .unwrap()
                .insert(parent, name, now_ns);
        }

        result
    }

    #[tracing::instrument(skip(self, ctx), fields(ino = %ino, op = "getattr"))]
    pub fn dispatch_getattr(
        &self,
        ctx: &RequestCtx,
        ino: u64,
        unique: u64,
        fh: Option<u64>,
    ) -> Result<FuseAttrOut, Errno> {
        let _timer = crate::observability::LatencyTimer::new(&crate::observability::HIST_METADATA);

        if let Some(attr_out) = self.removed_lookup_attr_out(ino) {
            return Ok(attr_out);
        }

        // Check the short-lived getattr cache before acquiring engine lock.
        {
            let cache = self.getattr_cache.lock().unwrap();
            if let Some((attr_out, expiry)) = cache.get(&ino) {
                if *expiry > std::time::Instant::now() {
                    return Ok(*attr_out);
                }
            }
        }

        let engine_fh = fh
            .map(|fh| self.resolve_file_handle(ino, fh, 0))
            .and_then(|x| x.ok());
        let engine_attr = {
            let e = self.engine.lock().unwrap();
            e.getattr(InodeId::new(ino), engine_fh.as_ref(), ctx)
        };
        let inode_attr = match engine_attr {
            Ok(attr) => attr,
            Err(Errno::ENOENT | Errno::ESTALE | Errno::EIO) => {
                if let Some(attr_out) = self.removed_lookup_attr_out(ino) {
                    return Ok(attr_out);
                }
                if let Some(ref ns) = self.namespace {
                    return self.dispatch_getattr_via_namespace(ns, ino);
                }
                let _ = unique;
                return Err(Errno::ESTALE);
            }
            Err(errno) => return Err(errno),
        };

        // Populate cache with TTL from the coherency profile.
        let cache_ttl = self.dentry_policy.positive_attr_ttl;
        let attr_out = fuse_attr_out_with_ttl(
            crate::workers_meta::fuse_attr_out(ino, &inode_attr.posix, inode_attr.kind),
            cache_ttl,
        );
        {
            let mut cache = self.getattr_cache.lock().unwrap();
            cache.insert(ino, (attr_out, std::time::Instant::now() + cache_ttl));
        }
        Ok(attr_out)
    }

    #[tracing::instrument(skip(self, ctx, attr), fields(ino = %ino, op = "setattr"))]
    pub fn dispatch_setattr(
        &self,
        ctx: &RequestCtx,
        unique: u64,
        ino: u64,
        attr: &SetAttr,
        fh: Option<u64>,
    ) -> Result<FuseAttrOut, Errno> {
        let _timer = crate::observability::LatencyTimer::new(&crate::observability::HIST_METADATA);
        let mutation_requested = attr.valid
            & (FATTR_SIZE
                | FATTR_MODE
                | FATTR_UID
                | FATTR_GID
                | FATTR_ATIME
                | FATTR_MTIME
                | FATTR_CTIME
                | FATTR_ATIME_NOW
                | FATTR_MTIME_NOW)
            != 0;
        if mutation_requested {
            self.check_not_read_only()?;
        }
        let engine_fh = fh
            .map(|fh| self.resolve_file_handle(ino, fh, 0))
            .and_then(|x| x.ok());
        let inode_id = InodeId::new(ino);
        let e = self.engine.lock().unwrap();
        let current_attr = match e.getattr(inode_id, engine_fh.as_ref(), ctx) {
            Ok(attr) => attr,
            Err(Errno::ENOENT | Errno::ESTALE | Errno::EIO)
                if self.writeback_cache_enabled
                    && fh.is_none()
                    && is_timestamp_only_setattr(attr)
                    && (self.orphan_index.lock().unwrap().contains(ino)
                        || self.is_writeback_seen_inode(ino)) =>
            {
                return Ok(orphan_timestamp_attr_out(ino, attr, ctx));
            }
            Err(Errno::ENOENT | Errno::EIO) if self.namespace.is_some() => {
                drop(e);
                let ns = self.namespace.as_ref().expect("namespace checked");
                return self.dispatch_setattr_via_namespace(
                    ns,
                    ino,
                    attr,
                    ctx.uid,
                    ctx.gid,
                    ctx.groups.as_slice(),
                );
            }
            Err(Errno::ENOENT | Errno::ESTALE | Errno::EIO) => return Err(Errno::ESTALE),
            Err(errno) => return Err(errno),
        };

        if mutation_requested {
            enforce_immutable_guard(current_attr.flags.to_raw_flags())?;
        }
        if crate::workers_meta::can_setattr(
            ctx.uid,
            ctx.gid,
            ctx.groups.as_slice(),
            current_attr.posix.uid,
            current_attr.posix.gid,
            attr.valid,
            attr,
        )
        .is_err()
        {
            return Err(Errno::EPERM);
        }
        // Capacity admission and tracking for size changes are handled by the
        // engine's CapacityAuthority during truncate_extents dispatch.
        let mut data_invalidation_range = None;

        // Perform extent mutation for size changes (shrink via punch-hole,
        // grow via zero-fill allocate). The engine lock is already held so
        // we call truncate_extents directly instead of going through
        // dispatch_ftruncate_file / dispatch_truncate (which would deadlock).
        if attr.valid & FATTR_SIZE != 0 {
            if current_attr.kind == NodeKind::Dir {
                return Err(Errno::EISDIR);
            }
            if attr.size < current_attr.posix.size {
                enforce_append_only_write_guard(current_attr.flags.to_raw_flags(), false)?;
            }
            if let Some(ref efh) = engine_fh {
                // File-handle-based truncate (ftruncate).
                // Reject read-only file handles: truncate is a write operation per POSIX.
                match open_flags_allow_write(efh.open_flags) {
                    Ok(true) => {}
                    Ok(false) | Err(_) => return Err(Errno::EBADF),
                }
                let old_sz = current_attr.posix.size;
                let new_sz = attr.size;
                Self::truncate_extents(&**e, inode_id, efh, old_sz, new_sz, ctx)?;
                if new_sz < old_sz {
                    self.clear_dirty_for_deallocate_range(ino, new_sz, old_sz - new_sz)?;
                    data_invalidation_range = Some((new_sz, old_sz - new_sz));
                } else if new_sz > old_sz {
                    data_invalidation_range = Some((old_sz, new_sz - old_sz));
                }
            } else {
                // Path-based truncate (no open file handle): open, truncate, release.
                let efh = e.open(inode_id, libc::O_RDWR as u32, ctx)?;
                let current_size = e.getattr(inode_id, Some(&efh), ctx)?.posix.size;
                let new_sz = attr.size;
                let result =
                    Self::truncate_extents(&**e, inode_id, &efh, current_size, new_sz, ctx);
                if result.is_ok() && new_sz < current_size {
                    self.clear_dirty_for_deallocate_range(ino, new_sz, current_size - new_sz)?;
                    data_invalidation_range = Some((new_sz, current_size - new_sz));
                } else if result.is_ok() && new_sz > current_size {
                    data_invalidation_range = Some((current_size, new_sz - current_size));
                }
                let _ = e.release(&efh);
                result?;
            }
        }
        let effective_attr = apply_setattr_privilege_mode_rules(attr, &current_attr, ctx);

        let updated = match e.setattr(inode_id, &effective_attr, engine_fh.as_ref(), ctx) {
            Ok(updated) => updated,
            Err(Errno::EIO) => {
                // Best-effort timestamp updates: tar(1) commonly issues fd-based
                // utimensat(2) after writing file contents. If the underlying
                // engine reports EIO for a pure timestamp mutation, prefer a
                // non-fatal behaviour so extraction can complete and data
                // remains readable. This is a stopgap until the storage commit
                // path is hardened for metadata-only updates.
                let time_bits: u32 = FATTR_ATIME
                    | FATTR_MTIME
                    | FATTR_CTIME
                    | FATTR_ATIME_NOW
                    | FATTR_MTIME_NOW
                    | FATTR_FH
                    | FATTR_LOCKOWNER;
                if (effective_attr.valid & !time_bits) == 0 {
                    e.getattr(inode_id, engine_fh.as_ref(), ctx)?
                } else {
                    return Err(Errno::EIO);
                }
            }
            Err(other) => return Err(other),
        };
        // Capacity tracking for all size changes is handled by the engine's
        // CapacityAuthority during truncate dispatch (check_enospc for growth,
        // record_free for shrinkage).
        self.sync_namespace_attrs_local(ino, &updated);
        drop(e);
        if let Some((offset, length)) = data_invalidation_range {
            self.invalidate_caches_after_engine_data_mutation(ino, offset, length);
        } else {
            self.invalidate_inode_metadata_local(ino);
        }

        Ok(crate::workers_meta::fuse_attr_out(
            ino,
            &updated.posix,
            updated.kind,
        ))
    }

    fn dispatch_fuse_setattr(
        &self,
        ctx: &RequestCtx,
        unique: u64,
        ino: u64,
        attr: &SetAttr,
        fh: Option<u64>,
    ) -> Result<FuseAttrOut, Errno> {
        if is_fuse_read_atime_setattr(attr, fh) {
            return self.dispatch_fuse_read_atime_setattr(ctx, unique, ino, attr);
        }
        self.dispatch_setattr(ctx, unique, ino, attr, fh)
    }

    fn dispatch_fuse_read_atime_setattr(
        &self,
        ctx: &RequestCtx,
        unique: u64,
        ino: u64,
        attr: &SetAttr,
    ) -> Result<FuseAttrOut, Errno> {
        if self.read_only || self.timestamp_policy == TimestampPolicy::NoAtime {
            return self.dispatch_getattr(ctx, ino, unique, None);
        }

        let updated = match self.record_fuse_read_atime_and_sync(ino, ctx, attr) {
            Ok(attr) => attr,
            Err(Errno::ENOENT | Errno::ESTALE) if self.namespace.is_some() => {
                return self.dispatch_getattr(ctx, ino, unique, None);
            }
            Err(Errno::ENOENT) => return Err(Errno::ESTALE),
            Err(errno) => return Err(errno),
        };
        self.invalidate_atime_caches_after_read(ino);

        Ok(crate::workers_meta::fuse_attr_out(
            ino,
            &updated.posix,
            updated.kind,
        ))
    }

    fn record_fuse_read_atime_and_sync(
        &self,
        ino: u64,
        ctx: &RequestCtx,
        attr: &SetAttr,
    ) -> Result<InodeAttr, Errno> {
        if attr.valid & FATTR_CTIME == 0 {
            return self.record_read_access_and_sync(ino, ctx);
        }

        let inode_id = InodeId::new(ino);
        let mut update = SetAttr::new();
        if attr.valid & FATTR_ATIME != 0 {
            update.valid |= FATTR_ATIME;
            update.atime_ns = attr.atime_ns;
        } else {
            update.valid |= FATTR_ATIME_NOW;
        }
        update.valid |= FATTR_CTIME;
        update.ctime_ns = attr.ctime_ns;

        let updated = {
            let e = self.engine.lock().unwrap();
            e.setattr(inode_id, &update, None, ctx)?
        };
        self.sync_namespace_attrs_local(ino, &updated);
        Ok(updated)
    }

    /// P5-02 classification for an incoming FUSE create request.
    #[must_use]
    fn classify_fuse_create(
        unique: u64,
        parent: u64,
        uid: u32,
        gid: u32,
        pid: u32,
    ) -> tidefs_types_posix_filesystem_adapter_core::PosixFilesystemAdapterRequestContextMirrorRecord
    {
        use tidefs_types_posix_filesystem_adapter_core::{
            PosixFilesystemAdapterRequestClass, PosixFilesystemAdapterShardKeyPolicy,
        };
        // FUSE_CREATE (opcode 35) -> NamespaceMut, ParentDir
        classify_request_context(
            unique,
            parent,
            uid,
            gid,
            pid,
            35, // opcode::FUSE_CREATE
            PosixFilesystemAdapterRequestClass::NamespaceMut,
            PosixFilesystemAdapterShardKeyPolicy::ParentDir,
            parent,
        )
    }

