    fn fsync(&mut self, req: &Request<'_>, ino: u64, fh: u64, datasync: bool, reply: ReplyEmpty) {
        if let Err(errno) = self.admit_fuse_request(FuseAdmissionOp::Fsync) {
            reply.reply_errno(errno);
            return;
        }
        let _p5_02 =
            Self::classify_fuse_fsync(req.unique(), ino, fh, req.uid(), req.gid(), req.pid());
        self.workload_observer.observe_fsync();
        if let Some(stats) = self.workload_observer.maybe_materialize() {
            tracing::info!(
                signature = stats.current_signature.name(),
                confidence = stats.confidence,
                window_ops = stats.window_ops,
                reads = stats.reads,
                writes = stats.writes,
                fsyncs = stats.fsyncs,
                read_bytes = stats.read_bytes,
                write_bytes = stats.write_bytes,
                "workload materialized"
            );
            self.signature_cache.refresh(stats);
        }
        let _start = std::time::Instant::now();
        let ctx = Self::ctx_from_req(req);
        let (op, hist): (&'static str, &crate::observability::LatencyHistogram) = if datasync {
            ("fdatasync", &crate::observability::HIST_FDATASYNC)
        } else {
            ("fsync", &crate::observability::HIST_FSYNC)
        };
        match if datasync {
            self.dispatch_fdatasync(&ctx, ino, fh)
        } else {
            self.dispatch_fsync(&ctx, ino, fh)
        } {
            Ok(()) => {
                hist.record(_start.elapsed());
                reply.ok();
            }
            Err(errno) => {
                hist.record(_start.elapsed());
                crate::observability::FuseErrorCode::from_errno(errno, op, ino).emit();
                reply.reply_errno(errno)
            }
        }
    }

