    fn readdir(
        &mut self,
        req: &Request<'_>,
        ino: u64,
        fh: u64,
        offset: i64,
        mut reply: ReplyDirectory,
    ) {
        if offset < 0 {
            reply.reply_errno(Errno::EINVAL);
            return;
        }
        if let Err(errno) = self.admit_fuse_request(FuseAdmissionOp::Readdir) {
            reply.reply_errno(errno);
            return;
        }
        let ctx = Self::ctx_from_req(req);
        // P5-02 classification (issue #3163): classify the incoming readdir
        // request for the multi-pool dispatch seam.  The classified context
        // is available for observability through the request-context mirror.
        let _p5_02 = Self::classify_fuse_readdir(
            req.unique(),
            ino,
            req.uid(),
            req.gid(),
            req.pid(),
            offset as u64,
            0, // size_hint not exposed by fuser::Request; P5-02 uses 0
        );
        let requested_offset: u64 = {
            let e = self.engine.lock().unwrap();
            match self.resolve_dir_handle(ino, fh, &ctx, &**e) {
                Ok(handle) => handle.requested_offset(offset as u64),
                Err(engine_errno) => {
                    drop(e);
                    if let Some(ref ns) = self.namespace {
                        let attrs = ns.get_attrs(ino);
                        if attrs.is_some_and(|attrs| (attrs.mode & 0o170000) == 0o040000) {
                            offset as u64
                        } else {
                            reply.reply_errno(engine_errno);
                            return;
                        }
                    } else {
                        reply.reply_errno(engine_errno);
                        return;
                    }
                }
            }
        };
        match self.dispatch_readdir(&ctx, ino, fh, requested_offset) {
            Ok((entries, _more)) => {
                let mut last_emitted_cookie = None;
                for (i, entry) in entries.iter().enumerate() {
                    let kind = file_type_for_node_kind(entry.kind);
                    let cookie = match fuse_dir_offset(entry.cookie, requested_offset, i) {
                        Ok(cookie) => cookie,
                        Err(errno) => {
                            reply.reply_errno(errno);
                            return;
                        }
                    };
                    if reply.add(
                        entry.inode_id.get(),
                        cookie,
                        kind,
                        OsStr::from_bytes(&entry.name),
                    ) {
                        break;
                    }
                    last_emitted_cookie = Some(cookie as u64);
                }
                self.finish_dir_page(fh, requested_offset, last_emitted_cookie);
                reply.ok();
            }
            Err(errno) => reply.reply_errno(errno),
        }
    }

