    /// Linux 6.13+ and macOS: atomically exchange the contents of two files.
    ///
    /// Resolves both (parent, name) pairs, verifies both are regular files,
    /// then swaps their data using in-memory buffers.  Inode numbers,
    /// permissions, and extended attributes are preserved.
    fn exchange(
        &mut self,
        req: &Request<'_>,
        parent: u64,
        name: &OsStr,
        newparent: u64,
        newname: &OsStr,
        options: u64,
        reply: ReplyEmpty,
    ) {
        if let Err(errno) = self.admit_fuse_request(FuseAdmissionOp::Exchange) {
            reply.reply_errno(errno);
            return;
        }
        let _ = options;
        let ctx = Self::ctx_from_req(req);
        let result = self.dispatch_exchange_entry(
            &ctx,
            parent,
            name.as_bytes(),
            newparent,
            newname.as_bytes(),
        );
        let _ = result.is_ok();
        reply_empty_ok_or_errno(reply, result);
    }
