    #[test]
    fn classify_fuse_read_returns_file_read_context() {
        use tidefs_types_posix_filesystem_adapter_core::{
            PosixFilesystemAdapterRequestClass, PosixFilesystemAdapterShardKeyPolicy,
        };
        let ctx = FuseVfsAdapter::classify_fuse_read(501, 42, 1000, 1000, 1234);

        assert_eq!(ctx.unique, 501);
        assert_eq!(ctx.nodeid, 42);
        assert_eq!(ctx.uid, 1000);
        assert_eq!(ctx.gid, 1000);
        assert_eq!(ctx.pid, 1234);
        assert_eq!(
            ctx.request_class,
            PosixFilesystemAdapterRequestClass::FileRead.as_u32()
        );
        assert_eq!(
            ctx.shard_key_policy,
            PosixFilesystemAdapterShardKeyPolicy::ObjectRead.as_u32()
        );
    }

    #[test]
    fn classify_fuse_read_preserves_caller_identity() {
        let ctx = FuseVfsAdapter::classify_fuse_read(777, 99, 500, 501, 42);

        assert_eq!(ctx.uid, 500);
        assert_eq!(ctx.gid, 501);
        assert_eq!(ctx.pid, 42);
    }

    #[test]
    fn classify_fuse_read_root_inode_ok() {
        use tidefs_types_posix_filesystem_adapter_core::PosixFilesystemAdapterRequestClass;
        let ctx = FuseVfsAdapter::classify_fuse_read(1, 1, 0, 0, 1);

        assert_eq!(ctx.nodeid, 1);
        assert_eq!(ctx.unique, 1);
        // Root inode read is still FileRead, not MetaRead
        assert_eq!(
            ctx.request_class,
            PosixFilesystemAdapterRequestClass::FileRead.as_u32()
        );
    }

    #[test]
    fn classify_fuse_read_large_inode_and_unique_ok() {
        use tidefs_types_posix_filesystem_adapter_core::PosixFilesystemAdapterRequestClass;
        let ctx = FuseVfsAdapter::classify_fuse_read(u64::MAX, u64::MAX, 0, 0, 0);

        assert_eq!(ctx.unique, u64::MAX);
        assert_eq!(ctx.nodeid, u64::MAX);
        assert_eq!(
            ctx.request_class,
            PosixFilesystemAdapterRequestClass::FileRead.as_u32()
        );
    }

