    #[test]
    fn write_leaves_relatime_atime_for_first_read() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let payload = b"xfstests generic 003 atime";
        let (inode, adapter_fh, _engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"relatime-write-read-atime.txt",
            libc::O_RDWR as u32,
        );

        let mut stale_atime = SetAttr::new();
        stale_atime.valid = FATTR_ATIME;
        stale_atime.atime_ns = 1;
        fixture
            .adapter
            .dispatch_setattr(&ctx, 1, inode.get(), &stale_atime, None)
            .expect("force old atime");

        let before_write = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(inode, None, &ctx)
                .expect("getattr before write")
        };
        assert_eq!(before_write.posix.atime_ns, 1);

        std::thread::sleep(Duration::from_millis(1));
        let written = fixture
            .adapter
            .dispatch_write(&ctx, inode.get(), adapter_fh, 0, payload, 0)
            .expect("write payload");
        assert_eq!(written, payload.len() as u32);

        let after_write = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(inode, None, &ctx)
                .expect("getattr after write")
        };
        assert_eq!(
            after_write.posix.atime_ns, before_write.posix.atime_ns,
            "writes must not advance atime"
        );
        assert!(
            after_write.posix.mtime_ns >= before_write.posix.mtime_ns,
            "writes must update mtime"
        );
        assert!(
            after_write.posix.ctime_ns >= before_write.posix.ctime_ns,
            "writes must update ctime"
        );

        std::thread::sleep(Duration::from_millis(1));
        let data = fixture
            .adapter
            .dispatch_read(&ctx, inode.get(), adapter_fh, 0, payload.len() as u32, None)
            .expect("read payload");
        assert_eq!(data, payload);

        let after_read = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(inode, None, &ctx)
                .expect("getattr after read")
        };
        assert!(
            after_read.posix.atime_ns > after_write.posix.atime_ns,
            "the first read after a write must advance relatime atime"
        );
        assert_eq!(
            after_read.posix.ctime_ns, after_write.posix.ctime_ns,
            "automatic read atime updates must not advance ctime"
        );
    }

    #[test]
    fn read_open_after_write_advances_relatime_atime_without_ctime() {
        let mut fixture = adapter_fixture_with_writeback_cache();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };
        let created = fixture
            .adapter
            .dispatch_create_entry(
                &ctx,
                root.get(),
                b"xfstests-generic-003-open-atime.txt",
                0o644,
                libc::O_WRONLY as u32,
            )
            .expect("create write-only handle");

        let mut stale_atime = SetAttr::new();
        stale_atime.valid = FATTR_ATIME;
        stale_atime.atime_ns = 1;
        fixture
            .adapter
            .dispatch_setattr(&ctx, 1, created.attr.inode_id.get(), &stale_atime, None)
            .expect("force old atime before write");

        let before_write = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(created.attr.inode_id, None, &ctx)
                .expect("getattr before write")
        };
        assert_eq!(before_write.posix.atime_ns, 1);

        std::thread::sleep(Duration::from_millis(1));
        fixture
            .adapter
            .dispatch_write(
                &ctx,
                created.attr.inode_id.get(),
                created.adapter_fh,
                0,
                b"aaa\n",
                0,
            )
            .expect("write payload");
        let after_write = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(created.attr.inode_id, None, &ctx)
                .expect("getattr after write")
        };
        assert_eq!(
            after_write.posix.atime_ns, before_write.posix.atime_ns,
            "write-only updates must leave atime for the later read"
        );
        assert!(
            after_write.posix.mtime_ns >= before_write.posix.mtime_ns,
            "write-only updates must advance mtime"
        );
        assert!(
            after_write.posix.ctime_ns >= before_write.posix.ctime_ns,
            "write-only updates must advance ctime"
        );

        fixture
            .adapter
            .dispatch_release(
                created.attr.inode_id.get(),
                created.adapter_fh,
                0,
                None,
                true,
            )
            .expect("release writer");

        std::thread::sleep(Duration::from_millis(1));
        let read_open = fixture
            .adapter
            .dispatch_open(&ctx, created.attr.inode_id.get(), libc::O_RDONLY as u32)
            .expect("open read-only handle");
        assert_eq!(
            read_open.open_flags & fuser::consts::FOPEN_DIRECT_IO,
            0,
            "active-atime read opens after the writer closes must keep buffered reads enabled"
        );
        assert_eq!(
            read_open.open_flags & fuser::consts::FOPEN_KEEP_CACHE,
            0,
            "active-atime read opens after the writer closes must not preserve stale kernel pages"
        );

        let after_read_open = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(created.attr.inode_id, None, &ctx)
                .expect("getattr after read open")
        };
        assert!(
            after_read_open.posix.atime_ns > after_write.posix.atime_ns,
            "the first read-only open after a write must advance relatime atime"
        );
        assert_eq!(
            after_read_open.posix.ctime_ns, after_write.posix.ctime_ns,
            "read-open atime updates must not advance ctime"
        );

        fixture
            .adapter
            .dispatch_release(
                created.attr.inode_id.get(),
                read_open.adapter_fh,
                0,
                None,
                false,
            )
            .expect("release reader");
    }

    #[test]
    fn pending_write_forces_relatime_read_open_atime_without_ctime() {
        let mut fixture = adapter_fixture_with_writeback_cache();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };
        let created = fixture
            .adapter
            .dispatch_create_entry(
                &ctx,
                root.get(),
                b"xfstests-generic-003-pending-atime.txt",
                0o644,
                libc::O_WRONLY as u32,
            )
            .expect("create write-only handle");

        fixture
            .adapter
            .dispatch_write(
                &ctx,
                created.attr.inode_id.get(),
                created.adapter_fh,
                0,
                b"aaa\n",
                0,
            )
            .expect("write payload");
        fixture
            .adapter
            .dispatch_release(
                created.attr.inode_id.get(),
                created.adapter_fh,
                0,
                None,
                true,
            )
            .expect("release writer");

        let after_write = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(created.attr.inode_id, None, &ctx)
                .expect("getattr after write")
        };
        let synthetic_recent_atime = after_write.posix.ctime_ns.saturating_add(1);
        let mut recent_atime = SetAttr::new();
        recent_atime.valid = FATTR_ATIME | FATTR_CTIME;
        recent_atime.atime_ns = synthetic_recent_atime;
        recent_atime.ctime_ns = after_write.posix.ctime_ns;
        fixture
            .adapter
            .dispatch_setattr(&ctx, 1, created.attr.inode_id.get(), &recent_atime, None)
            .expect("seed atime newer than write timestamps");

        let before_read = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(created.attr.inode_id, None, &ctx)
                .expect("getattr before read")
        };
        assert!(
            before_read.posix.atime_ns > before_read.posix.mtime_ns
                && before_read.posix.atime_ns > before_read.posix.ctime_ns,
            "test setup must make ordinary relatime suppress the read update"
        );

        std::thread::sleep(Duration::from_millis(1));
        let read_open = fixture
            .adapter
            .dispatch_open(&ctx, created.attr.inode_id.get(), libc::O_RDONLY as u32)
            .expect("open read-only handle");
        let after_forced_read = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(created.attr.inode_id, None, &ctx)
                .expect("getattr after forced read atime")
        };
        assert!(
            after_forced_read.posix.atime_ns > before_read.posix.atime_ns,
            "pending write must make the first later read own the relatime atime update"
        );
        assert_eq!(
            after_forced_read.posix.ctime_ns, before_read.posix.ctime_ns,
            "forced read-atime update must preserve ctime"
        );
        fixture
            .adapter
            .dispatch_release(
                created.attr.inode_id.get(),
                read_open.adapter_fh,
                0,
                None,
                false,
            )
            .expect("release reader");

        std::thread::sleep(Duration::from_millis(1));
        let second_read_open = fixture
            .adapter
            .dispatch_open(&ctx, created.attr.inode_id.get(), libc::O_RDONLY as u32)
            .expect("open read-only handle again");
        let after_second_read_open = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(created.attr.inode_id, None, &ctx)
                .expect("getattr after second read open")
        };
        assert_eq!(
            after_second_read_open.posix.atime_ns, after_forced_read.posix.atime_ns,
            "the pending marker must be consumed by the first read"
        );
        fixture
            .adapter
            .dispatch_release(
                created.attr.inode_id.get(),
                second_read_open.adapter_fh,
                0,
                None,
                false,
            )
            .expect("release second reader");
    }

    #[test]
    fn cached_read_syncs_namespace_atime_without_ctime() {
        let mut fixture = adapter_fixture_with_namespace();
        fixture.adapter.timestamp_policy = TimestampPolicy::StrictAtime;
        let ctx = root_ctx();
        let payload = b"namespace cached read atime";
        let name = b"namespace-cache-atime.txt";
        let (inode, adapter_fh, engine_fh) =
            create_adapter_file_handle(&fixture.adapter, &ctx, name, libc::O_RDWR as u32);
        let ns = fixture
            .adapter
            .namespace
            .as_ref()
            .expect("attached namespace");
        let ns_ino = ns
            .create_file(
                1,
                std::str::from_utf8(name).expect("test name is utf8"),
                tidefs_namespace::InodeAttributes::new_file(0),
            )
            .expect("seed namespace mirror");
        assert_eq!(ns_ino, inode.get());

        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .write(&engine_fh, 0, payload, &ctx)
                .expect("write payload");
        }

        let first = fixture
            .adapter
            .dispatch_read(&ctx, inode.get(), adapter_fh, 0, payload.len() as u32, None)
            .expect("first read fills cache");
        assert_eq!(first, payload);

        let mut stale_atime = SetAttr::new();
        stale_atime.valid = FATTR_ATIME;
        stale_atime.atime_ns = 1;
        fixture
            .adapter
            .dispatch_setattr(&ctx, 1, inode.get(), &stale_atime, None)
            .expect("force old atime");
        let before = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(inode, None, &ctx)
                .expect("getattr before cached read")
        };
        let ns_before = ns.get_attrs(inode.get()).expect("namespace attrs before");
        assert_eq!(before.posix.atime_ns, 1);
        assert_eq!(system_time_to_ns(ns_before.atime), 1);

        std::thread::sleep(Duration::from_millis(1));
        let second = fixture
            .adapter
            .dispatch_read(&ctx, inode.get(), adapter_fh, 0, payload.len() as u32, None)
            .expect("second read served from cache");
        assert_eq!(second, payload);

        let after = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(inode, None, &ctx)
                .expect("getattr after cached read")
        };
        let ns_after = ns.get_attrs(inode.get()).expect("namespace attrs after");
        assert!(
            after.posix.atime_ns > before.posix.atime_ns,
            "cached reads must advance engine atime"
        );
        assert_eq!(
            after.posix.ctime_ns, before.posix.ctime_ns,
            "cached read atime must not advance engine ctime"
        );
        assert_eq!(
            system_time_to_ns(ns_after.atime),
            after.posix.atime_ns,
            "cached reads must sync namespace atime from the engine"
        );
        assert_eq!(
            system_time_to_ns(ns_after.ctime),
            after.posix.ctime_ns,
            "cached read namespace ctime must stay aligned with engine ctime"
        );
    }

