    #[test]
    fn vfs_adapter_dispatch_link_creates_hard_link() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (root, source_inode) = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            let (source, _fh) = engine
                .create(root, b"source.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create source");
            (root, source.inode_id)
        };

        let linked = fixture
            .adapter
            .dispatch_link_entry(&ctx, source_inode.get(), root.get(), b"linked.txt")
            .expect("link dispatch");

        assert_eq!(linked.inode_id, source_inode);
        let engine = fixture.adapter.engine.lock().unwrap();
        assert_eq!(
            engine
                .lookup(root, b"source.txt", &ctx)
                .expect("source lookup")
                .inode_id,
            source_inode
        );
        let linked_lookup = engine
            .lookup(root, b"linked.txt", &ctx)
            .expect("linked lookup");
        assert_eq!(linked_lookup.inode_id, source_inode);
        assert_eq!(linked_lookup.posix.nlink, 2);
        assert_eq!(
            fixture
                .adapter
                .dentry_invalidations
                .lock()
                .unwrap()
                .entry_generation(root.get(), b"linked.txt"),
            Some(1)
        );
    }

