    #[test]
    fn vfs_adapter_dispatch_unlink_removes_file() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (root, target_inode, sibling_inode) = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            let (target, _target_fh) = engine
                .create(root, b"target.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create target");
            let (sibling, _sibling_fh) = engine
                .create(root, b"sibling.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create sibling");
            (root, target.inode_id, sibling.inode_id)
        };

        fixture
            .adapter
            .dispatch_unlink_entry(&ctx, root.get(), b"target.txt")
            .expect("unlink dispatch");

        {
            let engine = fixture.adapter.engine.lock().unwrap();
            assert_eq!(
                engine
                    .lookup(root, b"target.txt", &ctx)
                    .expect_err("target removed"),
                Errno::ENOENT
            );
            assert_eq!(
                engine
                    .lookup(root, b"sibling.txt", &ctx)
                    .expect("sibling lookup")
                    .inode_id,
                sibling_inode
            );
            assert_ne!(target_inode, sibling_inode);
        }
        let names = root_dir_entry_names(&fixture.adapter, &ctx, root);
        assert!(!names.iter().any(|name| name.as_slice() == b"target.txt"));
        assert!(names.iter().any(|name| name.as_slice() == b"sibling.txt"));
        assert_eq!(
            fixture
                .adapter
                .dentry_invalidations
                .lock()
                .unwrap()
                .entry_generation(root.get(), b"target.txt"),
            Some(1)
        );
    }

    #[test]
    fn vfs_adapter_dispatch_unlink_open_file_release_succeeds() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();

        // Simulate the full FUSE lifecycle: create -> unlink -> flush -> release.
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };

        // 1. Dispatch create (as FUSE create callback does).
        let create_dispatch = fixture
            .adapter
            .dispatch_create_entry(
                &ctx,
                root.get(),
                b"unlink-release.txt",
                0o644,
                libc::O_RDWR as u32,
            )
            .expect("create dispatch");
        let inode = create_dispatch.attr.inode_id;
        let adapter_fh = create_dispatch.adapter_fh;

        // 2. Write some data through the handle.
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            let efh = fixture
                .adapter
                .resolve_file_handle(inode.get(), adapter_fh, 0)
                .expect("resolve for write");
            engine
                .write(&efh, 0, b"payload", &ctx)
                .expect("write payload");
        }

        // 3. Unlink the entry while the handle is still open.
        fixture
            .adapter
            .dispatch_unlink_entry(&ctx, root.get(), b"unlink-release.txt")
            .expect("unlink while open");

        // Verify the name is gone.
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            assert_eq!(
                engine
                    .lookup(root, b"unlink-release.txt", &ctx)
                    .unwrap_err(),
                Errno::ENOENT
            );
        }

        // 4. Flush (as FUSE flush callback does before close).
        assert_eq!(
            fixture
                .adapter
                .dispatch_flush(&ctx, inode.get(), adapter_fh, 0),
            Ok(())
        );

        // 5. Release the still-open handle.
        assert_eq!(
            fixture
                .adapter
                .dispatch_release(inode.get(), adapter_fh, 0, None, false),
            Ok(())
        );

        // Double release must return EBADF.
        assert_eq!(
            fixture
                .adapter
                .dispatch_release(inode.get(), adapter_fh, 0, None, false),
            Err(Errno::EBADF)
        );
    }

    #[test]
    fn unlink_while_open_fences_data_only_on_last_close() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };
        let create = fixture
            .adapter
            .dispatch_create_entry(
                &ctx,
                root.get(),
                b"unlink-open-cache.bin",
                0o644,
                libc::O_RDWR as u32,
            )
            .expect("create open file");
        let ino = create.attr.inode_id.get();
        let open_snapshot = fixture.adapter.data_cache_generation_snapshot(ino, 0, 4096);
        let dentry_generation_before_unlink = fixture
            .adapter
            .dentry_invalidations
            .lock()
            .unwrap()
            .entry_generation(root.get(), b"unlink-open-cache.bin")
            .unwrap_or(0);

        fixture
            .adapter
            .dispatch_unlink_entry(&ctx, root.get(), b"unlink-open-cache.bin")
            .expect("unlink while open");

        let dentry_generation_after_unlink = fixture
            .adapter
            .dentry_invalidations
            .lock()
            .unwrap()
            .entry_generation(root.get(), b"unlink-open-cache.bin")
            .unwrap_or(0);
        assert!(
            dentry_generation_after_unlink > dentry_generation_before_unlink,
            "unlink must invalidate the removed dentry"
        );
        assert!(
            fixture
                .adapter
                .data_cache_snapshot_still_current(ino, 0, 4096, open_snapshot),
            "open-unlink keeps data cache valid through the live handle"
        );

        fixture
            .adapter
            .dispatch_release(ino, create.adapter_fh, 0, None, false)
            .expect("release last open handle");

        assert!(
            !fixture
                .adapter
                .data_cache_snapshot_still_current(ino, 0, 4096, open_snapshot),
            "orphan last close must fence the now-unreachable inode data"
        );
    }

