    #[test]
    fn vfs_adapter_dispatch_link_multiple_links_nlink_correct() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (root, source_inode, source_fh) = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            let (source, source_fh) = engine
                .create(root, b"source.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create source");
            (root, source.inode_id, source_fh)
        };

        // Create 3 hard links: alias1, alias2, alias3
        fixture
            .adapter
            .dispatch_link_entry(&ctx, source_inode.get(), root.get(), b"alias1.txt")
            .expect("link alias1");
        fixture
            .adapter
            .dispatch_link_entry(&ctx, source_inode.get(), root.get(), b"alias2.txt")
            .expect("link alias2");
        fixture
            .adapter
            .dispatch_link_entry(&ctx, source_inode.get(), root.get(), b"alias3.txt")
            .expect("link alias3");

        // Release the handle so getattr reflects real nlink from the filesystem
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.release(&source_fh).expect("release source handle");
        }

        let engine = fixture.adapter.engine.lock().unwrap();
        // All names resolve to the same inode
        assert_eq!(
            engine
                .lookup(root, b"source.txt", &ctx)
                .expect("source lookup")
                .inode_id,
            source_inode
        );
        assert_eq!(
            engine
                .lookup(root, b"alias1.txt", &ctx)
                .expect("alias1 lookup")
                .inode_id,
            source_inode
        );
        assert_eq!(
            engine
                .lookup(root, b"alias2.txt", &ctx)
                .expect("alias2 lookup")
                .inode_id,
            source_inode
        );
        assert_eq!(
            engine
                .lookup(root, b"alias3.txt", &ctx)
                .expect("alias3 lookup")
                .inode_id,
            source_inode
        );
        // nlink should be 4 (original + 3 links)
        let attr = engine
            .getattr(source_inode, None, &ctx)
            .expect("getattr source");
        assert_eq!(attr.posix.nlink, 4);
    }

