    #[test]
    fn vfs_adapter_dispatch_link_cross_directory_same_inode() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (root, subdir_inode, source_inode) = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            let subdir = engine
                .mkdir(root, b"subdir", 0o755, &ctx)
                .expect("create subdirectory");
            let (source, _fh) = engine
                .create(root, b"source.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create source");
            (root, subdir.inode_id, source.inode_id)
        };

        let linked = fixture
            .adapter
            .dispatch_link_entry(&ctx, source_inode.get(), subdir_inode.get(), b"alias.txt")
            .expect("cross-directory link dispatch");

        assert_eq!(linked.inode_id, source_inode);
        let engine = fixture.adapter.engine.lock().unwrap();
        /* Linked name resolves in subdir */
        let subdir_lookup = engine
            .lookup(subdir_inode, b"alias.txt", &ctx)
            .expect("alias lookup in subdir");
        assert_eq!(subdir_lookup.inode_id, source_inode);
        /* Source still resolves in root */
        let root_lookup = engine
            .lookup(root, b"source.txt", &ctx)
            .expect("source lookup in root");
        assert_eq!(root_lookup.inode_id, source_inode);
        /* nlink should be 2 (original + 1 link) */
        assert_eq!(root_lookup.posix.nlink, 2);
        /* Alias not visible in root */
        assert_eq!(engine.lookup(root, b"alias.txt", &ctx), Err(Errno::ENOENT));
        /* Source not visible in subdir */
        assert_eq!(
            engine.lookup(subdir_inode, b"source.txt", &ctx),
            Err(Errno::ENOENT)
        );
    }

