    #[test]
    fn vfs_adapter_dispatch_mknod_block_and_char_devices_preserve_kind_and_rdev() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };

        let cases = [
            (
                b"blockdev".as_slice(),
                libc::S_IFBLK | 0o600,
                0x0800,
                NodeKind::BlockDev,
                FileType::BlockDevice,
            ),
            (
                b"chardev".as_slice(),
                libc::S_IFCHR | 0o600,
                0x0103,
                NodeKind::CharDev,
                FileType::CharDevice,
            ),
        ];

        for (name, mode, rdev, expected_kind, expected_file_type) in cases {
            let attr = fixture
                .adapter
                .dispatch_mknod_entry(&ctx, root.get(), name, mode, rdev)
                .expect("mknod special device dispatch");

            assert_eq!(attr.kind, expected_kind);
            assert_eq!(attr.posix.mode & libc::S_IFMT, mode & libc::S_IFMT);
            assert_eq!(attr.posix.rdev, rdev);

            let attr_out = fixture
                .adapter
                .dispatch_getattr(&ctx, attr.inode_id.get(), 11632, None)
                .expect("getattr special device");
            assert_eq!(attr_out.attr.mode & libc::S_IFMT, mode & libc::S_IFMT);
            assert_eq!(attr_out.attr.rdev, rdev);
            assert_eq!(
                file_attr_from_fuse_attr(&attr_out.attr).kind,
                expected_file_type
            );
        }
    }

    #[test]
    fn vfs_adapter_dispatch_mknod_enospc_when_inode_capacity_exhausted() {
        // Build a filesystem with inode_capacity=1 so only the root inode fits.
        let temp_id = NEXT_TEMP_ID.fetch_add(1, Ordering::Relaxed);
        let root_dir = std::env::temp_dir().join(format!(
            "tidefs-vfs-adapter-enospc-{}-{temp_id}",
            std::process::id()
        ));
        std::fs::create_dir_all(&root_dir).expect("create temp root");
        let policy = LocalStorageAllocatorPolicy::new(
            LocalStorageAllocatorPolicy::default().content_capacity_bytes,
            1, /* inode_capacity: root only */
        );
        let local_fs = LocalFileSystem::open_with_allocator_policy_and_root_authentication_key(
            &root_dir,
            LocalFileSystemOpenConfig {
                options: StoreOptions::default(),
                allocator_policy: policy,
                root_authentication_key: RootAuthenticationKey::demo_key(),
                encryption: None,
                compression: None,
                log_device_device_path: None,
                recovery_policy: RecoveryPolicy::default(),
                block_devices: None,
            },
        )
        .expect("open local filesystem with inode_capacity=1");
        let engine = VfsLocalFileSystem::new(local_fs);
        let adapter = FuseVfsAdapter::new(Box::new(engine)).expect("create adapter");
        let ctx = access_ctx(0, 0, &[0]);
        let root_inode = {
            let engine = adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };

        let result = adapter.dispatch_mknod_entry(
            &ctx,
            root_inode.get(),
            b"nospace",
            libc::S_IFREG | 0o644,
            0,
        );
        assert_eq!(result.unwrap_err(), Errno::from_raw(libc::ENOSPC as u16));

        // Cleanup.
        drop(adapter);
        let _ = std::fs::remove_dir_all(&root_dir);
    }

