    #[test]
    fn vfs_adapter_dispatch_symlink_in_subdirectory_is_lookup_visible() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (root, subdir_inode) = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            let subdir = engine
                .mkdir(root, b"subdir", 0o755, &ctx)
                .expect("create subdirectory");
            (root, subdir.inode_id)
        };

        let plan = fixture.adapter.dispatch_symlink_entry(
            &ctx,
            subdir_inode.get(),
            b"nested-link",
            b"../relative-target",
        );

        assert!(plan.is_success());
        let attr = plan.attr.expect("symlink attr");
        assert_eq!(attr.kind, FileType::Symlink);
        assert_eq!(attr.size, 18);

        let engine = fixture.adapter.engine.lock().unwrap();
        let lookup = engine
            .lookup(subdir_inode, b"nested-link", &ctx)
            .expect("symlink lookup in subdirectory");
        assert_eq!(lookup.kind, NodeKind::Symlink);
        assert_eq!(
            engine.readlink(lookup.inode_id, &ctx).expect("readlink"),
            b"../relative-target"
        );

        // Verify the symlink is NOT visible in the root directory.
        assert_eq!(
            engine.lookup(root, b"nested-link", &ctx),
            Err(Errno::ENOENT)
        );
    }

