    #[test]
    fn vfs_adapter_dispatch_rename_exchange_swaps_entries() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (root, left_inode, right_inode) = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            let (left, _left_fh) = engine
                .create(root, b"left.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create left");
            let (right, _right_fh) = engine
                .create(root, b"right.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create right");
            (root, left.inode_id, right.inode_id)
        };

        fixture
            .adapter
            .dispatch_rename_entry(
                &ctx,
                root.get(),
                b"left.txt",
                root.get(),
                b"right.txt",
                RENAME_EXCHANGE,
            )
            .expect("rename exchange dispatch");

        let engine = fixture.adapter.engine.lock().unwrap();
        assert_eq!(
            engine
                .lookup(root, b"left.txt", &ctx)
                .expect("left lookup")
                .inode_id,
            right_inode
        );
        assert_eq!(
            engine
                .lookup(root, b"right.txt", &ctx)
                .expect("right lookup")
                .inode_id,
            left_inode
        );
        let invalidations = fixture.adapter.dentry_invalidations.lock().unwrap();
        assert_eq!(
            invalidations.entry_generation(root.get(), b"left.txt"),
            Some(1)
        );
        assert_eq!(
            invalidations.entry_generation(root.get(), b"right.txt"),
            Some(1)
        );
    }

