    #[test]
    fn vfs_adapter_dispatch_rename_overwrites_existing_target() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (root, source_inode, target_inode) = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            let (src, _fh) = engine
                .create(root, b"source.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create source");
            let (tgt, _fh) = engine
                .create(root, b"target.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create target");
            (root, src.inode_id, tgt.inode_id)
        };
        assert_ne!(source_inode, target_inode);

        fixture
            .adapter
            .dispatch_rename_entry(
                &ctx,
                root.get(),
                b"source.txt",
                root.get(),
                b"target.txt",
                0,
            )
            .expect("overwrite rename dispatch");

        let engine = fixture.adapter.engine.lock().unwrap();
        // Source name is gone
        assert_eq!(
            engine.lookup(root, b"source.txt", &ctx).unwrap_err(),
            Errno::ENOENT
        );
        // Target name now holds source inode (target inode was freed)
        let renamed = engine
            .lookup(root, b"target.txt", &ctx)
            .expect("target name lookup");
        assert_eq!(renamed.inode_id, source_inode);
        // Original target inode is gone
        assert_eq!(
            engine
                .lookup(root, b"target.txt", &ctx)
                .expect("target name still exists")
                .inode_id,
            source_inode
        );
    }

