    #[test]
    fn vfs_adapter_dispatch_flush_skips_engine_when_inode_clean() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, adapter_fh, _) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"flush-skip-clean.txt",
            libc::O_RDWR as u32,
        );

        // Before any writes, dirty_state is empty. Flush must short-circuit.
        {
            let ds = fixture.adapter.dirty_state.lock().unwrap();
            assert!(ds.get(&inode.get()).is_none_or(|dr| dr.is_empty()));
        }

        assert_eq!(
            fixture
                .adapter
                .dispatch_flush(&ctx, inode.get(), adapter_fh, 0),
            Ok(())
        );

        // After a dispatch_write, dirty_state is populated.
        let written = fixture
            .adapter
            .dispatch_write(&ctx, inode.get(), adapter_fh, 0, b"hello-world", 0)
            .expect("write data");
        assert_eq!(written, 11);

        {
            let ds = fixture.adapter.dirty_state.lock().unwrap();
            let dr = ds
                .get(&inode.get())
                .expect("dirty ranges exist after write");
            assert!(!dr.is_empty());
        }

        // Flush on a dirty file calls engine flush (no short-circuit).
        assert_eq!(
            fixture
                .adapter
                .dispatch_flush(&ctx, inode.get(), adapter_fh, 0),
            Ok(())
        );

        // dispatch_flush does NOT clear dirty_state (that is
        // dispatch_fsync_file's responsibility). The dirty ranges
        // persist after flush.
        {
            let ds = fixture.adapter.dirty_state.lock().unwrap();
            assert!(
                ds.get(&inode.get()).is_some_and(|dr| !dr.is_empty()),
                "dirty_state persists after dispatch_flush (fsync clears it)"
            );
        }
        assert_eq!(
            fixture
                .adapter
                .writeback_cache
                .lock()
                .unwrap()
                .is_dirty(inode.get()),
            Some(true),
            "flush must not publish the inode reclaim projection clean while dirty_state remains"
        );

        // Handle must still be resolvable after flush.
        assert!(fixture
            .adapter
            .resolve_file_handle(inode.get(), adapter_fh, 0)
            .is_ok());
    }

    #[test]
    fn vfs_adapter_dispatch_write_flush_fsync_read_round_trip() {
        // Write data through dispatch_write, call dispatch_flush (writeback),
        // call dispatch_fsync (clear dirty state + metadata sync), then
        // read back through dispatch_read and verify content matches.
        // This exercises the full durability chain: write -> flush -> fsync -> read.
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let payload = b"write-flush-fsync round-trip payload";
        let (inode, adapter_fh, _engine_fh) =
            create_adapter_file_handle(&fixture.adapter, &ctx, b"wff-rt.bin", libc::O_RDWR as u32);

        fixture
            .adapter
            .dispatch_write(&ctx, inode.get(), adapter_fh, 0, payload, 0)
            .expect("dispatch_write");

        fixture
            .adapter
            .dispatch_flush(&ctx, inode.get(), adapter_fh, 0)
            .expect("dispatch_flush");

        fixture
            .adapter
            .dispatch_fsync(&ctx, inode.get(), adapter_fh)
            .expect("dispatch_fsync");

        let read_back = fixture
            .adapter
            .dispatch_read(&ctx, inode.get(), adapter_fh, 0, payload.len() as u32, None)
            .expect("dispatch_read");

        assert_eq!(read_back, payload);
    }

    #[test]
    fn vfs_adapter_dispatch_flush_idempotent_repeated_calls() {
        // Write data through dispatch_write (dirtying pages), flush to
        // trigger writeback, then flush again. The second flush must
        // succeed and data must remain readable.
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let payload = b"double-flush idempotent payload";
        let (inode, adapter_fh, _engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"flush-idem.bin",
            libc::O_RDWR as u32,
        );

        fixture
            .adapter
            .dispatch_write(&ctx, inode.get(), adapter_fh, 0, payload, 0)
            .expect("dispatch_write");

        // First flush: triggers writeback of dirty pages.
        fixture
            .adapter
            .dispatch_flush(&ctx, inode.get(), adapter_fh, 0)
            .expect("first dispatch_flush should succeed");

        // Second flush: file is still dirty (flush does not clear dirty_state),
        // but the second call must succeed.
        fixture
            .adapter
            .dispatch_flush(&ctx, inode.get(), adapter_fh, 0)
            .expect("second dispatch_flush should succeed");

        // Data must still be readable through the handle.
        let read_back = fixture
            .adapter
            .dispatch_read(&ctx, inode.get(), adapter_fh, 0, payload.len() as u32, None)
            .expect("dispatch_read after double flush");

        assert_eq!(read_back, payload);

        // Handle must still be resolvable after repeated flushes.
        assert!(fixture
            .adapter
            .resolve_file_handle(inode.get(), adapter_fh, 0)
            .is_ok());
    }

