    #[test]
    fn vfs_adapter_dispatch_open_release_sequence() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };

        // Create 5 files through the engine, then open each through dispatch.
        let mut inodes: Vec<InodeId> = Vec::new();
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            for i in 0..5 {
                let name = format!("seq{i}.txt");
                let (attr, _fh) = engine
                    .create(root, name.as_bytes(), 0o644, libc::O_RDWR as u32, &ctx)
                    .expect("create seq file");
                inodes.push(attr.inode_id);
            }
        }

        let mut handles: Vec<(InodeId, u64)> = Vec::new();
        for inode in &inodes {
            let dispatch = fixture
                .adapter
                .dispatch_open(&ctx, inode.get(), libc::O_RDWR as u32)
                .expect("open seq file");
            handles.push((*inode, dispatch.adapter_fh));
        }

        // Release in reverse order.
        handles.reverse();
        for (inode, adapter_fh) in &handles {
            fixture
                .adapter
                .dispatch_release(inode.get(), *adapter_fh, 0, None, false)
                .expect("release seq file");
        }

        // All handles must now be unresolvable.
        for (inode, adapter_fh) in &handles {
            assert_eq!(
                fixture
                    .adapter
                    .resolve_file_handle(inode.get(), *adapter_fh, 0),
                Err(Errno::EBADF)
            );
        }
    }

