    #[test]
    fn vfs_adapter_last_close_no_writeback_when_not_last() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let inode = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            let (attr, _fh) = engine
                .create(root, b"not-last.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create not-last test file");
            attr.inode_id
        };

        let first = fixture
            .adapter
            .dispatch_open_entry(&ctx, inode.get(), libc::O_RDONLY as u32)
            .expect("first open");
        let _second = fixture
            .adapter
            .dispatch_open_entry(&ctx, inode.get(), libc::O_RDWR as u32)
            .expect("second open");

        {
            let mut ds = fixture.adapter.dirty_state.lock().unwrap();
            let mut dr = DirtyRanges::default();
            dr.mark_dirty(0, 10);
            ds.insert(inode.get(), dr);
        }

        fixture
            .adapter
            .dispatch_release(inode.get(), first.adapter_fh, 0, None, false)
            .expect("release first handle");

        assert_eq!(
            fixture
                .adapter
                .file_handles
                .lock()
                .unwrap()
                .open_ref_count(inode.get()),
            1
        );

        {
            let ds = fixture.adapter.dirty_state.lock().unwrap();
            assert!(
                ds.contains_key(&inode.get()),
                "dirty state should persist when not last close"
            );
        }
    }

