    #[test]
    fn access_plan_checks_owner_group_and_other_mode_bits() {
        let attr = test_attr_with_mode(42, 7, 0o754, 1000, 1001);
        let owner = access_ctx(1000, 2000, &[2000]);
        let group = access_ctx(2000, 1001, &[1001]);
        let supplementary_group = access_ctx(2000, 2001, &[1001]);
        let other = access_ctx(3000, 3001, &[3001]);

        assert_eq!(
            plan_fuse_access_decision(
                &attr,
                &owner,
                ACCESS_READ | ACCESS_WRITE | ACCESS_EXECUTE,
                None,
                &VALID_MOUNT
            ),
            Ok(())
        );
        assert_eq!(
            plan_fuse_access_decision(
                &attr,
                &group,
                ACCESS_READ | ACCESS_EXECUTE,
                None,
                &VALID_MOUNT
            ),
            Ok(())
        );
        assert_eq!(
            plan_fuse_access_decision(
                &attr,
                &supplementary_group,
                ACCESS_WRITE,
                None,
                &VALID_MOUNT
            ),
            Err(Errno::EACCES)
        );
        assert_eq!(
            plan_fuse_access_decision(&attr, &other, ACCESS_READ, None, &VALID_MOUNT),
            Ok(())
        );
        assert_eq!(
            plan_fuse_access_decision(&attr, &other, ACCESS_WRITE, None, &VALID_MOUNT),
            Err(Errno::EACCES)
        );
        assert_eq!(
            plan_fuse_access_decision(&attr, &other, ACCESS_EXECUTE, None, &VALID_MOUNT),
            Err(Errno::EACCES)
        );
    }

