    #[test]
    fn dentry_policy_defaults_use_short_negative_ttl() {
        let policy = DentryPolicy::default();
        let positive = policy.positive_lookup_config();
        let negative = policy.negative_lookup_config();

        assert_eq!(positive.entry_ttl_secs, 1);
        assert_eq!(positive.entry_ttl_nsec, 0);
        assert_eq!(positive.attr_ttl_secs, 1);
        assert_eq!(positive.attr_ttl_nsec, 0);
        assert_eq!(policy.positive_reply_ttl(), Duration::from_secs(1));
        assert_eq!(negative.entry_ttl_secs, 0);
        assert_eq!(negative.entry_ttl_nsec, 250_000_000);
        assert_eq!(negative.attr_ttl_secs, 0);
        assert_eq!(negative.attr_ttl_nsec, 0);
        assert_eq!(policy.negative_reply_ttl(), Duration::from_millis(250));
    }

    #[test]
    fn dentry_invalidation_tracks_child_and_parent_generation() {
        let mut state = DentryInvalidationState::default();

        let generation = state.invalidate_child(9, b"missing.txt");

        assert_eq!(generation, 1);
        assert_eq!(state.entry_generation(9, b"missing.txt"), Some(1));
        assert_eq!(state.parent_generation(9), Some(1));
        assert_eq!(state.entry_generation(9, b"other.txt"), None);
        assert_eq!(state.parent_generation(10), None);
    }

    #[test]
    fn dentry_invalidation_tracks_rename_endpoints() {
        let mut state = DentryInvalidationState::default();

        let generation = state.invalidate_rename(9, b"old.txt", 10, b"new.txt");

        assert_eq!(generation, 1);
        assert_eq!(state.entry_generation(9, b"old.txt"), Some(1));
        assert_eq!(state.entry_generation(10, b"new.txt"), Some(1));
        assert_eq!(state.parent_generation(9), Some(1));
        assert_eq!(state.parent_generation(10), Some(1));
    }

