    #[test]
    fn vfs_adapter_dispatch_statfs_empty_filesystem_reports_valid_info() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let statfs = fixture
            .adapter
            .dispatch_statfs(&ctx, 1)
            .expect("dispatch_statfs on empty filesystem");
        // All capacity fields must be positive.
        assert!(statfs.block_size > 0, "block_size must be positive");
        assert!(statfs.fragment_size > 0, "fragment_size must be positive");
        assert!(statfs.total_blocks > 0, "total_blocks must be positive");
        // Free and available blocks must be bounded by total blocks.
        assert!(statfs.free_blocks <= statfs.total_blocks);
        assert!(statfs.avail_blocks <= statfs.free_blocks);
        // Inode counters must be populated.
        assert!(statfs.files > 0, "files must be positive");
        assert!(statfs.files_free <= statfs.files);
        assert!(statfs.name_max > 0, "name_max must be positive");
    }

    #[test]
    fn vfs_adapter_dispatch_statfs_after_write_reduces_free_blocks() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let before = fixture
            .adapter
            .dispatch_statfs(&ctx, 1)
            .expect("statfs before write");
        let (ino, fh, _efh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"statfs-write.bin",
            libc::O_RDWR as u32,
        );
        // Write 16 KiB of data through the adapter.
        let payload = vec![0x5a; 16 * 1024];
        fixture
            .adapter
            .dispatch_write(&ctx, ino.get(), fh, 0, &payload, 0)
            .expect("write payload");
        let after = fixture
            .adapter
            .dispatch_statfs(&ctx, 1)
            .expect("statfs after write");
        // Block size must be stable.
        assert_eq!(after.block_size, before.block_size);
        assert_eq!(after.fragment_size, before.fragment_size);
        assert_eq!(after.name_max, before.name_max);
        // Writing data must not increase free blocks.
        assert!(
            after.free_blocks <= before.free_blocks,
            "free_blocks must not increase after write"
        );
        assert!(
            after.avail_blocks <= before.avail_blocks,
            "avail_blocks must not increase after write"
        );
    }

    #[test]
    fn vfs_adapter_dispatch_statfs_inode_counters_after_create() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let before = fixture
            .adapter
            .dispatch_statfs(&ctx, 1)
            .expect("statfs before create");
        let _ = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"statfs-inode.bin",
            libc::O_CREAT as u32,
        );
        let after = fixture
            .adapter
            .dispatch_statfs(&ctx, 1)
            .expect("statfs after create");
        // files_free must decrease (or stay equal if the store pre-allocates).
        assert!(
            after.files_free <= before.files_free,
            "files_free must not increase after creating a file"
        );
    }

