    #[test]
    fn file_handle_table_reconstructs_engine_handle_and_releases_once() {
        let mut table = AdapterFileHandleTable::default();
        let adapter_fh = table.allocate(
            42,
            libc::O_RDWR as u32,
            EngineFileHandle::new(InodeId::new(0), 0, FileHandleId::new(9), 0),
        );

        let resolved = table
            .resolve(42, adapter_fh, 700)
            .expect("resolve adapter fh");
        assert_eq!(resolved.inode_id, InodeId::new(42));
        assert_eq!(resolved.fh_id, FileHandleId::new(9));
        assert_eq!(resolved.open_flags, libc::O_RDWR as u32);
        assert_eq!(resolved.lock_owner, 700);
        assert_eq!(table.resolve(7, adapter_fh, 0), Err(Errno::EBADF));

        let released = table
            .remove(42, adapter_fh, 701)
            .expect("release adapter fh");
        assert_eq!(released.fh_id, FileHandleId::new(9));
        assert_eq!(released.lock_owner, 701);
        assert_eq!(table.remove(42, adapter_fh, 0), Err(Errno::EBADF));
    }

