    #[test]
    fn dispatch_fiemap_falls_back_to_data_ranges_for_file_without_extent_map() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, created_adapter_fh, created_engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"test_fiemap_fallback",
            libc::O_RDWR as u32,
        );
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .write(&created_engine_fh, 0, b"hello world", &ctx)
                .expect("write test file");
        }
        let input = FiemapInput {
            fm_start: 0,
            fm_length: 4096,
            fm_flags: 0,
            fm_extent_count: 4,
        };
        // File exists but has no extent map (inline or chunked content only).
        // fiemap_file() falls back to data_ranges() and produces valid extents.
        let buf = fixture
            .adapter
            .dispatch_fiemap(&ctx, inode.get(), created_adapter_fh, input, 4096)
            .expect("dispatch_fiemap with fallback");
        // Should get a header + at least one extent
        assert!(buf.len() >= FIEMAP_HEADER_SIZE);
        // fm_mapped_extents should be at least 1
        let mapped = u32::from_le_bytes(buf[20..24].try_into().unwrap());
        assert!(mapped >= 1);
        // The extent should cover the written data
        if buf.len() >= FIEMAP_HEADER_SIZE + FIEMAP_EXTENT_SIZE {
            let fe_logical = u64::from_le_bytes(
                buf[FIEMAP_HEADER_SIZE..FIEMAP_HEADER_SIZE + 8]
                    .try_into()
                    .unwrap(),
            );
            assert_eq!(fe_logical, 0, "first extent should start at offset 0");
        }
    }

    fn lseek_range(start: u64, end: u64) -> LseekDataRange {
        LseekDataRange::new(start, end)
    }

    #[test]
    fn lseek_dense_file_reports_data_and_eof_hole() {
        let data_ranges = [lseek_range(0, 10)];

        assert_eq!(
            lseek_sparse_offset(10, 0, libc::SEEK_DATA, &data_ranges),
            Ok(0)
        );
        assert_eq!(
            lseek_sparse_offset(10, 4, libc::SEEK_DATA, &data_ranges),
            Ok(4)
        );
        assert_eq!(
            lseek_sparse_offset(10, 0, libc::SEEK_HOLE, &data_ranges),
            Ok(10)
        );
        assert_eq!(
            lseek_sparse_offset(10, 10, libc::SEEK_DATA, &data_ranges),
            Err(Errno::ENXIO)
        );
    }

    #[test]
    fn lseek_leading_and_trailing_holes_are_reported() {
        let data_ranges = [lseek_range(8, 12)];

        assert_eq!(
            lseek_sparse_offset(20, 0, libc::SEEK_DATA, &data_ranges),
            Ok(8)
        );
        assert_eq!(
            lseek_sparse_offset(20, 0, libc::SEEK_HOLE, &data_ranges),
            Ok(0)
        );
        assert_eq!(
            lseek_sparse_offset(20, 8, libc::SEEK_HOLE, &data_ranges),
            Ok(12)
        );
        assert_eq!(
            lseek_sparse_offset(20, 12, libc::SEEK_HOLE, &data_ranges),
            Ok(12)
        );
        assert_eq!(
            lseek_sparse_offset(20, 12, libc::SEEK_DATA, &data_ranges),
            Err(Errno::ENXIO)
        );
    }

    #[test]
    fn lseek_interior_hole_skips_to_next_data() {
        let data_ranges = [lseek_range(0, 5), lseek_range(15, 20)];

        assert_eq!(
            lseek_sparse_offset(20, 3, libc::SEEK_HOLE, &data_ranges),
            Ok(5)
        );
        assert_eq!(
            lseek_sparse_offset(20, 5, libc::SEEK_HOLE, &data_ranges),
            Ok(5)
        );
        assert_eq!(
            lseek_sparse_offset(20, 5, libc::SEEK_DATA, &data_ranges),
            Ok(15)
        );
        assert_eq!(
            lseek_sparse_offset(20, 15, libc::SEEK_DATA, &data_ranges),
            Ok(15)
        );
        assert_eq!(
            lseek_sparse_offset(20, 15, libc::SEEK_HOLE, &data_ranges),
            Ok(20)
        );
    }

    #[test]
    fn lseek_merges_unsorted_adjacent_ranges_for_boundaries() {
        let data_ranges = [lseek_range(10, 15), lseek_range(0, 5), lseek_range(5, 10)];

        assert_eq!(
            lseek_sparse_offset(20, 4, libc::SEEK_HOLE, &data_ranges),
            Ok(15)
        );
        assert_eq!(
            lseek_sparse_offset(20, 15, libc::SEEK_HOLE, &data_ranges),
            Ok(15)
        );
    }

    #[test]
    fn lseek_rejects_eof_beyond_eof_negative_and_unknown_whence() {
        let data_ranges = [lseek_range(0, 5)];

        assert_eq!(
            lseek_sparse_offset(5, 5, libc::SEEK_HOLE, &data_ranges),
            Err(Errno::ENXIO)
        );
        assert_eq!(
            lseek_sparse_offset(5, 6, libc::SEEK_DATA, &data_ranges),
            Err(Errno::ENXIO)
        );
        assert_eq!(
            lseek_sparse_offset(5, -1, libc::SEEK_DATA, &data_ranges),
            Err(Errno::EINVAL)
        );
        assert_eq!(
            lseek_sparse_offset(5, 0, libc::SEEK_SET, &data_ranges),
            Err(Errno::EINVAL)
        );
    }

