    #[test]
    fn vfs_adapter_dispatch_open_fmode_exec_checks_execute_not_read() {
        let fixture = adapter_fixture();
        let root = {
            let ctx = root_ctx();
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };
        let inode = {
            let ctx = root_ctx();
            let engine = fixture.adapter.engine.lock().unwrap();
            let (attr, fh) = engine
                .create(root, b"exec-only.bin", 0o111, libc::O_RDWR as u32, &ctx)
                .expect("create exec-only file");
            engine.release(&fh).expect("release");
            attr.inode_id
        };
        let user_ctx = access_ctx(2000, 2000, &[2000]);

        assert_eq!(
            fixture
                .adapter
                .dispatch_open_entry(&user_ctx, inode.get(), libc::O_RDONLY as u32),
            Err(Errno::EACCES)
        );

        let dispatch = fixture
            .adapter
            .dispatch_open_entry(
                &user_ctx,
                inode.get(),
                libc::O_RDONLY as u32 | LINUX_FMODE_EXEC_OPEN_FLAG,
            )
            .expect("execute-only open should check execute permission");
        let handle = fixture.adapter.file_handles.lock().unwrap();
        let stored = handle
            .handles
            .get(&dispatch.adapter_fh)
            .expect("adapter handle");
        assert_eq!(
            stored.engine_handle.open_flags & LINUX_FMODE_EXEC_OPEN_FLAG,
            0
        );
        assert_eq!(
            stored.engine_handle.open_flags & libc::O_ACCMODE as u32,
            libc::O_RDONLY as u32
        );
    }

    #[test]
    fn vfs_adapter_dispatch_access_acl_aware() {
        let fixture = adapter_fixture();
        let root = {
            let ctx = root_ctx();
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };
        let inode = {
            let ctx = root_ctx();
            let engine = fixture.adapter.engine.lock().unwrap();
            let (attr, fh) = engine
                .create(root, b"acl-access.txt", 0o640, libc::O_RDWR as u32, &ctx)
                .expect("create file");
            engine.release(&fh).expect("release");
            attr.inode_id
        };
        // Mode bits deny user 1000.
        let user_ctx = access_ctx(1000, 2000, &[]);
        assert_eq!(
            fixture
                .adapter
                .dispatch_access(&user_ctx, inode.get(), libc::R_OK),
            Err(Errno::EACCES),
            "mode bits deny before ACL"
        );
        // Install ACL granting user 1000 read.
        let acl: Vec<PosixAclEntry> = vec![
            tidefs_posix_acl::PosixAclEntry {
                tag: tidefs_posix_acl::ACL_USER_OBJ,
                perm: 6,
                id: 0,
            },
            tidefs_posix_acl::PosixAclEntry {
                tag: tidefs_posix_acl::ACL_USER,
                perm: 4,
                id: 1000,
            },
            tidefs_posix_acl::PosixAclEntry {
                tag: tidefs_posix_acl::ACL_GROUP_OBJ,
                perm: 4,
                id: 0,
            },
            tidefs_posix_acl::PosixAclEntry {
                tag: tidefs_posix_acl::ACL_MASK,
                perm: 4,
                id: 0,
            },
            tidefs_posix_acl::PosixAclEntry {
                tag: tidefs_posix_acl::ACL_OTHER,
                perm: 0,
                id: 0,
            },
        ];
        let encoded = tidefs_permission::encode_posix_acl_xattr(&acl);
        fixture
            .adapter
            .dispatch_setxattr(
                &root_ctx(),
                inode.get(),
                b"system.posix_acl_access",
                &encoded,
                0,
            )
            .expect("set ACL");
        // ACL should grant user 1000 read access.
        fixture
            .adapter
            .dispatch_access(&user_ctx, inode.get(), libc::R_OK)
            .expect("ACL should grant access R_OK");
        // But NOT write access.
        assert_eq!(
            fixture
                .adapter
                .dispatch_access(&user_ctx, inode.get(), libc::W_OK),
            Err(Errno::EACCES),
            "ACL does not grant write"
        );
    }

