    #[test]
    fn vfs_adapter_dispatch_listxattr_after_set_and_remove() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, _fh) =
            create_file_with_data_and_open(&fixture, b"xattr-list-after-rm.txt", b"content", 0);

        // Set two xattrs
        fixture
            .adapter
            .dispatch_setxattr(&ctx, inode.get(), b"user.alpha", b"a", 0)
            .expect("set alpha");
        fixture
            .adapter
            .dispatch_setxattr(&ctx, inode.get(), b"user.beta", b"b", 0)
            .expect("set beta");

        // List should contain both
        let names = fixture
            .adapter
            .dispatch_listxattr(&ctx, inode.get())
            .expect("listxattr before remove");
        let parts: Vec<&[u8]> = names.split(|b| *b == 0).filter(|p| !p.is_empty()).collect();
        assert!(parts.contains(&b"user.alpha".as_ref()));
        assert!(parts.contains(&b"user.beta".as_ref()));
        assert_eq!(parts.len(), 2);

        // Remove one
        fixture
            .adapter
            .dispatch_removexattr(&ctx, inode.get(), b"user.alpha")
            .expect("remove alpha");

        // List should contain only the remaining key
        let names = fixture
            .adapter
            .dispatch_listxattr(&ctx, inode.get())
            .expect("listxattr after remove");
        let parts: Vec<&[u8]> = names.split(|b| *b == 0).filter(|p| !p.is_empty()).collect();
        assert!(!parts.contains(&b"user.alpha".as_ref()));
        assert!(parts.contains(&b"user.beta".as_ref()));
        assert_eq!(parts.len(), 1);
    }

    #[test]
    fn vfs_adapter_dispatch_listxattr_filters_trusted_for_nonroot() {
        let fixture = adapter_fixture();
        let root_ctx = root_ctx();
        let nonroot_ctx = RequestCtx {
            uid: 1000,
            gid: 1000,
            pid: 1,
            umask: 0o022,
            groups: vec![1000],
        };
        let (inode, _fh) =
            create_file_with_data_and_open(&fixture, b"xattr-list-trusted.txt", b"content", 0);

        // root sets both user.* and trusted.* xattrs
        fixture
            .adapter
            .dispatch_setxattr(&root_ctx, inode.get(), b"user.vis", b"yes", 0)
            .expect("set user.vis as root");
        fixture
            .adapter
            .dispatch_setxattr(&root_ctx, inode.get(), b"trusted.hid", b"no", 0)
            .expect("set trusted.hid as root");

        // non-root listxattr: trusted.* must be filtered, user.* must appear
        let names = fixture
            .adapter
            .dispatch_listxattr(&nonroot_ctx, inode.get())
            .expect("listxattr as nonroot");
        let parts: Vec<&[u8]> = names.split(|b| *b == 0).filter(|p| !p.is_empty()).collect();
        assert!(
            parts.contains(&b"user.vis".as_ref()),
            "user.vis should be visible to nonroot"
        );
        assert!(
            !parts.contains(&b"trusted.hid".as_ref()),
            "trusted.hid must not be visible to nonroot"
        );
    }

