    #[test]
    fn vfs_adapter_dispatch_xattr_persistence_across_close_reopen() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, fh) = create_file_with_data_and_open(
            &fixture,
            b"xattr-persist.txt",
            b"content",
            libc::O_RDWR as u32,
        );

        // set xattr while file is open
        fixture
            .adapter
            .dispatch_setxattr(&ctx, inode.get(), b"user.persist", b"survives", 0)
            .expect("setxattr before close");

        // close the file handle
        let released = fixture
            .adapter
            .remove_file_handle(inode.get(), fh, 0)
            .expect("remove file handle");
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.release(&released).expect("release engine handle");
        }

        // reopen the file
        let (_new_fh, _new_engine_fh) =
            open_adapter_file_handle(&fixture.adapter, &ctx, inode, libc::O_RDONLY as u32);

        // getxattr should still find the persisted value
        let value = fixture
            .adapter
            .dispatch_getxattr(&ctx, inode.get(), b"user.persist")
            .expect("getxattr after reopen");
        assert_eq!(value, b"survives");
    }
