    #[test]
    fn vfs_adapter_dispatch_readdirplus_attrs_populated() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };

        // Create files with specific modes so we can verify attr fidelity.
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .create(root, b"readme", 0o644, libc::O_CREAT as u32, &ctx)
                .expect("create readme");
            engine
                .create(root, b"script", 0o755, libc::O_CREAT as u32, &ctx)
                .expect("create script");
        }

        let dh = fixture
            .adapter
            .dispatch_opendir(&ctx, root.get())
            .expect("opendir root");
        let fh = dh.dh_id.get();

        let (pairs, has_more) = fixture
            .adapter
            .dispatch_readdirplus(&ctx, root.get(), fh, 0)
            .expect("readdirplus root");

        // We expect `.`, `..`, `readme`, `script` (4 entries).
        assert_eq!(pairs.len(), 4);
        assert!(!has_more);

        // Every pair should carry a valid attr with mode > 0, size, and nlink.
        for (entry, attr) in &pairs {
            assert!(
                attr.posix.mode > 0,
                "entry {:?} has zero mode",
                std::str::from_utf8(&entry.name).unwrap_or("?")
            );
            assert!(
                attr.posix.nlink > 0,
                "entry {:?} has zero nlink",
                std::str::from_utf8(&entry.name).unwrap_or("?")
            );
            // size may be zero for empty files, which is valid.
            // inode_id in the entry must match the attr.
            assert_eq!(
                entry.inode_id,
                attr.inode_id,
                "entry {:?} inode_id mismatch",
                std::str::from_utf8(&entry.name).unwrap_or("?")
            );
        }

        // Verify specific entries exist with correct names.
        let names: Vec<&str> = pairs
            .iter()
            .map(|(e, _)| std::str::from_utf8(&e.name).unwrap())
            .collect();
        assert!(names.contains(&"."));
        assert!(names.contains(&".."));
        assert!(names.contains(&"readme"));
        assert!(names.contains(&"script"));
    }

