    #[test]
    fn vfs_adapter_dispatch_readdir_after_unlink_does_not_panic() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };

        // Create two files.
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .create(root, b"alpha", 0o644, libc::O_CREAT as u32, &ctx)
                .expect("create alpha");
            engine
                .create(root, b"beta", 0o644, libc::O_CREAT as u32, &ctx)
                .expect("create beta");
        }

        // Open the root directory.
        let dh = fixture
            .adapter
            .dispatch_opendir(&ctx, root.get())
            .expect("opendir root");
        let fh = dh.dh_id.get();

        // Unlink one file while the dir is open.
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.unlink(root, b"alpha", &ctx).expect("unlink alpha");
        }

        // Readdir after unlink: should not panic and should only show the remaining entry.
        let (entries, has_more) = fixture
            .adapter
            .dispatch_readdir(&ctx, root.get(), fh, 0)
            .expect("readdir after unlink");
        assert!(!has_more);

        // Should have `.`, `..`, and only `beta` (3 entries total, `alpha` gone).
        let names: Vec<&str> = entries
            .iter()
            .map(|e| std::str::from_utf8(&e.name).unwrap())
            .collect();
        assert_eq!(names, vec![".", "..", "beta"]);
        assert_eq!(entries.len(), 3);
        // Cleanup the remaining file.
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.unlink(root, b"beta", &ctx).expect("unlink beta");
        }
        fixture.adapter.dispatch_releasedir(fh).expect("releasedir");
    }

    // ── DirStreamBackend integration tests (workers-ns dispatch) ─────

    /// A test [`DirStreamBackend`] backed by in-memory [`DirIndex`] instances
    /// and an [`NsInodeAttr`] table.  Exercises the workers-ns dispatch
    /// functions from the daemon test module.
    struct TestNsDirStreamBackend {
        inodes: std::vec::Vec<NsInodeAttr>,
        dirs: std::vec::Vec<(u64, DirIndex)>,
        handles: std::vec::Vec<(u64, u64)>,
        next_handle: u64,
    }

    impl TestNsDirStreamBackend {
        fn new() -> Self {
            Self {
                inodes: vec![NsInodeAttr {
                    ino: 1,
                    generation: 1,
                    kind: NsNodeKind::Directory,
                    mode: 0o40755,
                    uid: 0,
                    gid: 0,
                    nlink: 2,
                    rdev: 0,
                }],
                dirs: vec![(1, DirIndex::new(1, DatasetDirPolicy::DEFAULT))],
                handles: Vec::new(),
                next_handle: 100,
            }
        }

        fn dir_index_mut(&mut self, ino: u64) -> Option<&mut DirIndex> {
            self.dirs
                .iter_mut()
                .find(|(dir_ino, _)| *dir_ino == ino)
                .map(|(_, idx)| idx)
        }

        fn add_dir(&mut self, ino: u64) {
            self.inodes.push(NsInodeAttr {
                ino,
                generation: 1,
                kind: NsNodeKind::Directory,
                mode: 0o40755,
                uid: 0,
                gid: 0,
                nlink: 2,
                rdev: 0,
            });
            self.dirs
                .push((ino, DirIndex::new(ino, DatasetDirPolicy::DEFAULT)));
        }

        fn populate_dir(&mut self, dir_ino: u64, count: usize) {
            let dir = self.dir_index_mut(dir_ino).unwrap();
            for i in 0..count {
                let name = format!("entry_{i:03}.txt");
                dir.insert(name.as_bytes(), (200 + i) as u64, i as u64, 1)
                    .unwrap();
            }
        }
    }

    impl DirStreamBackend for TestNsDirStreamBackend {
        fn get_dir_index(&self, ino: u64) -> Option<&DirIndex> {
            self.dirs
                .iter()
                .find(|(dir_ino, _)| *dir_ino == ino)
                .map(|(_, idx)| idx)
        }

        fn get_dir_attr(&self, ino: u64) -> Result<NsInodeAttr, NsOpError> {
            self.inodes
                .iter()
                .find(|attr| attr.ino == ino)
                .copied()
                .ok_or(NsOpError::InodeNotFound)
        }

        fn alloc_dir_handle(&mut self, ino: u64) -> Result<u64, NsOpError> {
            let handle = self.next_handle;
            self.next_handle += 1;
            self.handles.push((handle, ino));
            Ok(handle)
        }

        fn release_dir_handle(&mut self, handle: u64) -> Result<(), NsOpError> {
            let pos = self
                .handles
                .iter()
                .position(|(h, _)| *h == handle)
                .ok_or(NsOpError::BadHandle)?;
            self.handles.remove(pos);
            Ok(())
        }

        fn lookup_dir_handle(&self, handle: u64) -> Option<u64> {
            self.handles
                .iter()
                .find(|(h, _)| *h == handle)
                .map(|(_, ino)| *ino)
        }
    }

    #[test]
    fn ns_dispatch_opendir_readdir_releasedir_lifecycle() {
        let mut backend = TestNsDirStreamBackend::new();
        backend.add_dir(2);
        backend.populate_dir(2, 3);

        // opendir
        let open = ns_dispatch_opendir(&mut backend, 2, 0).expect("opendir");
        assert!(open.handle >= 100);
        assert_eq!(open.open_flags, 0);
        assert_eq!(backend.lookup_dir_handle(open.handle), Some(2));

        // readdir
        let result = ns_dispatch_readdir(&backend, open.handle, 0, 128).expect("readdir");
        assert_eq!(result.entries.len(), 3);
        assert!(result.eof);
        assert_eq!(result.entries[0].name.as_bytes(), b"entry_000.txt");
        assert_eq!(result.entries[2].name.as_bytes(), b"entry_002.txt");

        // releasedir
        ns_dispatch_releasedir(&mut backend, open.handle).expect("releasedir");
        assert!(
            ns_dispatch_readdir(&backend, open.handle, 0, 128).is_err(),
            "readdir after releasedir must fail"
        );
    }

    #[test]
    fn ns_dispatch_readdir_pagination() {
        let mut backend = TestNsDirStreamBackend::new();
        backend.add_dir(2);
        backend.populate_dir(2, 10);
        let open = ns_dispatch_opendir(&mut backend, 2, 0).expect("opendir");

        let p1 = ns_dispatch_readdir(&backend, open.handle, 0, 3).expect("page 1");
        assert_eq!(p1.entries.len(), 3);
        assert!(!p1.eof);

        let p2 = ns_dispatch_readdir(&backend, open.handle, p1.next_offset, 3).expect("page 2");
        assert_eq!(p2.entries.len(), 3);
        assert!(!p2.eof);

        let p3 = ns_dispatch_readdir(&backend, open.handle, p2.next_offset, 3).expect("page 3");
        assert_eq!(p3.entries.len(), 3);
        let p4 = ns_dispatch_readdir(&backend, open.handle, p3.next_offset, 3).expect("page 4");
        assert_eq!(p4.entries.len(), 1);
        assert!(p4.eof);

        let total = p1.entries.len() + p2.entries.len() + p3.entries.len() + p4.entries.len();
        assert_eq!(total, 10);
    }

