    #[test]
    fn dr_clear_overlap_multiple_ranges() {
        let mut dr = DirtyRanges::default();
        dr.mark_dirty(0, 4096);
        dr.mark_dirty(8192, 4096);
        dr.mark_dirty(16384, 4096);
        // Clear range [6144,14336)
        dr.clear_overlap(6144, 8192);
        // First range [0,4096]: untouched (0 < 6144)
        // Second range [8192,12288]: fully covered by [6144,14336), removed
        // Third range [16384,20480]: no overlap (16384 >= 14336), untouched
        assert_eq!(dr.ranges(), &[(0, 4096), (16384, 20480)]);
    }

