        let (ino, fh, _) =
            create_adapter_file_handle(&f.adapter, &c, b"a.bin", libc::O_RDWR as u32);
        f.adapter
            .dispatch_write(&c, ino.get(), fh, 0, td, 0)
            .unwrap();
