    #[test]
    fn vfs_adapter_dispatch_fdatasync_flushes_dirty_pages() {
        // Write data through dispatch_write (dirtying pages), then call
        // dispatch_fdatasync which must trigger the writeback path and flush
        // dirty data through the block-volume target.
        let f = adapter_fixture();
        let c = root_ctx();
        let td = b"fdatasync wb";
        let (ino, fh, _) =
            create_adapter_file_handle(&f.adapter, &c, b"fdatasync-wb.bin", libc::O_RDWR as u32);
        f.adapter
            .dispatch_write(&c, ino.get(), fh, 0, td, 0)
            .unwrap();
        let (m, log) = MockBV::new();
        f.adapter.block_volume.lock().unwrap().replace(Box::new(m));
        f.adapter
            .dispatch_fdatasync(&c, ino.get(), fh)
            .expect("dispatch_fdatasync should succeed");
        // Dirty state must be cleared after successful writeback.
        assert!(f
            .adapter
            .dirty_state
            .lock()
            .unwrap()
            .get(&ino.get())
            .is_none_or(|dr| dr.is_empty()));
        // Data must have been written to the block-volume target.
        assert_eq!(log.lock().unwrap()[0].1, td);
    }

    #[test]
    fn vfs_adapter_dispatch_fsync_flushes_dirty_pages() {
        // Write data through dispatch_write (dirtying pages), then call
        // dispatch_fsync (full sync) which must trigger the writeback path and
        // flush dirty data through the block-volume target.
        let mut f = adapter_fixture();
        let writeback_page_cache = Arc::new(PageCache::new(8, 4096));
        f.adapter.writeback_page_cache = Some(Arc::clone(&writeback_page_cache));
        let c = root_ctx();
        let td = b"fsync wb";
        let (ino, fh, _) =
            create_adapter_file_handle(&f.adapter, &c, b"fsync-wb.bin", libc::O_RDWR as u32);
        f.adapter
            .dispatch_write(&c, ino.get(), fh, 0, td, 0)
            .unwrap();
        assert!(writeback_page_cache.has_dirty_pages_for_inode(ino.get()));
        assert!(f
            .adapter
            .write_page_cache
            .has_dirty_pages_for_inode(ino.get()));
        let (m, log) = MockBV::new();
        f.adapter.block_volume.lock().unwrap().replace(Box::new(m));
        f.adapter
            .dispatch_fsync(&c, ino.get(), fh)
            .expect("dispatch_fsync should succeed");
        // Dirty state must be cleared after successful writeback.
        assert!(f
            .adapter
            .dirty_state
            .lock()
            .unwrap()
            .get(&ino.get())
            .is_none_or(|dr| dr.is_empty()));
        assert!(!writeback_page_cache.has_dirty_pages_for_inode(ino.get()));
        assert!(!f
            .adapter
            .write_page_cache
            .has_dirty_pages_for_inode(ino.get()));
        // Data must have been written to the block-volume target.
        assert_eq!(log.lock().unwrap()[0].1, td);
    }

    #[test]
    fn vfs_adapter_dispatch_fsync_bv_error_returns_eio() {
        // When the block-volume write fails during dispatch_fsync, the error
        // must be propagated as EIO and dirty pages must be retained.
        let mut f = adapter_fixture();
        let tracker = Arc::new(Mutex::new(
            tidefs_local_filesystem::dirty_page_tracker::DirtyPageTracker::new(),
        ));
        f.adapter.writeback_range_tracker = Some(Arc::clone(&tracker));
        let writeback_page_cache = Arc::new(PageCache::new(8, 4096));
        f.adapter.writeback_page_cache = Some(Arc::clone(&writeback_page_cache));
        let c = root_ctx();
        let td = b"eio flush";
        let (ino, fh, _) =
            create_adapter_file_handle(&f.adapter, &c, b"eio-flush.bin", libc::O_RDWR as u32);
        f.adapter
            .dispatch_write(&c, ino.get(), fh, 0, td, 0)
            .unwrap();
        assert!(writeback_page_cache.has_dirty_pages_for_inode(ino.get()));
        assert!(f
            .adapter
            .write_page_cache
            .has_dirty_pages_for_inode(ino.get()));
        tracker.lock().unwrap().mark_dirty(ino, 0, td.len() as u64);
        let (m, _log) = MockBV::new();
        f.adapter
            .block_volume
            .lock()
            .unwrap()
            .replace(Box::new(MockBV { fail: true, ..m }));
        let result = f.adapter.dispatch_fsync(&c, ino.get(), fh);
        assert_eq!(result, Err(Errno::EIO));
        // Dirty pages must be retained when the block-volume write fails.
        assert!(f
            .adapter
            .dirty_state
            .lock()
            .unwrap()
            .get(&ino.get())
            .unwrap()
            .contains(0, td.len() as u32));
        assert!(writeback_page_cache.has_dirty_pages_for_inode(ino.get()));
        assert!(f
            .adapter
            .write_page_cache
            .has_dirty_pages_for_inode(ino.get()));
        let tracker = tracker.lock().unwrap();
        let ranges = tracker
            .dirty_ranges(ino)
            .expect("failed fsync range remains tracked");
        assert_eq!(ranges.len(), 1);
        assert_eq!(
            ranges[0].lifecycle_state(),
            tidefs_local_filesystem::dirty_page_tracker::DirtyLifecycleState::ErrorPoisoned
        );
        assert!(
            ranges[0].writeback_error().is_some(),
            "failed fsync must retain a writeback error"
        );
    }

    #[test]
    fn vfs_adapter_dispatch_fsync_txg_error_retains_dirty_projections() {
        let mut f = adapter_fixture();
        let tracker = Arc::new(Mutex::new(
            tidefs_local_filesystem::dirty_page_tracker::DirtyPageTracker::new(),
        ));
        f.adapter.writeback_range_tracker = Some(Arc::clone(&tracker));
        let writeback_page_cache = Arc::new(PageCache::new(8, 4096));
        f.adapter.writeback_page_cache = Some(Arc::clone(&writeback_page_cache));
        let invalid_store_root = f.root.join("txg-store-root-file");
        std::fs::write(&invalid_store_root, b"not a directory").expect("create invalid TXG root");
        f.adapter
            .txg_cycle_cell()
            .set_store_root(invalid_store_root);

        let ctx = root_ctx();
        let payload = b"late fsync failure";
        let (ino, fh, _) = create_adapter_file_handle(
            &f.adapter,
            &ctx,
            b"late-fsync-failure.bin",
            libc::O_RDWR as u32,
        );
        f.adapter
            .dispatch_write(&ctx, ino.get(), fh, 0, payload, 0)
            .expect("dispatch write");
        let worker_tracker =
            seed_worker_dirty_range(&f.adapter, ino.get(), 0, payload.len() as u64);
        tracker
            .lock()
            .unwrap()
            .mark_dirty(ino, 0, payload.len() as u64);
        let (block_volume, writes) = MockBV::new();
        f.adapter
            .block_volume
            .lock()
            .unwrap()
            .replace(Box::new(block_volume));

        assert_eq!(
            f.adapter.dispatch_fsync(&ctx, ino.get(), fh),
            Err(Errno::EIO)
        );
        assert_eq!(writes.lock().unwrap()[0].1, payload);
        assert!(f
            .adapter
            .dirty_state
            .lock()
            .unwrap()
            .get(&ino.get())
            .is_some_and(|ranges| ranges.contains(0, payload.len() as u32)));
        assert!(writeback_page_cache.has_dirty_pages_for_inode(ino.get()));
        assert!(f
            .adapter
            .write_page_cache
            .has_dirty_pages_for_inode(ino.get()));
        assert!(worker_tracker.lock().unwrap().has_dirty_ranges(ino.get()));

        let tracker = tracker.lock().unwrap();
        let ranges = tracker
            .dirty_ranges(ino)
            .expect("late fsync failure must retain the dirty range");
        assert_eq!(ranges.len(), 1);
        assert_eq!(
            ranges[0].lifecycle_state(),
            tidefs_local_filesystem::dirty_page_tracker::DirtyLifecycleState::ErrorPoisoned
        );
        assert!(ranges[0].writeback_error().is_some());
    }

    #[test]
    fn vfs_adapter_dispatch_fsync_idempotent_repeated_calls() {
        // Write data through dispatch_write (dirtying pages), fsync to flush,
        // then fsync again. The second fsync must be a clean no-op and must
        // not leave any dirty state behind.
        let f = adapter_fixture();
        let c = root_ctx();
        let td = b"fsync-idempotent";
        let (ino, fh, _) =
            create_adapter_file_handle(&f.adapter, &c, b"fsync-idem.bin", libc::O_RDWR as u32);
        f.adapter
            .dispatch_write(&c, ino.get(), fh, 0, td, 0)
            .unwrap();
        let (m, log) = MockBV::new();
        f.adapter.block_volume.lock().unwrap().replace(Box::new(m));

        // First fsync: flushes dirty pages to block volume.
        f.adapter
            .dispatch_fsync(&c, ino.get(), fh)
            .expect("first dispatch_fsync should succeed");
        assert!(f
            .adapter
            .dirty_state
            .lock()
            .unwrap()
            .get(&ino.get())
            .is_none_or(|dr| dr.is_empty()));
        assert_eq!(log.lock().unwrap().len(), 1, "first fsync wrote to BV");

        // Second fsync: file is clean, must be an idempotent no-op.
        f.adapter
            .dispatch_fsync(&c, ino.get(), fh)
            .expect("second dispatch_fsync should succeed");
        // BV write log must not have grown (no additional writeback).
        assert_eq!(log.lock().unwrap().len(), 1, "second fsync must not write");
        // Dirty state must still be empty.
        assert!(f
            .adapter
            .dirty_state
            .lock()
            .unwrap()
            .get(&ino.get())
            .is_none_or(|dr| dr.is_empty()));
    }

    #[test]
    fn vfs_adapter_dispatch_fsync_metadata_after_setattr() {
        // Change file metadata via dispatch_setattr, then fsync. The fsync
        // must succeed and the metadata changes must be visible after fsync.
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, adapter_fh, _) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"fsync-metadata.txt",
            libc::O_RDWR as u32,
        );

        // Change mode + ownership via setattr.
        let mut update = SetAttr::new();
        update.valid = FATTR_MODE | FATTR_UID | FATTR_GID;
        update.mode = 0o600;
        update.uid = 42;
        update.gid = 99;
        let attr_out = fixture
            .adapter
            .dispatch_setattr(&ctx, 8100, inode.get(), &update, None)
            .expect("setattr before fsync");
        assert_eq!(attr_out.attr.mode & 0o777, 0o600);
        assert_eq!(attr_out.attr.uid, 42);
        assert_eq!(attr_out.attr.gid, 99);

        // fsync must succeed after metadata-only changes.
        fixture
            .adapter
            .dispatch_fsync(&ctx, inode.get(), adapter_fh)
            .expect("fsync after setattr should succeed");

        // Metadata must remain stable after fsync.
        let engine = fixture.adapter.engine.lock().unwrap();
        let stored = engine
            .getattr(inode, None, &ctx)
            .expect("getattr after fsync");
        assert_eq!(stored.posix.mode & 0o777, 0o600);
        assert_eq!(stored.posix.uid, 42);
        assert_eq!(stored.posix.gid, 99);
    }

