    #[test]
    fn vfs_adapter_getattr_and_lookup_return_identical_fuse_attr() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };
        // Create a file and look it up through the engine.
        let (file_attr, _fh) = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .create(root, b"consistency_file", 0o755, libc::O_CREAT as u32, &ctx)
                .expect("create file")
        };
        let file_ino = file_attr.inode_id.get();
        let lookup_attr = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .lookup(root, b"consistency_file", &ctx)
                .expect("lookup file")
        };

        // GETATTR through the adapter.
        let getattr_out = fixture
            .adapter
            .dispatch_getattr(&ctx, file_ino, 42, None)
            .expect("getattr file");

        // Build expected FuseAttr from the InodeAttr returned by lookup,
        // using the same shared helper that GETATTR uses internally.
        let expected = posix_attrs_to_fuse_attr(
            lookup_attr.inode_id.get(),
            &lookup_attr.posix,
            lookup_attr.kind,
        );

        // Every field must match.
        assert_eq!(getattr_out.attr.ino, expected.ino);
        assert_eq!(getattr_out.attr.size, expected.size);
        assert_eq!(getattr_out.attr.blocks, expected.blocks);
        assert_eq!(getattr_out.attr.atime, expected.atime);
        assert_eq!(getattr_out.attr.mtime, expected.mtime);
        assert_eq!(getattr_out.attr.ctime, expected.ctime);
        assert_eq!(getattr_out.attr.atimensec, expected.atimensec);
        assert_eq!(getattr_out.attr.mtimensec, expected.mtimensec);
        assert_eq!(getattr_out.attr.ctimensec, expected.ctimensec);
        assert_eq!(getattr_out.attr.mode, expected.mode);
        assert_eq!(getattr_out.attr.nlink, expected.nlink);
        assert_eq!(getattr_out.attr.uid, expected.uid);
        assert_eq!(getattr_out.attr.gid, expected.gid);
        assert_eq!(getattr_out.attr.rdev, expected.rdev);
        assert_eq!(getattr_out.attr.blksize, expected.blksize);
        // GETATTR must follow the active adapter coherency policy.  The
        // default test fixture uses RelativeAtime, which intentionally disables
        // positive attr TTLs so lookup/getattr cannot hide atime updates.
        assert_eq!(
            fuse_attr_out_ttl(&getattr_out),
            fixture.adapter.dentry_policy.positive_attr_ttl
        );
    }

    #[test]
    fn file_attr_from_fuse_attr_preserves_pre_epoch_raw_seconds() {
        let raw_atime_sec = -315_593_940_i64;
        let raw_mtime_sec = -315_593_939_i64;
        let attr = FuseAttr {
            ino: 7,
            size: 0,
            blocks: 0,
            atime: raw_atime_sec as u64,
            mtime: raw_mtime_sec as u64,
            ctime: (-1_i64) as u64,
            atimensec: 0,
            mtimensec: 123,
            ctimensec: 999_999_999,
            mode: S_IFREG | 0o644,
            nlink: 1,
            uid: 1000,
            gid: 1000,
            rdev: 0,
            blksize: 4096,
            padding: 0,
        };

        let file_attr = file_attr_from_fuse_attr(&attr);

        assert_eq!(
            system_time_to_ns(file_attr.atime),
            raw_atime_sec * 1_000_000_000
        );
        assert_eq!(
            system_time_to_ns(file_attr.mtime),
            raw_mtime_sec * 1_000_000_000 + 123
        );
        assert_eq!(system_time_to_ns(file_attr.ctime), -1);
    }

    #[test]
    fn file_attr_from_fuse_attr_maps_posix_mode_file_types() {
        let cases = [
            (tidefs_types_vfs_core::S_IFDIR, FileType::Directory),
            (tidefs_types_vfs_core::S_IFREG, FileType::RegularFile),
            (tidefs_types_vfs_core::S_IFLNK, FileType::Symlink),
            (tidefs_types_vfs_core::S_IFCHR, FileType::CharDevice),
            (tidefs_types_vfs_core::S_IFBLK, FileType::BlockDevice),
            (tidefs_types_vfs_core::S_IFIFO, FileType::NamedPipe),
            (tidefs_types_vfs_core::S_IFSOCK, FileType::Socket),
        ];

        for (mode_type, expected) in cases {
            let attr = FuseAttr {
                ino: 7,
                size: 0,
                blocks: 0,
                atime: 0,
                mtime: 0,
                ctime: 0,
                atimensec: 0,
                mtimensec: 0,
                ctimensec: 0,
                mode: mode_type | 0o644,
                nlink: 1,
                uid: 1000,
                gid: 1000,
                rdev: 0x0103,
                blksize: 512,
                padding: 0,
            };

            assert_eq!(file_attr_from_fuse_attr(&attr).kind, expected);
        }
    }

