    #[test]
    fn vfs_adapter_dispatch_create_produces_writable_handle() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };

        let dispatch = fixture
            .adapter
            .dispatch_create_entry(
                &ctx,
                root.get(),
                b"writable.txt",
                0o644,
                libc::O_RDWR as u32,
            )
            .expect("create dispatch");

        // Resolve the adapter handle and write through it.
        let engine_fh = fixture
            .adapter
            .resolve_file_handle(dispatch.attr.inode_id.get(), dispatch.adapter_fh, 0)
            .expect("resolve created handle for write");

        let written = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .write(&engine_fh, 0, b"hello from create", &ctx)
                .expect("write through created handle")
        };
        assert_eq!(written, b"hello from create".len() as u32);

        // Read back to verify.
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            let data = engine.read(&engine_fh, 0, 32, &ctx).expect("read back");
            assert_eq!(data, b"hello from create");
        }
    }

