    #[test]
    fn vfs_adapter_dispatch_mkdir_public_api_nested_chain() {
        let fixture = adapter_fixture();
        let ctx = access_ctx(1000, 1001, &[1001]);
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };

        // mkdir root/a
        let a_attr = fixture
            .adapter
            .dispatch_mkdir(&ctx, root.get(), b"a", 0o755)
            .expect("mkdir a");
        assert_eq!(a_attr.kind, NodeKind::Dir);

        // mkdir a/b
        let b_attr = fixture
            .adapter
            .dispatch_mkdir(&ctx, a_attr.inode_id.get(), b"b", 0o755)
            .expect("mkdir a/b");
        assert_eq!(b_attr.kind, NodeKind::Dir);

        // mkdir a/b/c
        let c_attr = fixture
            .adapter
            .dispatch_mkdir(&ctx, b_attr.inode_id.get(), b"c", 0o755)
            .expect("mkdir a/b/c");
        assert_eq!(c_attr.kind, NodeKind::Dir);

        // Verify nested structure via lookup.
        let engine = fixture.adapter.engine.lock().unwrap();
        let lookup_a = engine.lookup(root, b"a", &ctx).expect("lookup a");
        assert_eq!(lookup_a.inode_id, a_attr.inode_id);
        let lookup_b = engine
            .lookup(a_attr.inode_id, b"b", &ctx)
            .expect("lookup b");
        assert_eq!(lookup_b.inode_id, b_attr.inode_id);
        let lookup_c = engine
            .lookup(b_attr.inode_id, b"c", &ctx)
            .expect("lookup c");
        assert_eq!(lookup_c.inode_id, c_attr.inode_id);

        // Verify parent nlink of a is 3: ., .., b
        let a_nlink = engine
            .getattr(a_attr.inode_id, None, &ctx)
            .expect("getattr a")
            .posix
            .nlink;
        assert_eq!(a_nlink, 3, "a should have nlink=3: ., .., b");
    }

