    #[test]
    fn vfs_adapter_dispatch_rename_public_api_enotdir_directory_over_file() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };

        // Create a regular file and a directory.
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .create(root, b"file.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create file");
            engine.mkdir(root, b"dir", 0o755, &ctx).expect("mkdir dir");
        }

        // Rename a directory onto a regular file via public API.
        let result =
            fixture
                .adapter
                .dispatch_rename(&ctx, root.get(), b"dir", root.get(), b"file.txt", 0);
        assert_eq!(result, Err(Errno::ENOTDIR));

        // Verify both entries preserved after failed rename.
        let engine = fixture.adapter.engine.lock().unwrap();
        let file_attr = engine
            .lookup(root, b"file.txt", &ctx)
            .expect("file still exists");
        assert_eq!(file_attr.kind, NodeKind::File);
        assert!(engine.lookup(root, b"dir", &ctx).is_ok());
    }

