    fn dispatch_statfs_free_blocks_decrease_after_write() {
        let f = adapter_fixture();
        let c = root_ctx();
        let b = f.adapter.dispatch_statfs(&c, 1).expect("statfs before");
        let (ino, afh, efh) =
            create_adapter_file_handle(&f.adapter, &c, b"x.bin", libc::O_RDWR as u32);
        f.adapter
            .engine
            .lock()
            .unwrap()
            .write(&efh, 0, &[0x5a; 64 * 1024], &c)
            .expect("write");
        f.adapter
            .remove_file_handle(ino.get(), afh, 0)
            .expect("remove");
        let a = f.adapter.dispatch_statfs(&c, 1).expect("statfs after");
        assert_eq!(a.block_size, b.block_size);
        assert!(a.free_blocks <= b.free_blocks);
        assert!(a.avail_blocks <= b.avail_blocks);
    }
    #[test]
    fn dispatch_statfs_files_free_decreases_after_file_creation() {
        let f = adapter_fixture();
        let c = root_ctx();
        let before = f.adapter.dispatch_statfs(&c, 1).expect("statfs before");
        // Create several files (each creates an inode).
        for i in 0..5 {
            let name = format!("file-{i}.bin");
            let (_ino, afh, _efh) =
                create_adapter_file_handle(&f.adapter, &c, name.as_bytes(), libc::O_RDWR as u32);
            f.adapter
                .remove_file_handle(_ino.get(), afh, 0)
                .expect("remove file handle");
        }
        let after = f.adapter.dispatch_statfs(&c, 1).expect("statfs after");
        assert_eq!(after.files, before.files, "total inode slots unchanged");
        assert_eq!(after.name_max, before.name_max, "name_max unchanged");
        // Free inodes should decrease (or stay the same if space is very large),
        // but never increase.
        assert!(
            after.files_free <= before.files_free,
            "free inodes should not increase after creating files: before={}, after={}",
            before.files_free,
            after.files_free
        );
    }

