    #[test]
    fn vfs_adapter_dispatch_write_partial_block_preserves_surrounding_data() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, adapter_fh, engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"write-partial.txt",
            libc::O_RDWR as u32,
        );

        let initial: Vec<u8> = (0..255u8).cycle().take(4096).collect();
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .write(&engine_fh, 0, &initial, &ctx)
                .expect("write initial block");
        }

        let replacement = b"REPLACE!";
        let written = fixture
            .adapter
            .dispatch_write(&ctx, inode.get(), adapter_fh, 8, replacement, 0)
            .expect("partial-block write dispatch");

        assert_eq!(written, replacement.len() as u32);

        {
            let engine = fixture.adapter.engine.lock().unwrap();
            let head = engine.read(&engine_fh, 0, 8, &ctx).expect("read head");
            assert_eq!(head, &initial[0..8], "head bytes should be preserved");

            let mid = engine
                .read(&engine_fh, 8, replacement.len() as u32, &ctx)
                .expect("read mid");
            assert_eq!(mid, replacement, "middle bytes should be replaced");

            let tail = engine.read(&engine_fh, 16, 16, &ctx).expect("read tail");
            assert_eq!(tail, &initial[16..32], "tail bytes should be preserved");
        }
    }

