    #[test]
    fn vfs_adapter_dispatch_write_getattr_cache_invalidation() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, adapter_fh, _engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"write-getattr-cache.txt",
            libc::O_RDWR as u32,
        );

        // Populate the getattr cache with initial size
        let initial = fixture
            .adapter
            .dispatch_getattr(&ctx, inode.get(), 100, None)
            .expect("initial getattr");
        assert_eq!(initial.attr.size, 0, "new file should be empty");

        // Write to extend the file (should invalidate getattr cache)
        let written = fixture
            .adapter
            .dispatch_write(&ctx, inode.get(), adapter_fh, 0, b"hello world", 0)
            .expect("write dispatch");
        assert_eq!(written, 11);

        // Second getattr must reflect updated size, not stale cached 0
        let after = fixture
            .adapter
            .dispatch_getattr(&ctx, inode.get(), 101, None)
            .expect("getattr after write");
        assert_eq!(
            after.attr.size, 11,
            "size must reflect written data after cache invalidation"
        );
    }

