    #[test]
    fn vfs_adapter_dispatch_setattr_utimens_updates_timestamps() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, _adapter_fh, _engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"setattr-utimens.txt",
            libc::O_RDWR as u32,
        );

        let mut update = SetAttr::new();
        update.valid = FATTR_ATIME | FATTR_MTIME;
        update.atime_ns = 1_000_000_000;
        update.mtime_ns = 2_000_000_000;

        let attr_out = fixture
            .adapter
            .dispatch_setattr(&ctx, 8103, inode.get(), &update, None)
            .expect("setattr utimens");

        // Verify returned attrs reflect new timestamps
        assert_eq!(attr_out.attr.atime, 1);
        assert_eq!(attr_out.attr.atimensec, 0);
        assert_eq!(attr_out.attr.mtime, 2);
        assert_eq!(attr_out.attr.mtimensec, 0);
        // Verify engine persisted the timestamps
        let engine = fixture.adapter.engine.lock().unwrap();
        let stored = engine
            .getattr(inode, None, &ctx)
            .expect("stored attr after utimens");
        assert_eq!(stored.posix.atime_ns, 1_000_000_000);
        assert_eq!(stored.posix.mtime_ns, 2_000_000_000);
    }

