    #[test]
    fn vfs_adapter_dispatch_setattr_chmod_preserves_file_type_bits() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, _adapter_fh, _engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"setattr-chmod-type.txt",
            libc::O_RDWR as u32,
        );
        // Fetch initial mode to confirm S_IFREG is set
        let initial = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(inode, None, &ctx)
                .expect("getattr before chmod")
        };
        assert!(initial.posix.mode & libc::S_IFMT == libc::S_IFREG);

        // Change only permission bits, should preserve S_IFREG
        let mut update = SetAttr::new();
        update.valid = FATTR_MODE;
        update.mode = 0o077; // rwx for all, no type bits set

        let attr_out = fixture
            .adapter
            .dispatch_setattr(&ctx, 8202, inode.get(), &update, None)
            .expect("setattr chmod type-bit preservation");

        // The returned mode should still have S_IFREG preserved
        assert_eq!(attr_out.attr.mode & libc::S_IFMT, libc::S_IFREG);
        // Permission bits should match what was requested
        assert_eq!(attr_out.attr.mode & 0o777, 0o077);

        let engine = fixture.adapter.engine.lock().unwrap();
        let stored = engine
            .getattr(inode, None, &ctx)
            .expect("stored attr after chmod");
        assert_eq!(stored.posix.mode & libc::S_IFMT, libc::S_IFREG);
        assert_eq!(stored.posix.mode & 0o777, 0o077);
    }

