    #[test]
    fn dispatch_read_directory_inode_returns_ebadf() {
        // Create a directory and a separate regular file.  Attempting to
        // dispatch_read on the directory inode with a file's handle must
        // fail with EBADF (the adapter-level inode guard rejects the
        // mismatched inode before reaching the engine's EISDIR check).
        let fixture = adapter_fixture();
        let ctx = root_ctx();

        // Create a directory.
        let dir_ino = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            engine
                .mkdir(root, b"readdir-test-dir", 0o755, &ctx)
                .expect("mkdir")
                .inode_id
                .get()
        };

        // Create a regular file and get its adapter handle.
        let (_file_inode, fh, _efh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"not-a-dir.bin",
            libc::O_RDWR as u32,
        );

        // Try to read from the directory inode using the file's handle.
        // The adapter-level inode guard rejects the mismatched inode.
        let result = fixture
            .adapter
            .dispatch_read(&ctx, dir_ino, fh, 0, 512, None);
        assert_eq!(
            result,
            Err(Errno::EBADF),
            "dispatch_read on directory inode with file handle must return EBADF, got {result:?}"
        );
    }

