    #[test]
    fn vfs_adapter_dispatch_rename_open_file_handle_survives() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, adapter_fh, _engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"before_rename.txt",
            libc::O_RDWR as u32,
        );

        // Rename the file
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };
        fixture
            .adapter
            .dispatch_rename_entry(
                &ctx,
                root.get(),
                b"before_rename.txt",
                root.get(),
                b"after_rename.txt",
                0,
            )
            .expect("rename with open handle");

        // Write through the old handle (should succeed since handles reference inodes)
        let payload = b"post-rename write payload";
        let written = fixture
            .adapter
            .dispatch_write(&ctx, inode.get(), adapter_fh, 0, payload, 0)
            .expect("write after rename");
        assert_eq!(written as usize, payload.len());

        // Read back through the same handle
        let data = fixture
            .adapter
            .dispatch_read(&ctx, inode.get(), adapter_fh, 0, payload.len() as u32, None)
            .expect("read after rename");
        assert_eq!(data, payload);

        // Verify the new name exists
        let engine = fixture.adapter.engine.lock().unwrap();
        assert!(engine.lookup(root, b"after_rename.txt", &ctx).is_ok());
        assert_eq!(
            engine
                .lookup(root, b"before_rename.txt", &ctx)
                .expect_err("old name gone"),
            Errno::ENOENT
        );
    }

