    /// Helper: call engine.tmpfile directly and register the handle.
    fn dispatch_tmpfile_helper(
        fixture: &AdapterFixture,
        ctx: &RequestCtx,
        parent: u64,
        mode: u32,
        flags: u32,
    ) -> (u64, u64) {
        let engine_flags = flags & !LINUX_O_TMPFILE;
        let (attr, engine_fh) = fixture
            .adapter
            .engine
            .lock()
            .unwrap()
            .tmpfile(InodeId::new(parent), mode, engine_flags, ctx)
            .expect("engine tmpfile succeeds");
        let ino = attr.inode_id.get();
        let adapter_fh = fixture
            .adapter
            .file_handles
            .lock()
            .unwrap()
            .allocate(ino, flags, engine_fh);
        (ino, adapter_fh)
    }

