    #[test]
    fn dispatch_readdir_cookie_order_preserves_engine_ordering() {
        // Verify that cookies increase monotonically and entries appear
        // in the order returned by the engine.
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };
        let dir_attr = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .mkdir(root, b"cookie-dir", 0o755, &ctx)
                .expect("mkdir")
        };

        const COUNT: usize = 8;
        let mut expected: Vec<Vec<u8>> = Vec::new();
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            for i in 0..COUNT {
                let name = format!("entry_{i:02}");
                engine
                    .create(
                        dir_attr.inode_id,
                        name.as_bytes(),
                        0o644,
                        libc::O_RDWR as u32,
                        &ctx,
                    )
                    .expect("create entry");
                expected.push(name.into_bytes());
            }
        }

        let dh = fixture
            .adapter
            .dispatch_opendir(&ctx, dir_attr.inode_id.get())
            .expect("opendir");

        let (entries, has_more) = fixture
            .adapter
            .dispatch_readdir(&ctx, dir_attr.inode_id.get(), dh.dh_id.0, 0)
            .expect("readdir");

        assert!(!has_more, "8 files plus . and .. should fit in one batch");

        // Cookies must be strictly increasing
        for i in 1..entries.len() {
            assert!(
                entries[i].cookie > entries[i - 1].cookie,
                "cookie at index {i} ({}) must exceed previous ({})",
                entries[i].cookie,
                entries[i - 1].cookie
            );
        }

        // Collect child names (skip . and ..)
        let mut seen: Vec<Vec<u8>> = Vec::new();
        for entry in &entries {
            if entry.name != b"." && entry.name != b".." {
                seen.push(entry.name.clone());
            }
        }
        seen.sort();
        expected.sort();
        assert_eq!(seen, expected, "all {COUNT} entries must be present");
    }

    #[test]
    fn dispatch_readdirplus_attrs_mode_nlink_size_after_write() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };
        let dir_attr = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .mkdir(root, b"attrs-dir", 0o755, &ctx)
                .expect("mkdir")
        };

        let file_ino = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let (attr, fh) = engine
                .create(
                    dir_attr.inode_id,
                    b"data.bin",
                    0o600,
                    libc::O_RDWR as u32,
                    &ctx,
                )
                .expect("create file");
            let payload = vec![0xABu8; 1024];
            engine.write(&fh, 0, &payload, &ctx).expect("write 1KB");
            attr.inode_id
        };

        let dh = fixture
            .adapter
            .dispatch_opendir(&ctx, dir_attr.inode_id.get())
            .expect("opendir");

        let (pairs, has_more) = fixture
            .adapter
            .dispatch_readdirplus(&ctx, dir_attr.inode_id.get(), dh.dh_id.0, 0)
            .expect("readdirplus attrs");

        assert!(!has_more);

        // data.bin: file, mode 0600, nlink=1, size=1024
        let file_pair = pairs
            .iter()
            .find(|(e, _)| e.name == b"data.bin")
            .expect("data.bin entry");
        assert_eq!(file_pair.0.kind, NodeKind::File);
        assert_eq!(file_pair.0.inode_id, file_ino);
        assert_eq!(file_pair.1.posix.mode & libc::S_IFMT, libc::S_IFREG);
        assert_eq!(file_pair.1.posix.mode & 0o777, 0o600);
        assert_eq!(file_pair.1.posix.nlink, 1);
        assert_eq!(file_pair.1.posix.size, 1024);

        // . and .. must also have valid attrs
        for name_bytes in [b".".as_slice(), b"..".as_slice()] {
            let pair = pairs
                .iter()
                .find(|(e, _)| e.name.as_slice() == name_bytes)
                .expect("must have dot/dotdot");
            assert_eq!(pair.0.kind, NodeKind::Dir);
            assert_eq!(pair.1.posix.mode & libc::S_IFMT, libc::S_IFDIR);
            assert!(pair.1.posix.nlink >= 1);
            assert!(pair.1.inode_id.get() > 0);
        }
    }

