    #[test]
    fn dispatch_opendir_readdir_releasedir_lifecycle() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };
        let dir_attr = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .mkdir(root, b"lifecycle-dir", 0o755, &ctx)
                .expect("mkdir lifecycle dir")
        };
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .create(
                    dir_attr.inode_id,
                    b"epsilon",
                    0o644,
                    libc::O_RDWR as u32,
                    &ctx,
                )
                .expect("create epsilon");
        }

        let dh = fixture
            .adapter
            .dispatch_opendir(&ctx, dir_attr.inode_id.get())
            .expect("opendir lifecycle");

        let (entries, has_more) = fixture
            .adapter
            .dispatch_readdir(&ctx, dir_attr.inode_id.get(), dh.dh_id.0, 0)
            .expect("readdir lifecycle");
        assert!(!has_more);
        let names: Vec<_> = entries.iter().map(|e| e.name.clone()).collect();
        assert!(names.contains(&b"epsilon".to_vec()));

        let (pairs, _) = fixture
            .adapter
            .dispatch_readdirplus(&ctx, dir_attr.inode_id.get(), dh.dh_id.0, 0)
            .expect("readdirplus lifecycle");
        let plus_names: Vec<_> = pairs.iter().map(|(e, _)| e.name.clone()).collect();
        assert!(plus_names.contains(&b"epsilon".to_vec()));

        assert_eq!(
            fixture.adapter.dispatch_releasedir(dh.dh_id.0),
            Ok(()),
            "releasedir lifecycle"
        );
        assert_eq!(
            fixture.adapter.dispatch_releasedir(dh.dh_id.0),
            Err(Errno::EBADF),
            "double releasedir must fail"
        );
    }

