    // ── io_roundtrip integration test ─────────────────────────────────────
    //
    // Sequences: create file → write → flush → read back → verify content →
    // unlink → verify ENOENT lookup.  Exercises writeback, extent-map, and
    // object-store paths through the public adapter surface.

    #[test]
    fn io_roundtrip_write_flush_read_unlink() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();

        // 1. Create a file with read-write handle through the public API.
        let (inode, adapter_fh, _engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"roundtrip-io.bin",
            libc::O_RDWR as u32,
        );

        // 2. Write data.
        let payload = b"TideFS io_roundtrip integration payload\r\n";
        let written = fixture
            .adapter
            .dispatch_write(&ctx, inode.get(), adapter_fh, 0, payload, 0)
            .expect("dispatch_write roundtrip");
        assert_eq!(written as usize, payload.len());

        // 3. Flush dirty data through dispatch_flush.
        fixture
            .adapter
            .dispatch_flush(&ctx, inode.get(), adapter_fh, 0)
            .expect("dispatch_flush roundtrip");

        // 4. Read back and verify content.
        let readback = fixture
            .adapter
            .dispatch_read(&ctx, inode.get(), adapter_fh, 0, payload.len() as u32, None)
            .expect("dispatch_read roundtrip");
        assert_eq!(readback, payload, "roundtrip content mismatch");

        // 5. Unlink the file.
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            engine
                .unlink(root, b"roundtrip-io.bin", &ctx)
                .expect("unlink roundtrip file");
        }

        // 6. Verify file no longer exists via lookup.
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            let result = engine.lookup(root, b"roundtrip-io.bin", &ctx);
            assert!(result.is_err(), "file must not exist after unlink");
        }
    }

