    #[test]
    fn block_volume_direct_write_stays_dirty_until_fsync() {
        for use_fallback_handle in [false, true] {
            let (mut fixture, block_volume) = adapter_fixture_with_mock_block_volume();
            fixture.adapter.writeback_cache_enabled = use_fallback_handle;
            let ctx = root_ctx();
            let (inode, buffered_fh, _engine_fh) = create_adapter_file_handle(
                &fixture.adapter,
                &ctx,
                b"direct-write-block-volume.bin",
                libc::O_RDWR as u32,
            );
            let baseline = vec![0x11; DIRECT_IO_ALIGNMENT as usize];
            fixture
                .adapter
                .dispatch_write(&ctx, inode.get(), buffered_fh, 0, &baseline, 0)
                .expect("baseline write");
            fixture
                .adapter
                .dispatch_fsync(&ctx, inode.get(), buffered_fh)
                .expect("baseline fsync");

            let replacement = vec![0xAA; DIRECT_IO_ALIGNMENT as usize];
            if use_fallback_handle {
                let read_only = fixture
                    .adapter
                    .dispatch_open_entry(&ctx, inode.get(), libc::O_RDONLY as u32)
                    .expect("open read-only handle");
                fixture
                    .adapter
                    .dispatch_write_with_request_flags(
                        &ctx,
                        inode.get(),
                        read_only.adapter_fh,
                        0,
                        &replacement,
                        WriteDispatchFlags {
                            write: 0,
                            request_open: libc::O_WRONLY as u32 | libc::O_DIRECT as u32,
                        },
                    )
                    .expect("fallback direct overwrite");
            } else {
                let direct_open = fixture
                    .adapter
                    .dispatch_open_entry(
                        &ctx,
                        inode.get(),
                        libc::O_RDWR as u32 | libc::O_DIRECT as u32,
                    )
                    .expect("open direct writer");
                fixture
                    .adapter
                    .dispatch_write(
                        &ctx,
                        inode.get(),
                        direct_open.adapter_fh,
                        0,
                        &replacement,
                        0,
                    )
                    .expect("direct overwrite");
            }
            assert!(
                fixture
                    .adapter
                    .dirty_state
                    .lock()
                    .unwrap()
                    .get(&inode.get())
                    .is_some_and(|ranges| ranges.overlaps(0, replacement.len() as u64)),
                "direct write must keep the stale block-volume range dirty"
            );
            assert_eq!(
                fixture
                    .adapter
                    .writeback_cache
                    .lock()
                    .unwrap()
                    .is_dirty(inode.get()),
                Some(true),
                "direct write must protect the inode reclaim projection"
            );
            assert_eq!(
                block_volume
                    .lock()
                    .unwrap()
                    .stored(0, baseline.len() as u64),
                baseline,
                "direct write must not silently refresh the block-volume mirror"
            );

            let readback = fixture
                .adapter
                .dispatch_read(
                    &ctx,
                    inode.get(),
                    buffered_fh,
                    0,
                    replacement.len() as u32,
                    None,
                )
                .expect("buffered read after direct write");
            assert_eq!(readback, replacement);

            fixture
                .adapter
                .dispatch_fsync(&ctx, inode.get(), buffered_fh)
                .expect("direct-write fsync");
            assert!(
                !fixture
                    .adapter
                    .dirty_state
                    .lock()
                    .unwrap()
                    .contains_key(&inode.get()),
                "fsync must retire the block-volume dirty range"
            );
            assert_eq!(
                fixture
                    .adapter
                    .writeback_cache
                    .lock()
                    .unwrap()
                    .is_dirty(inode.get()),
                Some(false),
                "fsync must release the inode reclaim projection"
            );
            fixture.adapter.invalidate_read_cache_entry(inode.get());
            fixture
                .adapter
                .invalidate_fuse_read_cache_inode(inode.get());
            let clean_readback = fixture
                .adapter
                .dispatch_read(
                    &ctx,
                    inode.get(),
                    buffered_fh,
                    0,
                    replacement.len() as u32,
                    None,
                )
                .expect("clean block-volume read after fsync");
            assert_eq!(clean_readback, replacement);
        }
    }

    /// After a writeback flush through the block-volume adapter, a
    /// subsequent read of the flushed range correctly returns the data
    /// that was written, confirming the writeback interaction.
    #[test]
    fn block_volume_writeback_flush_then_read_round_trip() {
        let (fixture, bv) = adapter_fixture_with_mock_block_volume();
        let ctx = root_ctx();
        let (inode, adapter_fh, _engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"wb-roundtrip.bin",
            libc::O_RDWR as u32,
        );
        let payload = b"writeback flush round-trip check!";
        fixture
            .adapter
            .dispatch_write(&ctx, inode.get(), adapter_fh, 0, payload, 0)
            .expect("write");
        // Flush: this triggers writeback through the block-volume adapter.
        fixture
            .adapter
            .dispatch_fsync(&ctx, inode.get(), adapter_fh)
            .expect("fsync");
        // Verify block volume received the data (at physical offsets).
        {
            let bv_guard = bv.lock().unwrap();
            let stored = bv_guard.stored(0, payload.len() as u64);
            assert_eq!(stored, payload, "block volume must hold the flushed data");
        }
        // Read back through the clean path.
        let readback = fixture
            .adapter
            .dispatch_read(&ctx, inode.get(), adapter_fh, 0, payload.len() as u32, None)
            .expect("read after fsync");
        assert_eq!(readback, payload);
    }

    #[test]
    fn dirty_state_tracks_multiple_inodes_independently() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (ino1, fh1, _efh1) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"dirty-inode-1.txt",
            libc::O_RDWR as u32,
        );
        let (ino2, fh2, _efh2) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"dirty-inode-2.txt",
            libc::O_RDWR as u32,
        );
        fixture
            .adapter
            .dispatch_write(&ctx, ino1.get(), fh1, 0, b"aaa", 0)
            .expect("write inode 1");
        fixture
            .adapter
            .dispatch_write(&ctx, ino2.get(), fh2, 0, b"bbb", 0)
            .expect("write inode 2");
        let ds = fixture.adapter.dirty_state.lock().unwrap();
        assert_eq!(ds.len(), 2);
        assert!(ds.contains_key(&ino1.get()));
        assert!(ds.contains_key(&ino2.get()));
        assert!(!ds.get(&ino1.get()).unwrap().is_empty());
        assert!(!ds.get(&ino2.get()).unwrap().is_empty());
    }

