    #[test]
    fn vfs_adapter_dispatch_readdir_nonempty_directory() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            engine
                .create(root, b"file-a.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create file-a");
            engine
                .create(root, b"file-b.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create file-b");
            engine
                .create(root, b"file-c.txt", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create file-c");
            root
        };

        let dh = fixture
            .adapter
            .dispatch_opendir(&ctx, root.get())
            .expect("opendir root");
        let fh = dh.dh_id.get();

        let (entries, has_more) = fixture
            .adapter
            .dispatch_readdir(&ctx, root.get(), fh, 0)
            .expect("readdir root");

        // Expect . (cookie 1), .. (cookie 2), and 3 engine entries
        assert_eq!(entries.len(), 5);
        assert_eq!(entries[0].name, b".");
        assert_eq!(entries[0].cookie, 1);
        assert_eq!(entries[1].name, b"..");
        assert_eq!(entries[1].cookie, 2);
        // Engine entries: sorted by name (DirIndex sorts by name)
        let engine_names: Vec<&[u8]> = entries[2..].iter().map(|e| e.name.as_slice()).collect();
        assert!(engine_names.contains(&b"file-a.txt".as_slice()));
        assert!(engine_names.contains(&b"file-b.txt".as_slice()));
        assert!(engine_names.contains(&b"file-c.txt".as_slice()));
        assert!(!has_more);

        fixture.adapter.dispatch_releasedir(fh).expect("releasedir");
    }

