    #[test]
    fn vfs_adapter_dispatch_readdir_partial_pagination() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            for i in 0..10 {
                let name = format!("entry_{i:03}.txt");
                engine
                    .create(root, name.as_bytes(), 0o644, libc::O_RDWR as u32, &ctx)
                    .expect("create entry");
            }
            root
        };

        let dh = fixture
            .adapter
            .dispatch_opendir(&ctx, root.get())
            .expect("opendir root");
        let fh = dh.dh_id.get();

        let (entries1, has_more1) = fixture
            .adapter
            .dispatch_readdir(&ctx, root.get(), fh, 0)
            .expect("readdir page 1");

        assert_eq!(entries1.len(), 12);
        assert!(!has_more1);
        assert_eq!(entries1[0].name, b".");
        assert_eq!(entries1[0].cookie, 1);
        assert_eq!(entries1[1].name, b"..");
        assert_eq!(entries1[1].cookie, 2);
        assert_eq!(entries1[2].name, b"entry_000.txt");
        assert_eq!(entries1[2].cookie, 3);
        assert_eq!(entries1.last().unwrap().name, b"entry_009.txt");
        let last_cookie = entries1.last().unwrap().cookie;

        let (entries2, has_more2) = fixture
            .adapter
            .dispatch_readdir(&ctx, root.get(), fh, last_cookie)
            .expect("readdir after last entry");
        assert!(entries2.is_empty());
        assert!(!has_more2);

        fixture.adapter.dispatch_releasedir(fh).expect("releasedir");
    }

