    #[test]
    fn vfs_adapter_opendir_readdir_releasedir_integration() {
        let mut fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            let subdir = engine
                .mkdir(root, b"subdir", 0o755, &ctx)
                .expect("mkdir subdir");
            engine
                .create(
                    subdir.inode_id,
                    b"child-a.txt",
                    0o644,
                    libc::O_RDWR as u32,
                    &ctx,
                )
                .expect("create child-a");
            engine
                .create(
                    subdir.inode_id,
                    b"child-b.txt",
                    0o644,
                    libc::O_RDWR as u32,
                    &ctx,
                )
                .expect("create child-b");
            subdir.inode_id
        };

        // Open directory
        let dh = fixture
            .adapter
            .dispatch_opendir(&ctx, root.get())
            .expect("opendir subdir");
        let fh = dh.dh_id.get();

        // Read entries
        let (entries, has_more) = fixture
            .adapter
            .dispatch_readdir(&ctx, root.get(), fh, 0)
            .expect("readdir subdir");

        // Expect . , .. , child-a.txt, child-b.txt
        assert_eq!(entries.len(), 4);
        assert_eq!(entries[0].name, b".");
        assert_eq!(entries[1].name, b"..");
        let entry_names: Vec<&[u8]> = entries[2..].iter().map(|e| e.name.as_slice()).collect();
        assert!(entry_names.contains(&b"child-a.txt".as_slice()));
        assert!(entry_names.contains(&b"child-b.txt".as_slice()));
        assert!(!has_more);

        // Release handle
        fixture
            .adapter
            .dispatch_releasedir(fh)
            .expect("releasedir subdir");

        // Verify released handle is gone
        let result = fixture.adapter.dispatch_readdir(&ctx, root.get(), fh, 0);
        assert_eq!(result, Err(Errno::EBADF));
    }
