    #[test]
    fn dispatch_statx_output_consistent_with_getattr() {
        let f = adapter_fixture();
        let c = root_ctx();
        let statx = f.adapter.dispatch_statx(&c, 1, 0).expect("statx");
        let attr = f.adapter.dispatch_getattr(&c, 1, 1, None).expect("getattr");
        // Core fields must match
        assert_eq!(statx.stx_ino, attr.attr.ino);
        assert_eq!(statx.stx_size, attr.attr.size);
        assert_eq!(statx.stx_blocks, attr.attr.blocks);
        assert_eq!(statx.stx_mode as u32, attr.attr.mode);
        assert_eq!(statx.stx_nlink, attr.attr.nlink);
        assert_eq!(statx.stx_uid, attr.attr.uid);
        assert_eq!(statx.stx_gid, attr.attr.gid);
        assert_eq!(statx.stx_blksize, attr.attr.blksize);
        // Timestamps must match
        assert_eq!(statx.stx_atime_sec, attr.attr.atime as i64);
        assert_eq!(statx.stx_atime_nsec, attr.attr.atimensec);
        assert_eq!(statx.stx_mtime_sec, attr.attr.mtime as i64);
        assert_eq!(statx.stx_mtime_nsec, attr.attr.mtimensec);
        assert_eq!(statx.stx_ctime_sec, attr.attr.ctime as i64);
        assert_eq!(statx.stx_ctime_nsec, attr.attr.ctimensec);
    }

