    #[test]
    fn vfs_adapter_dispatch_statfs_root_returns_nonzero_blocks() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };

        let statfs = fixture
            .adapter
            .dispatch_statfs(&ctx, root.get())
            .expect("statfs on root");

        assert!(statfs.block_size > 0, "block_size must be positive");
        assert!(statfs.total_blocks > 0, "total_blocks must be positive");
        assert!(statfs.free_blocks > 0, "free_blocks must be positive");
        assert!(
            statfs.free_blocks <= statfs.total_blocks,
            "free_blocks {} <= total_blocks {}",
            statfs.free_blocks,
            statfs.total_blocks
        );
        assert!(
            statfs.avail_blocks <= statfs.free_blocks,
            "avail_blocks {} <= free_blocks {}",
            statfs.avail_blocks,
            statfs.free_blocks
        );
        assert!(statfs.name_max >= 255, "name_max must be at least 255");
        assert_eq!(
            statfs.fragment_size, statfs.block_size,
            "fragment_size must equal block_size"
        );
    }

    #[test]
    fn vfs_adapter_dispatch_statfs_subdirectory_matches_root() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (root, subdir) = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let root = engine.get_root_inode(&ctx).expect("root inode");
            let subdir = engine
                .mkdir(root, b"subdir", 0o755, &ctx)
                .expect("mkdir subdir");
            (root, subdir.inode_id)
        };

        let root_statfs = fixture
            .adapter
            .dispatch_statfs(&ctx, root.get())
            .expect("statfs on root");
        let subdir_statfs = fixture
            .adapter
            .dispatch_statfs(&ctx, subdir.get())
            .expect("statfs on subdir");

        // Statfs is filesystem-global; all fields should match
        assert_eq!(subdir_statfs.block_size, root_statfs.block_size);
        assert_eq!(subdir_statfs.fragment_size, root_statfs.fragment_size);
        assert_eq!(subdir_statfs.total_blocks, root_statfs.total_blocks);
        assert_eq!(subdir_statfs.free_blocks, root_statfs.free_blocks);
        assert_eq!(subdir_statfs.avail_blocks, root_statfs.avail_blocks);
        assert_eq!(subdir_statfs.files, root_statfs.files);
        assert_eq!(subdir_statfs.files_free, root_statfs.files_free);
        assert_eq!(subdir_statfs.name_max, root_statfs.name_max);
    }

