    // ── dispatch_forget / forget refcount tests ───────────────────────

    #[test]
    fn forget_refcount_single_lookup_and_forget() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        // Create a file to get a known inode.
        let (inode_id, _adapter_fh, _engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"forget-test-1.txt",
            libc::O_RDWR as u32,
        );
        let ino = inode_id.get();

        // Simulate a kernel lookup → bump refcount.
        fixture.adapter.bump_forget_refcount(ino);
        {
            let refs = fixture.adapter.forget_refcounts.lock().unwrap();
            assert_eq!(refs.get(&ino), Some(&1));
        }

        // Simulate a forget with nlookup=1 → count reaches zero.
        let eligible = fixture.adapter.dispatch_forget(ino, 1);
        assert!(eligible);
        {
            let refs = fixture.adapter.forget_refcounts.lock().unwrap();
            assert!(!refs.contains_key(&ino));
        }
    }

