    #[test]
    fn dispatch_write_advances_mtime() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, fh, efh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"mtime-test.bin",
            libc::O_RDWR as u32,
        );
        let attr_before = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(inode, Some(&efh), &ctx)
                .expect("getattr before")
        };
        let mtime_before = attr_before.posix.mtime_ns;
        fixture
            .adapter
            .dispatch_write(&ctx, inode.get(), fh, 0, b"mtime-data", 0)
            .expect("write for mtime");
        let attr_after = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .getattr(inode, Some(&efh), &ctx)
                .expect("getattr after")
        };
        let mtime_after = attr_after.posix.mtime_ns;
        assert!(
            mtime_after > mtime_before,
            "mtime_ns must advance after write: before={mtime_before}, after={mtime_after}"
        );
    }

    #[test]
    fn dispatch_write_advances_mtime_on_multiple_writes() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, fh, efh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"mtime-multi.bin",
            libc::O_RDWR as u32,
        );
        let mut last_mtime = 0_i64;
        for i in 1..=4 {
            let payload = format!("mtime-write-{i}");
            fixture
                .adapter
                .dispatch_write(&ctx, inode.get(), fh, 0, payload.as_bytes(), 0)
                .expect("write for multi-mtime");
            let attr = {
                let engine = fixture.adapter.engine.lock().unwrap();
                engine.getattr(inode, Some(&efh), &ctx).expect("getattr")
            };
            let current_mtime = attr.posix.mtime_ns;
            assert!(
                current_mtime > last_mtime,
                "mtime must advance on write {i}: last={last_mtime}, current={current_mtime}"
            );
            last_mtime = current_mtime;
        }
    }

