    // Extent-map integration: sparse write/read validation

    #[test]
    fn vfs_adapter_write_sparse_non_contiguous_blocks_readable() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let (inode, adapter_fh, _engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"sparse-extents.txt",
            libc::O_RDWR as u32,
        );

        assert_eq!(
            fixture
                .adapter
                .dispatch_write(&ctx, inode.get(), adapter_fh, 0, &[0xAA_u8; 4096], 0)
                .unwrap(),
            4096
        );
        assert_eq!(
            fixture
                .adapter
                .dispatch_write(&ctx, inode.get(), adapter_fh, 8192, &[0xBB_u8; 4096], 0)
                .unwrap(),
            4096
        );
        assert_eq!(
            fixture
                .adapter
                .dispatch_write(&ctx, inode.get(), adapter_fh, 16384, &[0xCC_u8; 4096], 0)
                .unwrap(),
            4096
        );

        let buf0 = fixture
            .adapter
            .dispatch_read(&ctx, inode.get(), adapter_fh, 0, 4096, None)
            .expect("read block 0");
        assert_eq!(buf0, vec![0xAA_u8; 4096]);

        let buf_hole = fixture
            .adapter
            .dispatch_read(&ctx, inode.get(), adapter_fh, 4096, 4096, None)
            .expect("read hole");
        assert_eq!(buf_hole, vec![0_u8; 4096], "hole should read as zeroes");

        let buf2 = fixture
            .adapter
            .dispatch_read(&ctx, inode.get(), adapter_fh, 8192, 4096, None)
            .expect("read block 2");
        assert_eq!(buf2, vec![0xBB_u8; 4096]);

        let cross = fixture
            .adapter
            .dispatch_read(&ctx, inode.get(), adapter_fh, 8192, 8192, None)
            .expect("read cross");
        assert_eq!(cross.len(), 8192);
        assert_eq!(&cross[0..4096], &[0xBB_u8; 4096]);
        assert_eq!(&cross[4096..8192], &[0_u8; 4096]);

        let engine = fixture.adapter.engine.lock().unwrap();
        assert_eq!(
            engine
                .getattr(inode, None, &ctx)
                .expect("getattr")
                .posix
                .size,
            20480
        );
    }

