    #[test]
    fn vfs_adapter_dispatch_tmpfile_write_and_read_roundtrip() {
        let fixture = adapter_fixture();
        let ctx = access_ctx(1000, 1001, &[1001]);
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };

        let open_flags = (libc::O_RDWR | LINUX_O_TMPFILE as i32) as u32;
        let (attr, engine_fh) = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .tmpfile(root, 0o666, open_flags & !LINUX_O_TMPFILE, &ctx)
                .expect("engine tmpfile")
        };

        assert_eq!(attr.kind, NodeKind::File);
        assert_eq!(attr.posix.size, 0);

        // Write data through the tmpfile handle
        let payload = b"tmpfile data persists until release";
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            let written = engine
                .write(&engine_fh, 0, payload, &ctx)
                .expect("write to tmpfile");
            assert_eq!(written as usize, payload.len());
        }

        // Read it back via engine.read which returns Vec<u8>
        let data = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .read(&engine_fh, 0, payload.len() as u32, &ctx)
                .expect("read from tmpfile")
        };
        assert_eq!(data, payload);

        // Clean up
        let _ = fixture.adapter.engine.lock().unwrap().release(&engine_fh);
    }

    // ── namespace-mutation persistence round-trip tests ──────────────────

    #[test]
    fn vfs_adapter_namespace_mutations_persist_across_reopen() {
        let temp_id = NEXT_TEMP_ID.fetch_add(1, Ordering::Relaxed);
        let root = std::env::temp_dir().join(format!(
            "tidefs-ns-mut-persist-{}-{temp_id}",
            std::process::id()
        ));
        let _ = std::fs::remove_dir_all(&root);
        std::fs::create_dir_all(&root).expect("create temp root");

        let ctx = access_ctx(1000, 1001, &[1001]);
        let root_inode;
        let mkdir_inode;
        let file_inode;
        let symlink_inode;

        // Phase 1: create entries
        {
            let local_fs = LocalFileSystem::open_with_root_authentication_key(
                &root,
                StoreOptions::default(),
                RootAuthenticationKey::demo_key(),
            )
            .expect("open local filesystem");
            let engine = VfsLocalFileSystem::new(local_fs);
            let adapter = FuseVfsAdapter::new(Box::new(engine)).expect("create adapter");

            let eng = adapter.engine.lock().unwrap();
            let r = eng.get_root_inode(&ctx).expect("root inode");
            root_inode = r.get();

            // mkdir
            let attr = eng.mkdir(r, b"persist-dir", 0o755, &ctx).expect("mkdir");
            mkdir_inode = attr.inode_id.get();
            assert_eq!(attr.kind, NodeKind::Dir);

            // create file inside mkdir'd subdirectory
            let subdir = InodeId::new(mkdir_inode);
            let (file_attr, _) = eng
                .create(
                    subdir,
                    b"persist-file.txt",
                    0o644,
                    libc::O_RDWR as u32,
                    &ctx,
                )
                .expect("create file");
            file_inode = file_attr.inode_id.get();

            // symlink inside subdirectory
            let sym_attr = eng
                .symlink(subdir, b"persist-link", b"/some/target", &ctx)
                .expect("symlink");
            symlink_inode = sym_attr.inode_id.get();

            // hard link the file to root
            let link_attr = eng
                .link(InodeId::new(file_inode), r, b"persist-hardlink", &ctx)
                .expect("hard link");
            assert_eq!(link_attr.inode_id.get(), file_inode);
        }
        // Adapter (and engine) dropped here - filesystem closed

        // Phase 2: reopen and verify everything persisted
        {
            let local_fs = LocalFileSystem::open_with_root_authentication_key(
                &root,
                StoreOptions::default(),
                RootAuthenticationKey::demo_key(),
            )
            .expect("reopen local filesystem");
            let engine = VfsLocalFileSystem::new(local_fs);
            let adapter = FuseVfsAdapter::new(Box::new(engine)).expect("create adapter");

            let eng = adapter.engine.lock().unwrap();
            let r = eng.get_root_inode(&ctx).expect("root inode");
            assert_eq!(r.get(), root_inode, "root inode should be stable");

            // Verify mkdir persisted
            let lookup_dir = eng.lookup(r, b"persist-dir", &ctx).expect("lookup dir");
            assert_eq!(lookup_dir.inode_id.get(), mkdir_inode);
            assert_eq!(lookup_dir.kind, NodeKind::Dir);

            // Verify file inside subdirectory persisted
            let subdir = InodeId::new(mkdir_inode);
            let lookup_file = eng
                .lookup(subdir, b"persist-file.txt", &ctx)
                .expect("lookup file");
            assert_eq!(lookup_file.inode_id.get(), file_inode);
            assert_eq!(lookup_file.kind, NodeKind::File);

            // Verify symlink persisted
            let lookup_sym = eng
                .lookup(subdir, b"persist-link", &ctx)
                .expect("lookup symlink");
            assert_eq!(lookup_sym.inode_id.get(), symlink_inode);
            assert_eq!(lookup_sym.kind, NodeKind::Symlink);

            // Verify hard link persisted at root
            let lookup_link = eng
                .lookup(r, b"persist-hardlink", &ctx)
                .expect("lookup hardlink");
            assert_eq!(lookup_link.inode_id.get(), file_inode);
        }

        let _ = std::fs::remove_dir_all(&root);
    }

    // ── Negative lookup cache integration tests ────────────────────────

    #[test]
    fn negative_cache_avoids_engine_lookup_on_repeat_miss() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let root_ino_id = fixture
            .adapter
            .engine
            .lock()
            .unwrap()
            .get_root_inode(&ctx)
            .expect("root inode");

        // First lookup: should hit the engine and return ENOENT.
        let result1 = fixture
            .adapter
            .dispatch_lookup(&ctx, root_ino_id.get(), b"never_created");
        assert_eq!(result1, Err(Errno::ENOENT));

        // The negative cache should now contain this entry.
        {
            let cache = fixture.adapter.negative_cache.lock().unwrap();
            assert_eq!(
                cache.len(),
                1,
                "negative cache should have one entry after ENOENT"
            );
        }

        // Second lookup: the daemon-side negative cache should short-circuit.
        let result2 = fixture
            .adapter
            .dispatch_lookup(&ctx, root_ino_id.get(), b"never_created");
        assert_eq!(result2, Err(Errno::ENOENT));
    }

    #[test]
    fn negative_cache_invalidation_on_child_creation() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let root_ino_id = fixture
            .adapter
            .engine
            .lock()
            .unwrap()
            .get_root_inode(&ctx)
            .expect("root inode");

        // First lookup: miss, cached as negative.
        let result1 = fixture
            .adapter
            .dispatch_lookup(&ctx, root_ino_id.get(), b"will_exist");
        assert_eq!(result1, Err(Errno::ENOENT));

        {
            let cache = fixture.adapter.negative_cache.lock().unwrap();
            assert_eq!(cache.len(), 1, "negative cache has entry after first miss");
        }

        // Create the file — this should invalidate the negative cache entry.
        fixture
            .adapter
            .dispatch_create(&ctx, root_ino_id.get(), b"will_exist", 0o644, 0)
            .expect("create file");

        {
            let cache = fixture.adapter.negative_cache.lock().unwrap();
            assert_eq!(cache.len(), 0, "negative cache invalidated after creation");
        }

        // Now a lookup should find the file.
        let result2 = fixture
            .adapter
            .dispatch_lookup(&ctx, root_ino_id.get(), b"will_exist");
        assert!(result2.is_ok(), "file should be found after creation");
    }

    #[test]
    fn negative_cache_independent_entries_not_affected_by_other_invalidation() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let root_ino_id = fixture
            .adapter
            .engine
            .lock()
            .unwrap()
            .get_root_inode(&ctx)
            .expect("root inode");

        // Cache misses for two different names.
        let _ = fixture
            .adapter
            .dispatch_lookup(&ctx, root_ino_id.get(), b"still_missing");
        let _ = fixture
            .adapter
            .dispatch_lookup(&ctx, root_ino_id.get(), b"will_be_created");

        {
            let cache = fixture.adapter.negative_cache.lock().unwrap();
            assert_eq!(cache.len(), 2, "both misses cached");
        }

        // Create only one of them.
        fixture
            .adapter
            .dispatch_create(&ctx, root_ino_id.get(), b"will_be_created", 0o644, 0)
            .expect("create file");

        // The other entry should still be cached.
        {
            let cache = fixture.adapter.negative_cache.lock().unwrap();
            // The created file's entry is invalidated; the other remains.
            assert_eq!(
                cache.len(),
                1,
                "only the created file's entry was invalidated"
            );
        }
    }

    #[test]
    fn negative_cache_invalidation_on_rmdir() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let root_ino_id = fixture
            .adapter
            .engine
            .lock()
            .unwrap()
            .get_root_inode(&ctx)
            .expect("root inode");

        // Create a subdirectory.
        let dir_attr = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .mkdir(root_ino_id, b"cache_test_dir", 0o755, &ctx)
                .expect("mkdir")
        };

        // Lookup a nonexistent name inside the subdirectory to populate the
        // negative cache with (dir_inode, "no_such_file").
        let _ = fixture
            .adapter
            .dispatch_lookup(&ctx, dir_attr.inode_id.get(), b"no_such_file");
        {
            let cache = fixture.adapter.negative_cache.lock().unwrap();
            assert_eq!(
                cache.len(),
                1,
                "negative cache has one entry after miss inside subdir"
            );
        }

        // Remove the subdirectory via the adapter dispatch so the
        // negative-cache invalidation path is exercised.
        fixture
            .adapter
            .dispatch_rmdir(&ctx, root_ino_id.get(), b"cache_test_dir")
            .expect("rmdir");

        // The negative cache entry for (removed_dir, "no_such_file") should
        // be invalidated since the parent directory no longer exists.
        {
            let cache = fixture.adapter.negative_cache.lock().unwrap();
            assert_eq!(
                cache.len(),
                0,
                "negative cache invalidated when parent directory removed"
            );
        }
    }

    #[test]
    fn positive_path_lookup_cache_populates_on_successful_lookup() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let root_ino_id = fixture
            .adapter
            .engine
            .lock()
            .unwrap()
            .get_root_inode(&ctx)
            .expect("root inode");

        let (created_attr, create_fh) = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .create(root_ino_id, b"cache_hit_file", 0o644, 0, &ctx)
                .expect("create file")
        };
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.release(&create_fh).expect("release create handle");
        }

        assert!(
            fixture.adapter.path_lookup_cache.lock().unwrap().is_empty(),
            "positive cache starts empty"
        );

        let attr = fixture
            .adapter
            .dispatch_lookup(&ctx, root_ino_id.get(), b"cache_hit_file")
            .expect("lookup file");
        assert_eq!(attr.inode_id, created_attr.inode_id);

        let mut cache = fixture.adapter.path_lookup_cache.lock().unwrap();
        let entry = cache
            .get(root_ino_id.get(), b"cache_hit_file")
            .expect("successful lookup populates positive path cache");
        assert_eq!(entry.ino, created_attr.inode_id.get());
        assert_eq!(entry.generation, created_attr.generation.get());
        assert_eq!(entry.value.inode_id, created_attr.inode_id);
    }

