    #[test]
    fn read_only_mount_rejects_write_truncate_fallocate() {
        let adapter = fresh_test_adapter().with_read_only();
        let ctx = root_ctx();
        let root = InodeId::new(1);
        let buf = [0u8; 8];

        // write and truncate need a valid file handle; the readonly guard
        // fires at the entry point before handle resolution.
        assert_eq!(
            adapter
                .dispatch_write(&ctx, root.get(), 0, 0, &buf, 0)
                .unwrap_err(),
            Errno::EROFS
        );
        assert_eq!(
            adapter
                .dispatch_truncate(&ctx, root.get(), 4096)
                .unwrap_err(),
            Errno::EROFS
        );
        assert_eq!(
            adapter
                .dispatch_ftruncate_file(&ctx, root.get(), 0, 4096)
                .unwrap_err(),
            Errno::EROFS
        );
        assert_eq!(
            adapter
                .dispatch_fallocate_file(&ctx, root.get(), 0, 0, 0, 4096)
                .unwrap_err(),
            Errno::EROFS
        );
    }
