    #[test]
    fn engine_dispatch_link_creates_hard_link_and_shares_inode() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();
        let root_ino = 1u64;

        // Create a regular file via mknod to get a target inode
        let file_attr = {
            let engine = fixture.adapter.engine.lock().unwrap();
            let r = engine.get_root_inode(&ctx).expect("root inode");
            engine
                .mknod(r, b"source-file", 0o100644, 0, &ctx)
                .expect("mknod file")
        };
        let target_ino = file_attr.inode_id.get();

        let link_attr = fixture
            .adapter
            .dispatch_link(&ctx, target_ino, root_ino, b"hard-link")
            .expect("link");
        assert_eq!(link_attr.inode_id.get(), target_ino);

        // Verify nlink incremented
        let engine = fixture.adapter.engine.lock().unwrap();
        let r = engine.get_root_inode(&ctx).expect("root inode");
        let looked_up = engine
            .lookup(r, b"source-file", &ctx)
            .expect("lookup source");
        assert_eq!(looked_up.posix.nlink, 2);
    }

