    fn make_adapter(engine: AclMockEngine) -> FuseVfsAdapter {
        FuseVfsAdapter::new(Box::new(engine)).expect("create test adapter")
    }

    #[test]
    fn acl_grants_access_for_owner_match() {
        let acl = vec![
            PosixAclEntry {
                tag: ACL_USER_OBJ,
                perm: 6,
                id: 0,
            },
            PosixAclEntry {
                tag: ACL_GROUP_OBJ,
                perm: 4,
                id: 0,
            },
            PosixAclEntry {
                tag: ACL_MASK,
                perm: 6,
                id: 0,
            },
            PosixAclEntry {
                tag: ACL_OTHER,
                perm: 0,
                id: 0,
            },
        ];
        let engine = AclMockEngine::new()
            .with_root(1)
            .with_attr(1000, 100, 0o000)
            .with_acl_encoded(acl);
        let adapter = make_adapter(engine);
        let ctx = test_ctx(1000, 100);
        let result = adapter.dispatch_access_check(&ctx, 1, libc::R_OK);
        assert!(result.is_ok(), "owner should be granted read by ACL");
    }

    #[test]
    fn acl_denies_access_for_non_matching_user() {
        let acl = vec![
            PosixAclEntry {
                tag: ACL_USER_OBJ,
                perm: 6,
                id: 0,
            },
            PosixAclEntry {
                tag: ACL_GROUP_OBJ,
                perm: 0,
                id: 0,
            },
            PosixAclEntry {
                tag: ACL_MASK,
                perm: 6,
                id: 0,
            },
            PosixAclEntry {
                tag: ACL_OTHER,
                perm: 0,
                id: 0,
            },
        ];
        let engine = AclMockEngine::new()
            .with_root(1)
            .with_attr(1000, 100, 0o777)
            .with_acl_encoded(acl);
        let adapter = make_adapter(engine);
        let ctx = test_ctx(2000, 200);
        let result = adapter.dispatch_access_check(&ctx, 1, libc::R_OK);
        assert_eq!(
            result,
            Err(Errno::EACCES),
            "non-owner should be denied by ACL"
        );
    }

