    #[test]
    fn no_acl_falls_through_to_mode_bits() {
        let engine = AclMockEngine::new()
            .with_root(1)
            .with_attr(1000, 100, 0o644)
            .with_no_acl();
        let adapter = make_adapter(engine);
        assert!(adapter
            .dispatch_access_check(&test_ctx(1000, 100), 1, libc::R_OK)
            .is_ok());
        assert_eq!(
            adapter.dispatch_access_check(&test_ctx(2000, 200), 1, libc::W_OK),
            Err(Errno::EACCES)
        );
        assert!(adapter
            .dispatch_access_check(&test_ctx(2000, 200), 1, libc::R_OK)
            .is_ok());
    }

