    // ── Parent-directory ACL enforcement tests ───────────────────────────

    /// Parent directory has an ACL that grants write+execute only to the
    /// owner (uid=1000). A non-owner caller (uid=2000) creating a file
    /// must be denied with EACCES.
    #[test]
    fn parent_dir_acl_denies_create_for_non_matching_user() {
        let parent_acl = vec![
            PosixAclEntry {
                tag: ACL_USER_OBJ,
                perm: 7,
                id: 0,
            },
            PosixAclEntry {
                tag: ACL_GROUP_OBJ,
                perm: 0,
                id: 0,
            },
            PosixAclEntry {
                tag: ACL_MASK,
                perm: 7,
                id: 0,
            },
            PosixAclEntry {
                tag: ACL_OTHER,
                perm: 0,
                id: 0,
            },
        ];
        let engine = AclMockEngine::new()
            .with_root(1)
            .with_dir_attr(1000, 100, 0o000)
            .with_acl_encoded(parent_acl);
        let adapter = make_adapter(engine);
        let ctx = test_ctx(2000, 200);
        let result = adapter.dispatch_create_entry(
            &ctx,
            1,
            b"newfile",
            0o644,
            libc::O_CREAT as u32 | libc::O_RDWR as u32,
        );
        assert_eq!(
            result,
            Err(Errno::EACCES),
            "non-owner should be denied create by parent ACL"
        );
    }

    /// Parent directory has no ACL (falls through to mode bits).
    /// Parent mode 0o755 grants write+execute to owner, so the owner
    /// can create a file.
    #[test]
    fn parent_dir_no_acl_allows_create_for_owner() {
        let engine = AclMockEngine::new()
            .with_root(1)
            .with_dir_attr(1000, 100, 0o755)
            .with_no_acl()
            .with_create_ok(10);
        let adapter = make_adapter(engine);
        let ctx = test_ctx(1000, 100);
        let result = adapter.dispatch_create_entry(
            &ctx,
            1,
            b"newfile",
            0o644,
            libc::O_CREAT as u32 | libc::O_RDWR as u32,
        );
        assert!(
            result.is_ok(),
            "owner should be allowed to create when parent mode grants write+execute"
        );
    }

    /// Parent directory mode 0o700 grants write+execute only to owner.
    /// A non-owner non-group caller (matching OTHER bits=0) is denied.
    #[test]
    fn parent_dir_mode_denies_create_for_other() {
        let engine = AclMockEngine::new()
            .with_root(1)
            .with_dir_attr(1000, 100, 0o700)
            .with_no_acl();
        let adapter = make_adapter(engine);
        let ctx = test_ctx(2000, 200);
        let result = adapter.dispatch_create_entry(
            &ctx,
            1,
            b"newfile",
            0o644,
            libc::O_CREAT as u32 | libc::O_RDWR as u32,
        );
        assert_eq!(
            result,
            Err(Errno::EACCES),
            "non-owner non-group should be denied create by parent mode bits"
        );
    }

    /// Parent directory ACL allows group-class write+execute (GROUP_OBJ perm=7,
    /// MASK perm=7). Caller with matching gid can create.
    #[test]
    fn parent_dir_acl_allows_create_for_group_match() {
        let parent_acl = vec![
            PosixAclEntry {
                tag: ACL_USER_OBJ,
                perm: 0,
                id: 0,
            },
            PosixAclEntry {
                tag: ACL_GROUP_OBJ,
                perm: 7,
                id: 0,
            },
            PosixAclEntry {
                tag: ACL_MASK,
                perm: 7,
                id: 0,
            },
            PosixAclEntry {
                tag: ACL_OTHER,
                perm: 0,
                id: 0,
            },
        ];
        let engine = AclMockEngine::new()
            .with_root(1)
            .with_dir_attr(1000, 100, 0o000)
            .with_acl_encoded(parent_acl)
            .with_create_ok(20);
        let adapter = make_adapter(engine);
        let ctx = test_ctx(2000, 100);
        let result = adapter.dispatch_create_entry(
            &ctx,
            1,
            b"newfile",
            0o644,
            libc::O_CREAT as u32 | libc::O_RDWR as u32,
        );
        assert!(
            result.is_ok(),
            "group member should be allowed to create when parent ACL grants group write+execute"
        );
    }

    /// Parent directory ACL allows named user write+execute. Caller with
    /// matching uid can create even though owner and group-class deny.
