    #[test]
    fn dispatch_getxattr_returns_value_for_existing_attr() {
        let adapter = mock_xattr_adapter();
        let ctx = root_ctx();
        // Pre-populate the mock engine with a known xattr.
        adapter
            .dispatch_setxattr(&ctx, 1, b"user.test", b"hello", 0)
            .expect("setxattr");
        let value = adapter
            .dispatch_getxattr(&ctx, 1, b"user.test")
            .expect("getxattr");
        assert_eq!(value, b"hello");
    }

