    #[test]
    fn dispatch_fsyncdir_drains_writeback_range_tracker() {
        let (mut fixture, tracker) = adapter_fixture_with_writeback_tracker();
        let ctx = root_ctx();
        let writeback_page_cache = Arc::new(PageCache::new(8, 4096));
        fixture.adapter.writeback_page_cache = Some(Arc::clone(&writeback_page_cache));

        // Open the root directory for fsyncdir.
        let root = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };
        let dh = fixture
            .adapter
            .dispatch_opendir(&ctx, root.get())
            .expect("opendir");

        // Artificially mark the directory inode dirty in the tracker
        // so we can verify drain-on-fsyncdir.
        {
            tracker.lock().unwrap().mark_dirty(root, 0, 4096);
        }
        let worker_tracker = seed_worker_dirty_range(&fixture.adapter, root.get(), 0, 4096);
        let _ = writeback_page_cache
            .insert(root.get(), 0)
            .expect("insert directory writeback mirror");
        writeback_page_cache.mark_dirty(root.get(), 0);
        let _ = fixture
            .adapter
            .write_page_cache
            .insert(root.get(), 0)
            .expect("insert directory adapter mirror");
        fixture.adapter.write_page_cache.mark_dirty(root.get(), 0);
        {
            let mut cache = fixture.adapter.writeback_cache.lock().unwrap();
            cache.insert(root.get());
            cache.mark_dirty(root.get(), 4096);
        }
        assert!(tracker.lock().unwrap().is_dirty(root));
        assert_eq!(
            fixture
                .adapter
                .writeback_cache
                .lock()
                .unwrap()
                .is_dirty(root.get()),
            Some(true)
        );

        // Run fsyncdir — must drain the tracker for the directory inode.
        assert_eq!(
            fixture
                .adapter
                .dispatch_fsyncdir(&ctx, root.get(), dh.dh_id.get(), false),
            Ok(())
        );

        assert!(!tracker.lock().unwrap().is_dirty(root));
        assert!(!worker_tracker.lock().unwrap().has_dirty_ranges(root.get()));
        assert!(!writeback_page_cache.has_dirty_pages_for_inode(root.get()));
        assert!(!fixture
            .adapter
            .write_page_cache
            .has_dirty_pages_for_inode(root.get()));
        assert_eq!(
            fixture
                .adapter
                .writeback_cache
                .lock()
                .unwrap()
                .is_dirty(root.get()),
            Some(false),
            "fsyncdir must publish the reclaim projection clean after every dirty owner drains"
        );

        fixture
            .adapter
            .dispatch_releasedir(dh.dh_id.get())
            .expect("releasedir");
    }

    #[test]
    fn dispatch_fsyncdir_failures_retain_writeback_error() {
        let tracker = Arc::new(Mutex::new(
            tidefs_local_filesystem::dirty_page_tracker::DirtyPageTracker::new(),
        ));
        let mut adapter = make_adapter(
            AclMockEngine::new()
                .with_root(1)
                .with_fsyncdir_error(Errno::EIO),
        );
        adapter.writeback_range_tracker = Some(Arc::clone(&tracker));
        let inode = InodeId::new(41);
        let dh = EngineDirHandle::new(inode, DirHandleId::new(7));
        adapter.dir_handles.lock().unwrap().insert(dh);
        tracker.lock().unwrap().mark_dirty(inode, 1024, 2048);
        let worker_tracker = seed_worker_dirty_range(&adapter, inode.get(), 1024, 2048);
        let writeback_page_cache = Arc::new(PageCache::new(8, 4096));
        let _ = writeback_page_cache
            .insert(inode.get(), 0)
            .expect("insert directory writeback mirror");
        writeback_page_cache.mark_dirty(inode.get(), 0);
        adapter.writeback_page_cache = Some(Arc::clone(&writeback_page_cache));
        let _ = adapter
            .write_page_cache
            .insert(inode.get(), 0)
            .expect("insert directory adapter mirror");
        adapter.write_page_cache.mark_dirty(inode.get(), 0);

        assert_eq!(
            adapter.dispatch_fsyncdir(&root_ctx(), inode.get(), dh.dh_id.get(), false),
            Err(Errno::EIO)
        );
        assert!(writeback_page_cache.has_dirty_pages_for_inode(inode.get()));
        assert!(adapter
            .write_page_cache
            .has_dirty_pages_for_inode(inode.get()));
        assert!(worker_tracker.lock().unwrap().has_dirty_ranges(inode.get()));

        let tracker = tracker.lock().unwrap();
        let ranges = tracker
            .dirty_ranges(inode)
            .expect("failed fsyncdir must retain the dirty range");
        assert_eq!(ranges.len(), 1);
        assert_eq!(
            ranges[0].lifecycle_state(),
            tidefs_local_filesystem::dirty_page_tracker::DirtyLifecycleState::ErrorPoisoned
        );
        assert!(ranges[0].writeback_error().is_some());
    }

    #[test]
    fn dispatch_syncfs_drains_all_dirty_projection_inodes() {
        let (mut fixture, tracker) = adapter_fixture_with_writeback_tracker();
        let ctx = root_ctx();
        let writeback_page_cache = Arc::new(PageCache::new(8, 4096));
        fixture.adapter.writeback_page_cache = Some(Arc::clone(&writeback_page_cache));

        // Create two files and write dirty data to both.
        let (ino_a, fh_a, _efh_a) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"syncfs-a.txt",
            libc::O_RDWR as u32,
        );
        let (ino_b, fh_b, _efh_b) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"syncfs-b.txt",
            libc::O_RDWR as u32,
        );

        fixture
            .adapter
            .dispatch_write(&ctx, ino_a.get(), fh_a, 0, b"AAAA", 0)
            .expect("write A");
        fixture
            .adapter
            .dispatch_write(&ctx, ino_b.get(), fh_b, 0, b"BBBB", 0)
            .expect("write B");

        // Artificially mark both inodes dirty so drain-on-syncfs is verifiable.
        tracker
            .lock()
            .unwrap()
            .mark_dirty(ino_a, 0, b"AAAA".len() as u64);
        tracker
            .lock()
            .unwrap()
            .mark_dirty(ino_b, 0, b"BBBB".len() as u64);
        let worker_tracker =
            seed_worker_dirty_range(&fixture.adapter, ino_a.get(), 0, b"AAAA".len() as u64);
        {
            let mut worker_tracker = worker_tracker.lock().unwrap();
            worker_tracker
                .mark_dirty(ino_b.get(), 0, b"BBBB".len() as u64)
                .expect("seed worker range B");
        }
        let worker_only_inode = 900_001;
        {
            let mut worker_tracker = worker_tracker.lock().unwrap();
            worker_tracker
                .mark_dirty(worker_only_inode, 0, 4096)
                .expect("seed worker-only dirty range");
        }
        {
            let mut cache = fixture.adapter.writeback_cache.lock().unwrap();
            cache.insert(worker_only_inode);
            cache.mark_dirty(worker_only_inode, 4096);
        }
        for inode in [ino_a, ino_b] {
            let _ = writeback_page_cache
                .insert(inode.get(), 0)
                .expect("insert writeback mirror");
            writeback_page_cache.mark_dirty(inode.get(), 0);
            let _ = fixture
                .adapter
                .write_page_cache
                .insert(inode.get(), 0)
                .expect("insert adapter write mirror");
            fixture.adapter.write_page_cache.mark_dirty(inode.get(), 0);
        }
        assert!(tracker.lock().unwrap().is_dirty(ino_a));
        assert!(tracker.lock().unwrap().is_dirty(ino_b));
        assert_eq!(
            fixture
                .adapter
                .writeback_cache
                .lock()
                .unwrap()
                .is_dirty(worker_only_inode),
            Some(true)
        );

        // Run syncfs — must drain ALL inodes from the tracker.
        fixture.adapter.dispatch_syncfs(&ctx).expect("syncfs");

        assert!(!tracker.lock().unwrap().is_dirty(ino_a));
        assert!(!tracker.lock().unwrap().is_dirty(ino_b));
        assert!(!worker_tracker.lock().unwrap().has_dirty_ranges(ino_a.get()));
        assert!(!worker_tracker.lock().unwrap().has_dirty_ranges(ino_b.get()));
        assert!(!worker_tracker
            .lock()
            .unwrap()
            .has_dirty_ranges(worker_only_inode));
        for inode in [ino_a, ino_b] {
            assert!(!writeback_page_cache.has_dirty_pages_for_inode(inode.get()));
            assert!(!fixture
                .adapter
                .write_page_cache
                .has_dirty_pages_for_inode(inode.get()));
        }
        assert_eq!(
            fixture
                .adapter
                .writeback_cache
                .lock()
                .unwrap()
                .is_dirty(worker_only_inode),
            Some(false),
            "syncfs must publish the reclaim projection clean after a worker-only owner drains"
        );
    }

