    #[test]
    fn dispatch_defrag_single_file_reduces_extent_count() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();

        // Create a file and allocate explicit extents.
        let (inode, _adapter_fh, efh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"defrag_single.txt",
            libc::O_RDWR as u32,
        );

        // Write data through the engine — the engine's write path should
        // create extent map entries through the extent allocator.
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .write(&efh, 0, &[0xAAu8; 4096], &ctx)
                .expect("write block 1");
            engine
                .write(&efh, 4096, &[0xBBu8; 4096], &ctx)
                .expect("write block 2");
            engine
                .write(&efh, 8192, &[0xCCu8; 4096], &ctx)
                .expect("write block 3");
        }

        // Trigger defrag via the dispatch method.
        let input = DefragIoctlInput {
            ino: inode.get(),
            flags: 0,
        };
        let result = fixture.adapter.dispatch_defrag(&ctx, input);

        // The engine may or may not have an explicit extent map for this inode.
        // Accept either success or ENOSYS/ENOENT (no extent map to defrag).
        match result {
            Ok(buf) => {
                assert_eq!(buf.len(), 24, "defrag response should be 24 bytes");
                let extents_before = u64::from_le_bytes(buf[0..8].try_into().unwrap());
                let extents_after = u64::from_le_bytes(buf[8..16].try_into().unwrap());
                // After defrag, extent count should not increase.
                assert!(
                    extents_after <= extents_before,
                    "extents should not increase: before={extents_before} after={extents_after}"
                );
            }
            Err(_) => {
                // No explicit extent map: defrag is a no-op.
            }
        }
    }

    #[test]
    fn dispatch_defrag_empty_file_returns_zeroed_stats() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();

        let (inode, _adapter_fh, efh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"defrag_empty.txt",
            libc::O_RDWR as u32,
        );

        // Open the file but write nothing (empty file, zero size).
        // The engine should still have an extent map for the inode after open+write(0).
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            // Write zero bytes to ensure the inode has extent map state.
            let _ = engine.write(&efh, 0, b"", &ctx); // no-op
        }

        let input = DefragIoctlInput {
            ino: inode.get(),
            flags: 0,
        };
        let result = fixture.adapter.dispatch_defrag(&ctx, input);

        // May succeed with zero extents or return ENOSYS/ENOENT if no extent map exists.
        // Either outcome is valid for an empty file.
        match result {
            Ok(buf) => {
                assert_eq!(buf.len(), 24);
                let extents_before = u64::from_le_bytes(buf[0..8].try_into().unwrap());
                let extents_after = u64::from_le_bytes(buf[8..16].try_into().unwrap());
                assert_eq!(extents_before, extents_after);
            }
            Err(_) => {
                // ENOSYS or ENOENT is acceptable for files without extent maps.
            }
        }
    }

    #[test]
    fn defrag_ioctl_wire_format_roundtrip() {
        // Verify that DefragIoctlOutput::encode() produces the correct wire format.
        let output = DefragIoctlOutput {
            extents_before: 10,
            extents_after: 4,
            fragmentation_reduction_pct: 6000, // 60.00%
            inodes_defragmented: 1,
        };
        let buf = output.encode();
        assert_eq!(buf.len(), 24);

        let eb = u64::from_le_bytes(buf[0..8].try_into().unwrap());
        let ea = u64::from_le_bytes(buf[8..16].try_into().unwrap());
        let fr = u32::from_le_bytes(buf[16..20].try_into().unwrap());
        let id = u32::from_le_bytes(buf[20..24].try_into().unwrap());

        assert_eq!(eb, 10);
        assert_eq!(ea, 4);
        assert_eq!(fr, 6000);
        assert_eq!(id, 1);
    }

