    #[test]
    fn dispatch_defrag_recursive_directory_aggregates_stats() {
        let fixture = adapter_fixture();
        let ctx = root_ctx();

        // Create a subdirectory.
        let root_ino = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine.get_root_inode(&ctx).expect("root inode")
        };
        let dir_attr = {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .mkdir(root_ino, b"defrag_dir", 0o755, &ctx)
                .expect("mkdir")
        };
        let dir_ino = dir_attr.inode_id;

        // Create files in the directory and write data to generate extents.
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            let (_f1_attr, f1_efh) = engine
                .create(dir_ino, b"file1", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create file1");
            engine
                .write(&f1_efh, 0, &[0xAAu8; 4096], &ctx)
                .expect("write file1 blk1");
            engine
                .write(&f1_efh, 4096, &[0xBBu8; 4096], &ctx)
                .expect("write file1 blk2");
            engine.release(&f1_efh).expect("release file1");

            let (_f2_attr, f2_efh) = engine
                .create(dir_ino, b"file2", 0o644, libc::O_RDWR as u32, &ctx)
                .expect("create file2");
            engine
                .write(&f2_efh, 0, &[0xCCu8; 8192], &ctx)
                .expect("write file2");
            engine.release(&f2_efh).expect("release file2");
        }

        // Trigger recursive defrag on the directory.
        let input = DefragIoctlInput {
            ino: dir_ino.get(),
            flags: 1,
        };
        let result = fixture.adapter.dispatch_defrag(&ctx, input);

        // The engine may or may not have explicit extent maps.
        match result {
            Ok(buf) => {
                assert_eq!(buf.len(), 24, "defrag response should be 24 bytes");
                let before = u64::from_le_bytes(buf[0..8].try_into().unwrap());
                let after = u64::from_le_bytes(buf[8..16].try_into().unwrap());
                let defragged = u32::from_le_bytes(buf[20..24].try_into().unwrap()) as u64;
                assert!(
                    after <= before,
                    "extents should not increase: before={before} after={after}"
                );
                assert!(
                    defragged <= 2,
                    "at most 2 inodes defragged, got {defragged}"
                );
            }
            Err(_) => { /* ENOSYS/ENOENT OK when no explicit extent maps */ }
        }
    }

