        let mut expected = vec![0x31; page_size];
        {
            let engine = fixture.adapter.engine.lock().unwrap();
            engine
                .write(&engine_fh, 0, &expected, &ctx)
                .expect("seed original page");
        }
        fixture
            .adapter
