    #[test]
    fn writeback_cached_clean_write_through_helper_ignores_next_page_worker_dirty_range() {
        let fixture = adapter_fixture_with_writeback_cache();
        let ctx = root_ctx();
        let (inode, _adapter_fh, _engine_fh) = create_adapter_file_handle(
            &fixture.adapter,
            &ctx,
            b"wb-clean-write-through-helper-next-page-worker-dirty.bin",
            libc::O_RDWR as u32,
        );
        let ino = inode.get();
        let page_size = fixture.adapter.write_page_cache.page_size();
        let page_size_u64 = u64::try_from(page_size).expect("page size fits u64");
        let write_len = page_size / 2;
        let write_len_u32 = u32::try_from(write_len).expect("write length fits u32");
        let page_offset = page_size_u64;
        let next_page_offset = page_offset + page_size_u64;
        let mut expected = vec![0xAA; page_size];
        fixture
            .adapter
            .write_page_cache
            .insert(ino, page_offset)
            .expect("insert resident clean mirror");
        {
            let mut page = fixture
                .adapter
                .write_page_cache
                .lookup(ino, page_offset)
                .expect("lookup resident clean mirror");
            page.data_mut().copy_from_slice(&expected);
            assert!(!page.is_dirty());
        }
        let worker_tracker = fixture
            .adapter
            .write_dispatch
            .lock()
            .unwrap()
            .dirty_page_tracker_arc();
        worker_tracker
            .lock()
            .unwrap()
            .mark_dirty(ino, next_page_offset, u64::from(write_len_u32))
            .expect("seed next-page worker dirty range");
        {
            let mut cache = fixture.adapter.writeback_cache.lock().unwrap();
            cache.insert(ino);
            cache.mark_dirty(ino, u64::from(write_len_u32));
        }

        let replacement = vec![0xC4; write_len];
        fixture
            .adapter
            .record_clean_write_through_after_write(ino, page_offset, write_len_u32, &replacement)
            .expect("record clean write-through after write");
        expected[..write_len].copy_from_slice(&replacement);

        assert!(
            worker_tracker
                .lock()
                .unwrap()
                .get_dirty_ranges(ino)
                .iter()
                .any(|range| range.offset_start == next_page_offset
                    && range.offset_end == next_page_offset + u64::from(write_len_u32)),
            "next-page worker dirty range should remain tracked"
        );
        {
            let page = fixture
                .adapter
                .write_page_cache
                .lookup(ino, page_offset)
                .expect("resident clean mirror remains resident");
            assert_eq!(page.data(), expected.as_slice());
            assert!(
                !page.is_dirty(),
                "next-page worker dirty range must not dirty the accepted clean page"
            );
        }
    }

    #[test]
    fn writeback_cached_dirty_write_policy_skips_same_request_kernel_invalidation() {
        assert_eq!(
            KernelPageCacheInvalidation::for_write_request(true),
            KernelPageCacheInvalidation::SkipSameRequestWriteback
        );
        assert!(
            !KernelPageCacheInvalidation::for_write_request(true).should_notify(),
            "writeback-cache WRITE replies must not invalidate the same kernel page-cache range"
        );
        assert!(
            KernelPageCacheInvalidation::for_write_request(false).should_notify(),
            "non-writeback dirty writes keep kernel page-cache invalidation"
        );
    }

